INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Mojito','virgin-mojito','A refreshing alcohol-free twist on the classic Cuban cocktail. Fresh mint and lime combine with sparkling water for a crisp and cooling drink.','A bright and bubbly mocktail packed with fresh mint and zesty lime.','Cuban','Easy',5,0,5,1,90,0,23,0,0,'[{"amount":10,"unit":"leaves","item":"fresh mint","group":"main"},{"amount":1,"unit":"whole","item":"lime cut into wedges","group":"main"},{"amount":2,"unit":"tbsp","item":"white sugar","group":"main"},{"amount":1,"unit":"cup","item":"sparkling water","group":"main"},{"amount":0.5,"unit":"cup","item":"crushed ice","group":"main"},{"amount":1,"unit":"tbsp","item":"lime juice","group":"main"},{"amount":1,"unit":"sprig","item":"fresh mint for garnish","group":"garnish"},{"amount":1,"unit":"slice","item":"lime for garnish","group":"garnish"}]','[{"title":"Muddle Mint and Lime","text":"Place the fresh mint leaves and lime wedges into a sturdy glass. Add the white sugar and gently muddle everything together using a muddler or the back of a spoon until the mint is bruised and the lime juice is released. Do not over-muddle or the mint will turn bitter.","timer":0},{"title":"Add Ice","text":"Fill the glass generously with crushed ice. Crushed ice chills the drink faster and dilutes it slightly for a balanced flavor. Pack the ice in well so the drink stays cold throughout.","timer":0},{"title":"Add Lime Juice","text":"Pour the extra tablespoon of fresh lime juice over the ice. This boosts the citrus flavor and brightens the overall taste of the mocktail. Stir lightly to combine with the muddled mixture below.","timer":0},{"title":"Top with Sparkling Water","text":"Slowly pour the sparkling water over the ice to preserve the bubbles. Gently stir with a long spoon to combine all the ingredients without losing too much carbonation. The drink should look slightly cloudy and very effervescent.","timer":0},{"title":"Garnish and Serve","text":"Garnish with a fresh sprig of mint and a slice of lime on the rim of the glass. Serve immediately with a straw. For best results drink within a few minutes while the bubbles are still lively.","timer":0}]','[{"original":"white sugar","swap":"simple syrup or agave nectar"},{"original":"sparkling water","swap":"ginger ale or lemon lime soda"},{"original":"fresh mint","swap":"fresh basil for an herbal twist"}]','["Over-muddling the mint which releases bitter compounds from the stems","Using bottled lime juice instead of fresh which makes the drink taste flat","Stirring too aggressively after adding sparkling water which kills the carbonation"]','["mocktail","refreshing","summer","mint","lime","non-alcoholic","quick"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Espresso Martini','virgin-espresso-martini','A bold and creamy alcohol-free version of the beloved espresso martini. Rich espresso and coffee syrup create a sophisticated mocktail with a beautiful frothy top.','A velvety and energizing coffee mocktail that looks as impressive as it tastes.','American','Easy',5,0,5,1,120,1,28,1,0,'[{"amount":2,"unit":"shots","item":"freshly brewed espresso cooled","group":"main"},{"amount":2,"unit":"tbsp","item":"coffee syrup or simple syrup","group":"main"},{"amount":0.25,"unit":"cup","item":"cold brew coffee concentrate","group":"main"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"main"},{"amount":0.5,"unit":"cup","item":"ice cubes","group":"main"},{"amount":2,"unit":"tbsp","item":"aquafaba for froth","group":"main"},{"amount":3,"unit":"whole","item":"coffee beans for garnish","group":"garnish"},{"amount":1,"unit":"pinch","item":"cocoa powder for garnish","group":"garnish"}]','[{"title":"Brew and Cool Espresso","text":"Brew two shots of strong espresso and allow them to cool to room temperature. You can speed this up by placing the espresso in the freezer for 5 minutes. Using hot espresso will melt the ice too quickly and dilute the final drink.","timer":300},{"title":"Combine Ingredients in Shaker","text":"Fill a cocktail shaker with ice cubes. Add the cooled espresso, cold brew coffee concentrate, coffee syrup, vanilla extract, and aquafaba. The aquafaba is the key ingredient that will create the signature frothy top on the mocktail.","timer":0},{"title":"Shake Vigorously","text":"Seal the shaker tightly and shake as hard as you can for at least 20 to 30 seconds. This is the most important step because vigorous shaking creates the foam and chills the drink perfectly. You should hear the ice crashing loudly inside.","timer":30},{"title":"Strain into Glass","text":"Strain the mixture through the cocktail shaker strainer into a chilled martini glass. Pour slowly and steadily so the foam rises naturally to the top. The drink should have a deep brown color with a thick pale foam layer on the surface.","timer":0},{"title":"Garnish and Serve","text":"Place three coffee beans on top of the foam in the center of the glass. Lightly dust the foam with a tiny pinch of cocoa powder for a finishing touch. Serve immediately before the foam begins to dissolve.","timer":0}]','[{"original":"aquafaba","swap":"egg white for a richer and more stable foam"},{"original":"cold brew concentrate","swap":"strong brewed coffee cooled completely"},{"original":"coffee syrup","swap":"caramel syrup for a sweeter variation"}]','["Using hot espresso which melts ice too fast and results in a watery drink","Not shaking long enough which means the foam does not form properly","Using a warm glass which causes the foam to collapse almost immediately"]','["mocktail","coffee","espresso","elegant","non-alcoholic","frothy","party"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shirley Temple','shirley-temple','The ultimate classic non-alcoholic drink loved by kids and adults alike for decades. Ginger ale and grenadine combine for a sweet rosy drink topped with a maraschino cherry.','A sweet and fizzy pink mocktail that is as fun to look at as it is to drink.','American','Easy',3,0,3,1,150,0,38,0,0,'[{"amount":1,"unit":"cup","item":"ginger ale chilled","group":"main"},{"amount":2,"unit":"tbsp","item":"grenadine syrup","group":"main"},{"amount":0.25,"unit":"cup","item":"orange juice freshly squeezed","group":"main"},{"amount":0.5,"unit":"cup","item":"ice cubes","group":"main"},{"amount":2,"unit":"whole","item":"maraschino cherries for garnish","group":"garnish"},{"amount":1,"unit":"slice","item":"orange for garnish","group":"garnish"},{"amount":1,"unit":"whole","item":"cocktail umbrella for garnish","group":"garnish"},{"amount":1,"unit":"sprig","item":"fresh mint optional garnish","group":"garnish"}]','[{"title":"Chill the Glass","text":"Place your serving glass in the freezer for 2 to 3 minutes before assembling the drink. A cold glass helps keep the drink colder for longer and makes the presentation look more polished. This step is optional but highly recommended.","timer":180},{"title":"Add Ice","text":"Remove the glass from the freezer and fill it generously with ice cubes. Use plenty of ice so the drink stays cold and refreshing until the very last sip. Clear ice cubes look best in this presentation-forward drink.","timer":0},{"title":"Add Grenadine","text":"Pour the grenadine syrup directly over the ice. The grenadine will sink to the bottom of the glass creating a beautiful gradient effect that looks stunning before stirring. Do not stir yet if you want that layered look for photos.","timer":0},{"title":"Add Orange Juice and Ginger Ale","text":"Pour the fresh orange juice over the grenadine followed slowly by the chilled ginger ale. Pour the ginger ale gently against the side of the glass to preserve the carbonation. The drink will naturally turn a gorgeous pink and orange color.","timer":0},{"title":"Garnish and Serve","text":"Give the drink one gentle stir if you prefer an even color throughout. Garnish with maraschino cherries on a cocktail pick, an orange slice on the rim, and a cocktail umbrella for a festive look. Serve immediately with a straw.","timer":0}]','[{"original":"ginger ale","swap":"lemon lime soda or sprite for a less spicy base"},{"original":"grenadine syrup","swap":"pomegranate juice mixed with a little sugar"},{"original":"orange juice","swap":"pineapple juice for a tropical variation"}]','["Adding too much grenadine which makes the drink overly sweet and overpowers the other flavors","Using warm ginger ale which results in a flat and unrefreshing drink","Stirring too aggressively which destroys all the carbonation in the ginger ale"]','["mocktail","classic","sweet","kids","party","non-alcoholic","quick","pink"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Pina Colada','virgin-pina-colada','A tropical and creamy alcohol-free version of the iconic beach cocktail. Pineapple juice and coconut cream blend into a luscious frozen drink that transports you straight to paradise.','A rich and frosty tropical mocktail bursting with pineapple and coconut flavors.','Caribbean','Easy',5,0,5,2,220,2,42,8,1,'[{"amount":1,"unit":"cup","item":"fresh pineapple chunks frozen","group":"main"},{"amount":0.5,"unit":"cup","item":"pineapple juice","group":"main"},{"amount":0.5,"unit":"cup","item":"coconut cream","group":"main"},{"amount":1,"unit":"cup","item":"ice cubes","group":"main"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"main"},{"amount":1,"unit":"tbsp","item":"honey or agave","group":"main"},{"amount":2,"unit":"slices","item":"fresh pineapple for garnish","group":"garnish"},{"amount":2,"unit":"whole","item":"maraschino cherries for garnish","group":"garnish"}]','[{"title":"Prepare Frozen Pineapple","text":"If you do not have pre-frozen pineapple chunks, cut fresh pineapple into bite-sized pieces and freeze them for at least 2 hours before making the drink. Frozen pineapple gives the mocktail a thick frosty texture without needing as much ice.","timer":7200},{"title":"Combine in Blender","text":"Add the frozen pineapple chunks, pineapple juice, coconut cream, vanilla extract, and honey into a high-powered blender. Add the ice cubes last so they blend evenly throughout the mixture. Make sure the blender lid is secured tightly before blending.","timer":0},{"title":"Blend Until Smooth","text":"Blend on high speed for 30 to 60 seconds until the mixture is completely smooth and creamy with no visible chunks. Stop and scrape down the sides of the blender if needed. The final texture should resemble a thick and pourable smoothie.","timer":60},{"title":"Taste and Adjust","text":"Taste the blended mixture and adjust sweetness by adding more honey if desired. If the drink is too thick add a splash more pineapple juice and blend briefly. If it is too thin add a few more frozen pineapple pieces and blend again until perfect.","timer":0},{"title":"Pour and Garnish","text":"Pour the mocktail into two chilled glasses. Garnish each glass with a fresh pineapple slice on the rim and a maraschino cherry on top. Add a cocktail umbrella and a straw for the full tropical experience. Serve immediately before it melts.","timer":0}]','[{"original":"coconut cream","swap":"coconut milk for a lighter and less rich version"},{"original":"fresh pineapple","swap":"canned pineapple chunks drained and frozen"},{"original":"honey","swap":"maple syrup or simple syrup for a vegan option"}]','["Using coconut milk instead of coconut cream which results in a thin and watery drink","Not freezing the pineapple first which makes the drink too watery and not cold enough","Over-blending the ice which can make the drink separate and become slushy rather than creamy"]','["mocktail","tropical","frozen","blended","coconut","pineapple","summer","non-alcoholic"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Watermelon Margarita','virgin-watermelon-margarita','A vibrant and refreshing alcohol-free margarita made with fresh juicy watermelon. Bright lime juice and a salted rim make this mocktail the perfect summer sipper.','A stunning pink mocktail with sweet watermelon and tangy lime in every sip.','Mexican','Easy',8,0,8,2,110,1,27,0,1,'[{"amount":3,"unit":"cups","item":"fresh watermelon cubed and seeded","group":"main"},{"amount":3,"unit":"tbsp","item":"fresh lime juice","group":"main"},{"amount":1,"unit":"tbsp","item":"agave nectar or simple syrup","group":"main"},{"amount":0.5,"unit":"cup","item":"sparkling water","group":"main"},{"amount":1,"unit":"cup","item":"ice cubes","group":"main"},{"amount":2,"unit":"tbsp","item":"coarse salt for rim","group":"garnish"},{"amount":1,"unit":"tbsp","item":"lime zest for rim","group":"garnish"},{"amount":2,"unit":"slices","item":"fresh watermelon for garnish","group":"garnish"}]','[{"title":"Prepare the Salted Rim","text":"Mix the coarse salt and lime zest together on a small flat plate. Run a lime wedge around the rim of each glass to moisten it. Dip each glass rim into the salt mixture and twist gently to coat evenly. Set the glasses aside while you prepare the drink.","timer":0},{"title":"Blend the Watermelon","text":"Place the cubed watermelon into a blender and blend on high speed until completely smooth and liquefied. This should take about 20 to 30 seconds. Do not add any liquid at this stage as watermelon contains plenty of natural juice.","timer":30},{"title":"Strain the Juice","text":"Pour the blended watermelon through a fine mesh strainer into a pitcher pressing down with a spoon to extract all the juice. Discard the pulp left in the strainer. Straining gives you a smooth and elegant drink rather than a pulpy one.","timer":0},{"title":"Mix the Mocktail","text":"Add the fresh lime juice and agave nectar to the strained watermelon juice and stir well to combine. Fill the prepared glasses with ice cubes then pour the watermelon mixture over the ice. Top each glass with a splash of sparkling water for effervescence.","timer":0},{"title":"Garnish and Serve","text":"Place a small triangle of fresh watermelon on the rim of each glass as a garnish. You can also add a lime wheel or a sprig of fresh mint for extra color. Serve immediately while the drinks are cold and the sparkling water is still bubbly.","timer":0}]','[{"original":"fresh watermelon","swap":"frozen watermelon chunks for a frostier version"},{"original":"agave nectar","swap":"honey or simple syrup for sweetness"},{"original":"sparkling water","swap":"coconut water for a tropical twist"}]','["Not straining the blended watermelon which results in a pulpy and unpleasant texture","Skipping the salted rim which is essential for balancing the sweetness of the watermelon","Using seedless watermelon without checking for seeds which can make the drink bitter if blended with seeds"]','["mocktail","watermelon","summer","margarita","refreshing","non-alcoholic","fruity","pink"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Margarita','virgin-margarita','A refreshing alcohol-free twist on the classic margarita with bright citrus flavor. This mocktail delivers the same tangy and sweet balance without the tequila.','A zesty lime and orange mocktail with a salted rim that tastes just like the real thing.','Mexican','Easy',5,0,5,2,120,1,30,0,1,'[{"amount":120,"unit":"ml","item":"fresh lime juice","group":"base"},{"amount":60,"unit":"ml","item":"fresh orange juice","group":"base"},{"amount":60,"unit":"ml","item":"simple syrup","group":"sweetener"},{"amount":120,"unit":"ml","item":"sparkling water","group":"base"},{"amount":1,"unit":"tsp","item":"orange zest","group":"flavor"},{"amount":2,"unit":"tbsp","item":"coarse salt","group":"garnish"},{"amount":1,"unit":"cup","item":"ice cubes","group":"serving"},{"amount":2,"unit":"slices","item":"lime for garnish","group":"garnish"}]','[{"title":"Prepare the Glass","text":"Run a lime wedge around the rim of each glass. Pour coarse salt onto a flat plate and dip the rim into the salt to coat it evenly. Fill the glasses with ice cubes and set aside.","timer":0},{"title":"Mix the Citrus Base","text":"In a cocktail shaker, combine the fresh lime juice, fresh orange juice, simple syrup, and orange zest. Add a generous handful of ice to the shaker.","timer":0},{"title":"Shake Vigorously","text":"Seal the cocktail shaker tightly and shake vigorously for about 15 seconds until the mixture is well chilled and slightly frothy.","timer":15},{"title":"Strain and Pour","text":"Strain the mixture through a fine mesh strainer into the prepared glasses over ice. Pour slowly to preserve the foam on top.","timer":0},{"title":"Top and Garnish","text":"Top each glass with sparkling water and stir gently to combine. Garnish with a lime slice on the rim and serve immediately.","timer":0}]','[{"original":"simple syrup","swap":"agave nectar for a more authentic margarita flavor"},{"original":"sparkling water","swap":"lemon-lime soda for added sweetness"},{"original":"coarse salt","swap":"tajin seasoning for a spicy chili rim"}]','["Using bottled lime juice instead of fresh lime juice which dulls the bright citrus flavor","Adding too much simple syrup which makes the drink cloyingly sweet and unbalanced","Skipping the shaking step and just stirring which results in a poorly mixed and warm drink"]','["mocktail","citrus","summer","party drink","alcohol-free","lime"]','["vegan","gluten-free","dairy-free"]','Mocktails','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Pina Colada','virgin-pina-colada','A creamy and tropical alcohol-free pina colada blended with pineapple and coconut cream. This mocktail is rich, smooth, and perfect for warm weather.','A lush blended tropical mocktail with pineapple and coconut that feels like a vacation in a glass.','Caribbean','Easy',5,0,5,2,280,2,42,14,2,'[{"amount":240,"unit":"ml","item":"pineapple juice","group":"base"},{"amount":120,"unit":"ml","item":"coconut cream","group":"base"},{"amount":200,"unit":"g","item":"frozen pineapple chunks","group":"base"},{"amount":1,"unit":"cup","item":"ice cubes","group":"serving"},{"amount":30,"unit":"ml","item":"fresh lime juice","group":"flavor"},{"amount":1,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":2,"unit":"slices","item":"fresh pineapple for garnish","group":"garnish"},{"amount":2,"unit":"tbsp","item":"toasted coconut flakes","group":"garnish"}]','[{"title":"Prepare Your Blender","text":"Make sure your blender is clean and dry. Chill your serving glasses in the freezer for a few minutes so the drink stays cold longer once poured.","timer":120},{"title":"Add Ingredients to Blender","text":"Add the frozen pineapple chunks, pineapple juice, coconut cream, fresh lime juice, honey, and ice cubes to the blender. Layer the ingredients starting with liquids so the blender runs smoothly.","timer":0},{"title":"Blend Until Smooth","text":"Blend on high speed for about 45 seconds until the mixture is completely smooth and creamy with no visible chunks of ice or pineapple remaining.","timer":45},{"title":"Check Consistency","text":"Check the consistency of the blended mixture. It should be thick like a milkshake but still pourable. Add more ice for a thicker drink or more pineapple juice to thin it out.","timer":0},{"title":"Pour and Garnish","text":"Pour the blended mixture into the chilled glasses. Garnish each glass with a slice of fresh pineapple on the rim and a sprinkle of toasted coconut flakes on top. Serve immediately.","timer":0}]','[{"original":"coconut cream","swap":"full-fat coconut milk for a lighter and less rich version"},{"original":"honey","swap":"maple syrup or agave to keep the drink fully vegan"},{"original":"frozen pineapple chunks","swap":"fresh pineapple with extra ice cubes for the same chilled effect"}]','["Using light coconut milk instead of coconut cream which makes the drink thin and watery","Not using frozen pineapple which results in a watered-down drink as excess ice melts","Over-blending the mixture which melts the ice and creates a liquid instead of a slushy texture"]','["mocktail","tropical","blended","coconut","pineapple","summer","alcohol-free"]','["vegan","gluten-free","dairy-free"]','Mocktails','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mocktail Aperol Spritz','mocktail-aperol-spritz','A vibrant and bubbly alcohol-free version of the beloved Italian Aperol Spritz with bitter orange notes. It uses blood orange juice and a touch of gentian-based bitters for authentic depth.','A gorgeous crimson sparkling mocktail that captures the bittersweet citrus spirit of a classic Aperol Spritz.','Italian','Easy',5,0,5,2,95,1,23,0,0,'[{"amount":120,"unit":"ml","item":"blood orange juice","group":"base"},{"amount":240,"unit":"ml","item":"sparkling water","group":"base"},{"amount":60,"unit":"ml","item":"fresh orange juice","group":"base"},{"amount":2,"unit":"dashes","item":"alcohol-free aromatic bitters","group":"flavor"},{"amount":30,"unit":"ml","item":"simple syrup","group":"sweetener"},{"amount":1,"unit":"tsp","item":"fresh lemon juice","group":"flavor"},{"amount":1,"unit":"cup","item":"large ice cubes","group":"serving"},{"amount":2,"unit":"slices","item":"orange for garnish","group":"garnish"}]','[{"title":"Chill Your Glasses","text":"Place two large wine glasses or balloon glasses in the freezer for 3 to 5 minutes. Using large glasses enhances the visual presentation and keeps the drink cold longer.","timer":300},{"title":"Build the Base","text":"Remove the glasses from the freezer and fill each generously with large ice cubes. Pour in the blood orange juice, fresh orange juice, and simple syrup over the ice.","timer":0},{"title":"Add Bitters and Lemon","text":"Add two dashes of alcohol-free aromatic bitters to each glass along with a small squeeze of fresh lemon juice. These ingredients mimic the signature bitter and complex flavor of Aperol.","timer":0},{"title":"Top with Sparkling Water","text":"Slowly pour the sparkling water down the side of the glass to preserve the bubbles. Do not stir aggressively or you will lose the effervescence that makes this drink special.","timer":0},{"title":"Garnish and Serve","text":"Give the drink one very gentle stir from bottom to top. Garnish each glass with a half-slice of orange on the rim. Serve immediately while the drink is still bubbly and cold.","timer":0}]','[{"original":"blood orange juice","swap":"regular orange juice with a small amount of pomegranate juice for color and tartness"},{"original":"alcohol-free aromatic bitters","swap":"a tiny pinch of grapefruit zest and a drop of vanilla extract for complexity"},{"original":"simple syrup","swap":"honey syrup made with equal parts honey and warm water for a floral sweetness"}]','["Pouring sparkling water too aggressively which destroys the bubbles and flattens the drink","Using too many dashes of bitters which overwhelms the delicate citrus flavor of the drink","Skipping the large ice cubes and using crushed ice which melts too fast and dilutes the mocktail"]','["mocktail","Italian","citrus","sparkling","aperitivo","alcohol-free","elegant"]','["vegan","gluten-free","dairy-free"]','Mocktails','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Watermelon Mint Cooler','watermelon-mint-cooler','A light and refreshing mocktail made with fresh watermelon juice and cool mint leaves. This drink is hydrating, naturally sweet, and ideal for hot summer days.','A bright pink mocktail bursting with fresh watermelon and cool mint that is effortlessly refreshing.','American','Easy',10,0,10,2,85,1,21,0,1,'[{"amount":400,"unit":"g","item":"fresh seedless watermelon chunks","group":"base"},{"amount":15,"unit":"leaves","item":"fresh mint","group":"flavor"},{"amount":30,"unit":"ml","item":"fresh lime juice","group":"flavor"},{"amount":120,"unit":"ml","item":"sparkling water","group":"base"},{"amount":20,"unit":"ml","item":"simple syrup","group":"sweetener"},{"amount":1,"unit":"cup","item":"ice cubes","group":"serving"},{"amount":2,"unit":"small sprigs","item":"mint for garnish","group":"garnish"},{"amount":2,"unit":"small wedges","item":"watermelon for garnish","group":"garnish"}]','[{"title":"Blend the Watermelon","text":"Place the watermelon chunks into a blender and blend on high for 20 seconds until completely smooth and liquid. The natural juice from the watermelon makes this drink naturally sweet and vibrant pink.","timer":20},{"title":"Strain the Juice","text":"Pour the blended watermelon through a fine mesh strainer into a pitcher, pressing gently with a spoon to extract as much juice as possible. Discard the pulp left in the strainer.","timer":0},{"title":"Muddle the Mint","text":"Divide the fresh mint leaves between two glasses. Using a muddler or the back of a spoon, gently press and twist the mint leaves about 5 times to release their aromatic oils. Do not over-muddle or the mint will taste bitter.","timer":0},{"title":"Build the Drink","text":"Fill each glass with ice cubes. Add the fresh lime juice and simple syrup to each glass. Pour the strained watermelon juice evenly between the two glasses over the mint and ice.","timer":0},{"title":"Top and Garnish","text":"Top each glass with sparkling water and stir gently once to combine all the layers. Garnish with a fresh mint sprig and a small watermelon wedge on the rim. Serve immediately.","timer":0}]','[{"original":"fresh watermelon chunks","swap":"store-bought watermelon juice for a quicker preparation"},{"original":"simple syrup","swap":"skip entirely if the watermelon is very ripe and naturally sweet enough"},{"original":"sparkling water","swap":"ginger beer for an extra spicy and bubbly kick"}]','["Over-muddling the mint which causes a bitter chlorophyll taste that ruins the fresh flavor","Not straining the watermelon juice which leaves fibrous pulp and creates an unpleasant texture","Using unripe watermelon which is not sweet enough and results in a bland and disappointing drink"]','["mocktail","watermelon","mint","summer","refreshing","alcohol-free","pink"]','["vegan","gluten-free","dairy-free"]','Mocktails','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sparkling Elderflower Lemonade','sparkling-elderflower-lemonade','An elegant and floral mocktail combining elderflower cordial with freshly squeezed lemon juice and sparkling water. This sophisticated drink is light, aromatic, and perfect for celebrations.','A delicate and floral sparkling lemonade with elderflower that feels special enough for any festive occasion.','British','Easy',5,0,5,2,110,0,28,0,0,'[{"amount":60,"unit":"ml","item":"elderflower cordial","group":"base"},{"amount":90,"unit":"ml","item":"fresh lemon juice","group":"base"},{"amount":300,"unit":"ml","item":"sparkling water","group":"base"},{"amount":20,"unit":"ml","item":"simple syrup","group":"sweetener"},{"amount":4,"unit":"slices","item":"fresh cucumber","group":"flavor"},{"amount":1,"unit":"cup","item":"ice cubes","group":"serving"},{"amount":2,"unit":"slices","item":"lemon for garnish","group":"garnish"},{"amount":4,"unit":"sprigs","item":"fresh thyme for garnish","group":"garnish"}]','[{"title":"Infuse the Cucumber","text":"Place the cucumber slices into a small jug with the elderflower cordial and let them sit together for 2 minutes. This quick infusion adds a subtle fresh and cool note to the drink.","timer":120},{"title":"Mix the Base","text":"In a cocktail shaker or mixing jug, combine the elderflower cordial with the cucumber slices, fresh lemon juice, and simple syrup. Stir well to make sure the syrup is fully dissolved.","timer":0},{"title":"Fill the Glasses","text":"Fill two tall glasses generously with ice cubes. Place one cucumber slice and a sprig of fresh thyme into each glass for added visual appeal and subtle aroma.","timer":0},{"title":"Pour and Top","text":"Divide the elderflower and lemon mixture evenly between the two glasses by pouring it over the ice. Top each glass slowly with sparkling water to retain maximum bubbles.","timer":0},{"title":"Garnish and Serve","text":"Gently stir each drink once with a long spoon. Garnish with a lemon slice on the rim and an extra sprig of fresh thyme. Serve immediately while the sparkling water is still bubbly.","timer":0}]','[{"original":"elderflower cordial","swap":"rose water syrup for a different but equally floral and elegant flavor"},{"original":"fresh thyme","swap":"fresh basil leaves for a slightly more herbal and Italian-inspired aroma"},{"original":"simple syrup","swap":"lavender syrup for an extra floral and aromatic layer of sweetness"}]','["Using too much elderflower cordial which makes the drink overly sweet and overpowers the fresh lemon","Using bottled lemon juice instead of fresh which gives the drink a flat and artificial taste","Stirring too vigorously after adding the sparkling water which releases all the bubbles and flattens the drink"]','["mocktail","elderflower","lemonade","floral","elegant","sparkling","alcohol-free","British"]','["vegan","gluten-free","dairy-free"]','Mocktails','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Arnold Palmer','arnold-palmer','A classic blend of iced tea and lemonade named after the legendary golfer. This refreshing drink is perfect for warm days and easy entertaining.','A half and half mix of freshly brewed iced tea and tart lemonade served over ice.','American','Easy',10,5,15,2,120,0,32,0,0,'[{"amount":2,"unit":"cups","item":"water","group":"Tea"},{"amount":2,"unit":"bags","item":"black tea bags","group":"Tea"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"Tea"},{"amount":1,"unit":"cup","item":"fresh lemon juice","group":"Lemonade"},{"amount":3,"unit":"cups","item":"cold water","group":"Lemonade"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"Lemonade"},{"amount":2,"unit":"cups","item":"ice cubes","group":"Serving"},{"amount":2,"unit":"slices","item":"lemon","group":"Garnish"}]','[{"title":"Brew the Tea","text":"Bring 2 cups of water to a boil. Remove from heat and steep both tea bags for 5 minutes. Remove bags and stir in 2 tablespoons of sugar until dissolved. Let cool to room temperature.","timer":300},{"title":"Make the Lemonade","text":"Combine 0.5 cup sugar with 0.5 cup hot water in a small saucepan and stir until sugar dissolves to form a simple syrup. Mix the syrup with fresh lemon juice and 2.5 cups cold water in a pitcher.","timer":120},{"title":"Chill Both Components","text":"Refrigerate both the brewed tea and the lemonade until fully cold, at least 30 minutes. Cold components ensure the drink stays chilled longer and does not water down over ice.","timer":1800},{"title":"Combine and Pour","text":"Fill two tall glasses with ice cubes. Pour equal parts iced tea and lemonade simultaneously into each glass or layer lemonade first then tea for a visual effect.","timer":60},{"title":"Garnish and Serve","text":"Place a lemon slice on the rim of each glass. Stir gently before drinking and serve immediately for the best flavor and chill.","timer":30}]','[{"original":"black tea bags","swap":"green tea bags for a lighter flavor"},{"original":"granulated sugar","swap":"honey for a floral sweetness"},{"original":"fresh lemon juice","swap":"bottled lemon juice in a pinch"}]','["Over-steeping the tea which causes a bitter and astringent flavor","Using warm tea over ice which dilutes the drink too quickly","Adding too much sugar to the lemonade which overwhelms the tea flavor"]','["refreshing","summer drink","classic","lemonade","iced tea","no alcohol"]','["vegan","gluten-free","dairy-free"]','Beverage','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Virgin Mary','virgin-mary','A bold and savory tomato juice mocktail packed with spice and umami flavor. It delivers all the satisfaction of a Bloody Mary without any alcohol.','A spiced tomato juice drink with hot sauce, Worcestershire, and fresh garnishes served over ice.','American','Easy',10,0,10,2,80,3,14,0,2,'[{"amount":2,"unit":"cups","item":"tomato juice","group":"Base"},{"amount":2,"unit":"tablespoons","item":"fresh lemon juice","group":"Base"},{"amount":1,"unit":"teaspoon","item":"Worcestershire sauce","group":"Seasoning"},{"amount":0.5,"unit":"teaspoon","item":"hot sauce","group":"Seasoning"},{"amount":0.25,"unit":"teaspoon","item":"celery salt","group":"Seasoning"},{"amount":0.25,"unit":"teaspoon","item":"black pepper","group":"Seasoning"},{"amount":2,"unit":"stalks","item":"celery","group":"Garnish"},{"amount":2,"unit":"wedges","item":"lemon","group":"Garnish"}]','[{"title":"Prepare the Mix","text":"In a large pitcher combine tomato juice, fresh lemon juice, Worcestershire sauce, hot sauce, celery salt, and black pepper. Stir everything together thoroughly until all seasonings are evenly distributed.","timer":60},{"title":"Taste and Adjust","text":"Taste the mixture and adjust seasoning to your preference. Add more hot sauce for extra heat, more lemon for brightness, or more celery salt for a deeper savory note.","timer":30},{"title":"Chill the Mixture","text":"Refrigerate the tomato mixture for at least 15 minutes to allow the flavors to meld together. This step makes a noticeable difference in the overall depth of flavor.","timer":900},{"title":"Prepare the Glasses","text":"Run a lemon wedge around the rim of each glass then dip the rim into a small plate of celery salt to create a seasoned rim. Fill each glass with ice cubes.","timer":60},{"title":"Pour and Garnish","text":"Pour the tomato mixture over the ice in each rimmed glass. Garnish with a celery stalk and a lemon wedge on the rim. Serve immediately.","timer":30}]','[{"original":"tomato juice","swap":"vegetable juice blend for extra complexity"},{"original":"Worcestershire sauce","swap":"soy sauce for a vegan alternative"},{"original":"hot sauce","swap":"horseradish for a sharper heat"}]','["Skipping the chilling step which leaves the flavors tasting flat and separate","Using low quality tomato juice which makes the drink taste thin and bland","Over salting the rim which makes every sip too salty"]','["savory","tomato","mocktail","brunch","spicy","no alcohol"]','["vegan","gluten-free","dairy-free","low calorie"]','Beverage','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sleepy Girl Mocktail','sleepy-girl-mocktail','A viral tart cherry and magnesium mocktail designed to support relaxation and better sleep. It is sweet, bubbly, and genuinely soothing before bedtime.','A two ingredient mocktail of tart cherry juice and prebiotic soda with optional magnesium powder for sleep support.','American','Easy',5,0,5,1,130,1,33,0,0,'[{"amount":0.5,"unit":"cup","item":"pure tart cherry juice","group":"Base"},{"amount":1,"unit":"cup","item":"prebiotic soda","group":"Base"},{"amount":1,"unit":"teaspoon","item":"magnesium glycinate powder","group":"Supplement"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Serving"},{"amount":1,"unit":"tablespoon","item":"fresh lime juice","group":"Optional"},{"amount":2,"unit":"slices","item":"fresh lime","group":"Garnish"},{"amount":0.5,"unit":"teaspoon","item":"honey","group":"Optional"},{"amount":4,"unit":"leaves","item":"fresh mint","group":"Garnish"}]','[{"title":"Prepare Your Glass","text":"Fill a tall glass with ice cubes all the way to the top. A chilled glass works best to keep the drink cold and the bubbles lively throughout.","timer":30},{"title":"Add the Cherry Juice","text":"Pour the tart cherry juice directly over the ice. Use pure 100 percent tart cherry juice with no added sugar for the best flavor and the most natural melatonin support.","timer":15},{"title":"Mix in the Magnesium","text":"Stir the magnesium glycinate powder into the cherry juice until it fully dissolves. Do not skip this step or the powder will clump when the soda is added.","timer":30},{"title":"Top with Prebiotic Soda","text":"Slowly pour the prebiotic soda over the back of a spoon to preserve the carbonation. Add fresh lime juice and a small drizzle of honey at this stage if desired.","timer":20},{"title":"Garnish and Enjoy","text":"Tuck mint leaves and lime slices into the glass for garnish. Give the drink one gentle stir and sip slowly about 30 to 60 minutes before bedtime.","timer":15}]','[{"original":"prebiotic soda","swap":"sparkling water for a lower sugar option"},{"original":"magnesium glycinate powder","swap":"omit entirely for a standard mocktail without supplements"},{"original":"tart cherry juice","swap":"pomegranate juice for a slightly sweeter variation"}]','["Using sweetened cherry cocktail instead of pure tart cherry juice which adds excess sugar","Adding magnesium powder after the soda which causes excessive fizzing and clumping","Drinking it too late at night and not allowing enough time for the magnesium to take effect"]','["sleep","wellness","tart cherry","mocktail","viral","relaxing","no alcohol"]','["vegan","gluten-free","dairy-free"]','Beverage','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Shirley Temple','classic-shirley-temple','A beloved sweet and bubbly non alcoholic drink made with ginger ale, grenadine, and a bright cherry on top. This iconic mocktail has delighted guests of all ages for decades.','A fizzy combination of ginger ale and grenadine syrup garnished with maraschino cherries and an orange slice.','American','Easy',5,0,5,2,150,0,38,0,0,'[{"amount":2,"unit":"cups","item":"ginger ale","group":"Base"},{"amount":3,"unit":"tablespoons","item":"grenadine syrup","group":"Base"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Serving"},{"amount":4,"unit":"whole","item":"maraschino cherries","group":"Garnish"},{"amount":2,"unit":"slices","item":"orange","group":"Garnish"},{"amount":2,"unit":"teaspoons","item":"fresh orange juice","group":"Optional"},{"amount":2,"unit":"slices","item":"lemon","group":"Garnish"},{"amount":2,"unit":"whole","item":"decorative paper straws","group":"Serving"}]','[{"title":"Chill the Glasses","text":"Place two tall glasses in the freezer for 5 minutes or fill them with ice water and let sit while you prepare the other ingredients. A cold glass keeps the drink fizzy longer.","timer":300},{"title":"Add Ice","text":"Discard the ice water if used to chill the glasses then fill each glass generously with fresh ice cubes. Pack the ice tightly so the drink stays cold throughout.","timer":20},{"title":"Pour the Grenadine","text":"Add 1.5 tablespoons of grenadine syrup to each glass. The grenadine will sink to the bottom and create a beautiful layered look before stirring.","timer":15},{"title":"Top with Ginger Ale","text":"Slowly pour one cup of cold ginger ale into each glass over the back of a spoon to protect the bubbles. Add a splash of fresh orange juice if desired for extra citrus flavor.","timer":20},{"title":"Garnish and Serve","text":"Thread two maraschino cherries onto a cocktail pick and rest it across the top of each glass. Add an orange slice and lemon slice to the rim and insert a decorative straw. Serve immediately.","timer":30}]','[{"original":"ginger ale","swap":"lemon lime soda for a slightly different flavor profile"},{"original":"grenadine syrup","swap":"pomegranate juice for a less sweet and more natural option"},{"original":"maraschino cherries","swap":"fresh cherries for a less sweet and more natural garnish"}]','["Pouring ginger ale too fast which destroys the carbonation and makes the drink flat","Using warm ginger ale straight from the pantry instead of a chilled bottle","Adding too much grenadine which makes the drink cloyingly sweet and overpowers the ginger ale"]','["classic","sweet","bubbly","kids drink","mocktail","party","no alcohol"]','["vegan","gluten-free","dairy-free"]','Beverage','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sparkling Cucumber Mint Cooler','sparkling-cucumber-mint-cooler','A crisp and elegantly refreshing mocktail built around cool cucumber and bright fresh mint. It is light, hydrating, and perfect for warm weather sipping.','A clean and herbal sparkling water drink infused with cucumber, mint, and a hint of lime.','American','Easy',10,0,10,2,40,0,10,0,1,'[{"amount":1,"unit":"whole","item":"English cucumber","group":"Base"},{"amount":10,"unit":"leaves","item":"fresh mint leaves","group":"Base"},{"amount":2,"unit":"tablespoons","item":"fresh lime juice","group":"Base"},{"amount":1,"unit":"tablespoon","item":"simple syrup","group":"Sweetener"},{"amount":2,"unit":"cups","item":"sparkling water","group":"Base"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Serving"},{"amount":4,"unit":"slices","item":"cucumber","group":"Garnish"},{"amount":2,"unit":"sprigs","item":"fresh mint","group":"Garnish"}]','[{"title":"Muddle the Cucumber and Mint","text":"Peel and roughly chop half the cucumber. Place the chopped cucumber and 8 fresh mint leaves into a cocktail shaker or sturdy glass. Muddle firmly for about 20 seconds to release the juices and oils.","timer":20},{"title":"Add Lime and Syrup","text":"Pour the fresh lime juice and simple syrup over the muddled cucumber and mint. Stir to combine and let the mixture sit for 2 minutes so the flavors infuse together.","timer":120},{"title":"Strain into Glasses","text":"Fill two glasses with ice. Pour the cucumber mint mixture through a fine mesh strainer into each glass, pressing on the solids with a spoon to extract as much liquid as possible.","timer":30},{"title":"Top with Sparkling Water","text":"Slowly pour one cup of cold sparkling water into each glass. Pour gently over the back of a spoon to keep the bubbles intact and maintain carbonation.","timer":20},{"title":"Garnish and Serve","text":"Slice the remaining cucumber thinly and fan two slices on the rim of each glass. Add a fresh mint sprig and serve immediately while the drink is still sparkling and cold.","timer":30}]','[{"original":"simple syrup","swap":"agave nectar for a vegan and lower glycemic option"},{"original":"sparkling water","swap":"coconut water for a tropical and naturally sweet variation"},{"original":"lime juice","swap":"lemon juice for a slightly softer and less sharp citrus note"}]','["Over muddling the mint which releases bitter compounds and makes the drink taste harsh","Skipping the straining step which leaves pulpy bits in the glass and changes the texture","Using flat or warm sparkling water which removes the refreshing effervescence from the final drink"]','["refreshing","light","cucumber","mint","mocktail","summer","low calorie","no alcohol"]','["vegan","gluten-free","dairy-free","low calorie"]','Beverage','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Guava Mocktail','spicy-guava-mocktail','A bold tropical mocktail blending sweet guava with a fiery chili kick. It is refreshing and vibrant with every sip.','A sweet and spicy guava mocktail ready in under 10 minutes.','Latin Fusion','Easy',8,0,8,2,120,1,30,0,1,'[{"amount":1,"unit":"cup","item":"guava juice","group":"base"},{"amount":0.5,"unit":"cup","item":"sparkling water","group":"base"},{"amount":2,"unit":"tbsp","item":"lime juice","group":"base"},{"amount":1,"unit":"tbsp","item":"agave syrup","group":"sweetener"},{"amount":0.25,"unit":"tsp","item":"cayenne pepper","group":"spice"},{"amount":0.5,"unit":"tsp","item":"chili salt","group":"garnish"},{"amount":1,"unit":"cup","item":"ice cubes","group":"base"},{"amount":2,"unit":"slices","item":"fresh lime","group":"garnish"},{"amount":2,"unit":"sprigs","item":"fresh mint","group":"garnish"}]','[{"title":"Prepare the glass","text":"Rub a lime wedge around the rim of each glass and dip into chili salt to coat the rim evenly. Fill each glass with ice cubes.","timer":0},{"title":"Mix the base","text":"In a small pitcher combine guava juice, lime juice, and agave syrup. Stir well until the agave is fully dissolved.","timer":60},{"title":"Add the spice","text":"Sprinkle in the cayenne pepper and stir vigorously to incorporate it throughout the mixture. Taste and adjust heat to your preference.","timer":30},{"title":"Pour and fizz","text":"Pour the guava mixture over the iced glasses filling them about three quarters full. Top each glass gently with sparkling water.","timer":0},{"title":"Garnish and serve","text":"Place a lime slice on the rim and tuck in a fresh mint sprig. Serve immediately while the fizz is still active.","timer":0}]','[{"original":"agave syrup","swap":"honey or simple syrup"},{"original":"cayenne pepper","swap":"tajin seasoning"},{"original":"sparkling water","swap":"ginger beer for extra kick"}]','["Adding sparkling water too early causing the fizz to go flat before serving","Using too much cayenne which overwhelms the sweet guava flavor","Skipping the chili salt rim which is a key part of the flavor profile"]','["mocktail","tropical","spicy","guava","non-alcoholic","summer"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Mango Habanero Fizz','mango-habanero-fizz','A fiery and fruity sparkling drink that combines ripe mango with the intense heat of habanero. This fizz is not for the faint of heart.','A bold sparkling mango drink with a serious habanero heat in just 10 minutes.','Caribbean Fusion','Easy',10,5,15,2,140,1,35,0,2,'[{"amount":1,"unit":"cup","item":"mango puree","group":"base"},{"amount":0.5,"unit":"cup","item":"club soda","group":"base"},{"amount":1,"unit":"whole","item":"habanero pepper seeded and minced","group":"spice"},{"amount":3,"unit":"tbsp","item":"sugar","group":"sweetener"},{"amount":3,"unit":"tbsp","item":"water","group":"sweetener"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"base"},{"amount":1,"unit":"cup","item":"ice","group":"base"},{"amount":2,"unit":"slices","item":"fresh mango","group":"garnish"},{"amount":0.25,"unit":"tsp","item":"tajin seasoning","group":"garnish"}]','[{"title":"Make habanero simple syrup","text":"Combine sugar, water, and minced habanero in a small saucepan over medium heat. Stir until sugar dissolves then simmer for 3 minutes. Strain through a fine mesh sieve and let cool completely.","timer":300},{"title":"Blend the mango base","text":"Stir together mango puree, lime juice, and 2 tablespoons of the cooled habanero syrup in a pitcher. Mix well and taste for heat level.","timer":60},{"title":"Prepare the glasses","text":"Rim each glass with lime juice and a pinch of tajin seasoning. Add ice to each glass.","timer":0},{"title":"Build the drink","text":"Pour the mango habanero mixture over ice until glasses are three quarters full. Slowly top with club soda and do not stir to preserve the fizz.","timer":0},{"title":"Garnish and serve","text":"Slide a fresh mango slice onto the rim of each glass. Serve immediately and warn guests about the heat level.","timer":0}]','[{"original":"habanero pepper","swap":"serrano pepper for milder heat"},{"original":"mango puree","swap":"fresh blended mango with a splash of water"},{"original":"club soda","swap":"ginger ale for a sweeter finish"}]','["Not straining the habanero syrup which leaves bitter pepper bits in the drink","Adding too much habanero syrup without tasting first since heat levels vary by pepper","Stirring after adding club soda which destroys the effervescence"]','["mocktail","mango","habanero","spicy","fizz","tropical","non-alcoholic"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hot Honey Lemonade','hot-honey-lemonade','A comforting warm lemonade sweetened with spiced honey and fresh lemon juice. It is the perfect soothing drink for cool evenings.','A warm soothing lemonade made with hot honey and fresh citrus in just 10 minutes.','American','Easy',5,5,10,2,110,0,29,0,0,'[{"amount":2,"unit":"cups","item":"hot water","group":"base"},{"amount":4,"unit":"tbsp","item":"fresh lemon juice","group":"base"},{"amount":3,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":0.5,"unit":"tsp","item":"red pepper flakes","group":"spice"},{"amount":0.25,"unit":"tsp","item":"ground ginger","group":"spice"},{"amount":2,"unit":"slices","item":"fresh lemon","group":"garnish"},{"amount":1,"unit":"stick","item":"cinnamon","group":"garnish"},{"amount":1,"unit":"pinch","item":"sea salt","group":"seasoning"}]','[{"title":"Make the hot honey","text":"Warm honey in a small saucepan over low heat for 2 minutes. Add red pepper flakes and ground ginger and stir well. Do not let the honey boil.","timer":120},{"title":"Heat the water","text":"Heat water until it is hot but not boiling, around 190 degrees Fahrenheit. Boiling water can destroy some of the honey nutrients and alter the flavor.","timer":180},{"title":"Combine ingredients","text":"Pour the hot water into mugs. Add freshly squeezed lemon juice and the hot honey mixture. Stir well to combine everything evenly.","timer":30},{"title":"Season and balance","text":"Add a pinch of sea salt to enhance all flavors. Taste and adjust honey or lemon juice to reach your preferred balance of sweet and tart.","timer":0},{"title":"Garnish and serve","text":"Place a lemon slice on the rim and a cinnamon stick in each mug as a stirrer. Serve immediately while hot.","timer":0}]','[{"original":"honey","swap":"maple syrup for a vegan option"},{"original":"red pepper flakes","swap":"a pinch of cayenne pepper"},{"original":"fresh lemon juice","swap":"bottled lemon juice in a pinch"}]','["Boiling the honey which destroys its natural enzymes and changes the flavor","Using bottled lemon juice instead of fresh which results in a flat flavor","Adding too many pepper flakes without tasting first making the drink unpleasantly spicy"]','["hot drink","lemonade","honey","spicy","warm","winter","soothing"]','["gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pineapple Chili Cooler','pineapple-chili-cooler','A refreshing tropical cooler that pairs sweet pineapple with a bold chili punch. It is a crowd-pleasing drink with a memorable heat finish.','A sweet tropical pineapple drink with a spicy chili kick ready in 10 minutes.','Tropical Fusion','Easy',10,0,10,2,130,1,32,0,1,'[{"amount":1,"unit":"cup","item":"fresh pineapple juice","group":"base"},{"amount":0.5,"unit":"cup","item":"coconut water","group":"base"},{"amount":2,"unit":"tbsp","item":"lime juice","group":"base"},{"amount":1,"unit":"tbsp","item":"honey","group":"sweetener"},{"amount":0.5,"unit":"tsp","item":"chili powder","group":"spice"},{"amount":0.25,"unit":"tsp","item":"cayenne pepper","group":"spice"},{"amount":1,"unit":"cup","item":"ice cubes","group":"base"},{"amount":2,"unit":"wedges","item":"fresh pineapple","group":"garnish"},{"amount":0.5,"unit":"tsp","item":"tajin seasoning","group":"garnish"}]','[{"title":"Prepare the spice blend","text":"Combine chili powder and cayenne pepper in a small bowl and mix well. This ensures even heat distribution throughout the drink.","timer":0},{"title":"Mix the liquid base","text":"In a pitcher stir together pineapple juice, coconut water, lime juice, and honey until the honey fully dissolves.","timer":60},{"title":"Add the spice","text":"Whisk the chili powder blend into the pineapple mixture. Start with half the amount and taste before adding more to control the heat level.","timer":30},{"title":"Build the glasses","text":"Coat the rim of each glass with tajin seasoning using a lime wedge as adhesive. Fill each glass with ice then pour the pineapple chili mixture over the top.","timer":0},{"title":"Garnish and serve","text":"Skewer a fresh pineapple wedge on the rim of each glass. Serve immediately and stir before drinking to redistribute the spices.","timer":0}]','[{"original":"fresh pineapple juice","swap":"canned pineapple juice for convenience"},{"original":"coconut water","swap":"plain water or sparkling water"},{"original":"honey","swap":"agave syrup for a vegan version"}]','["Not tasting the spice blend before adding the full amount leading to an overly hot drink","Skipping the tajin rim which adds an important savory contrast to the sweetness","Using old chili powder that has lost its potency resulting in a flat spice flavor"]','["mocktail","pineapple","chili","tropical","spicy","non-alcoholic","summer"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Watermelon Jalapeno Slush','watermelon-jalapeno-slush','A frosty blended watermelon drink with a sharp jalapeno heat that lingers on the palate. It is the ultimate sweet and spicy summer refresher.','A frosty watermelon slush with jalapeno heat that takes only 10 minutes to make.','Mexican Inspired','Easy',10,0,10,2,95,1,23,0,1,'[{"amount":3,"unit":"cups","item":"fresh watermelon chunks seedless","group":"base"},{"amount":1,"unit":"whole","item":"jalapeno seeded and sliced","group":"spice"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"base"},{"amount":1,"unit":"tbsp","item":"agave syrup","group":"sweetener"},{"amount":1.5,"unit":"cups","item":"ice cubes","group":"base"},{"amount":0.25,"unit":"tsp","item":"salt","group":"seasoning"},{"amount":2,"unit":"slices","item":"watermelon wedge for garnish","group":"garnish"},{"amount":0.5,"unit":"tsp","item":"chili lime seasoning","group":"garnish"},{"amount":2,"unit":"rings","item":"jalapeno slices for garnish","group":"garnish"}]','[{"title":"Prep the jalapeno","text":"Slice the jalapeno in half lengthwise and remove all seeds and white membrane using a spoon. Wear gloves if your skin is sensitive. Slice into small pieces.","timer":0},{"title":"Blend the base","text":"Add watermelon chunks, jalapeno pieces, lime juice, agave syrup, and salt to a blender. Blend on high for 30 seconds until completely smooth.","timer":30},{"title":"Add ice and blend again","text":"Add ice cubes to the blender and blend again on high speed until the mixture becomes a thick slush consistency. Do not over blend or it will become too liquid.","timer":20},{"title":"Taste and adjust","text":"Taste the slush and adjust heat by adding more jalapeno or sweetness by adding more agave. Blend briefly after any additions.","timer":10},{"title":"Serve and garnish","text":"Pour the slush into chilled glasses. Sprinkle chili lime seasoning on top and garnish with a watermelon wedge and a fresh jalapeno ring on the rim.","timer":0}]','[{"original":"jalapeno","swap":"serrano pepper for more intense heat"},{"original":"agave syrup","swap":"simple syrup or honey"},{"original":"fresh watermelon","swap":"frozen watermelon chunks for a thicker slush"}]','["Leaving seeds in the jalapeno which can make the drink unpredictably and overwhelmingly spicy","Over blending the ice which turns the slush into a watery liquid instead of a frozen texture","Not chilling the glasses beforehand which causes the slush to melt too quickly"]','["mocktail","slush","watermelon","jalapeno","spicy","frozen","summer","non-alcoholic"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cucumber Mint Fizz','cucumber-mint-fizz','A crisp and cooling sparkling drink made with fresh cucumber and vibrant mint. Perfect for hot summer days or elegant entertaining.','A refreshing sparkling cucumber and mint drink ready in minutes.','American','Easy',10,0,10,4,45,0,11,0,0,'[{"amount":1,"unit":"large","item":"English cucumber","group":"Produce"},{"amount":20,"unit":"leaves","item":"fresh mint","group":"Produce"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"Produce"},{"amount":3,"unit":"tbsp","item":"simple syrup","group":"Sweetener"},{"amount":4,"unit":"cups","item":"sparkling water","group":"Liquid"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Other"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"Seasoning"},{"amount":4,"unit":"slices","item":"cucumber for garnish","group":"Garnish"}]','[{"title":"Blend the Cucumber","text":"Peel and roughly chop the cucumber. Place it in a blender and blend until completely smooth. Strain through a fine mesh sieve into a pitcher, pressing to extract all the juice. Discard the solids.","timer":120},{"title":"Muddle the Mint","text":"Place the fresh mint leaves in the bottom of the pitcher with the cucumber juice. Gently muddle the mint using a muddler or the back of a spoon to release the oils. Do not over-muddle or the mint will turn bitter.","timer":30},{"title":"Add Sweetener and Citrus","text":"Pour the simple syrup and fresh lime juice into the pitcher. Add the sea salt and stir well to combine all the flavors together.","timer":30},{"title":"Add Sparkling Water","text":"Slowly pour the sparkling water into the pitcher and stir gently to preserve the carbonation. Taste and adjust sweetness or lime juice as needed.","timer":30},{"title":"Serve and Garnish","text":"Fill glasses with ice cubes and pour the cucumber mint fizz over the top. Garnish each glass with a fresh cucumber slice and a sprig of mint. Serve immediately.","timer":60}]','[{"original":"simple syrup","swap":"honey or agave nectar"},{"original":"sparkling water","swap":"club soda or tonic water"},{"original":"lime juice","swap":"lemon juice"}]','["Over-muddling the mint which releases bitter compounds from the stems","Skipping the straining step which leaves pulp in the drink","Adding sparkling water too early causing the drink to go flat"]','["summer","refreshing","sparkling","nonalcoholic","cucumber","mint"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Lavender Lemonade','lavender-lemonade','A floral and tangy lemonade infused with aromatic culinary lavender syrup. This elegant drink is both soothing and refreshing.','A beautifully floral lavender-infused lemonade that is sweet, tart, and elegant.','French-Inspired','Easy',15,10,25,6,95,0,25,0,0,'[{"amount":2,"unit":"tbsp","item":"dried culinary lavender buds","group":"Flavorings"},{"amount":1,"unit":"cup","item":"granulated sugar","group":"Sweetener"},{"amount":1.5,"unit":"cups","item":"water for syrup","group":"Liquid"},{"amount":1.5,"unit":"cups","item":"fresh lemon juice","group":"Produce"},{"amount":4,"unit":"cups","item":"cold water","group":"Liquid"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Other"},{"amount":6,"unit":"sprigs","item":"fresh lavender for garnish","group":"Garnish"},{"amount":6,"unit":"slices","item":"lemon for garnish","group":"Garnish"}]','[{"title":"Make the Lavender Syrup","text":"Combine the sugar, water, and dried culinary lavender buds in a small saucepan over medium heat. Stir until the sugar dissolves completely and the mixture just begins to simmer. Do not let it boil rapidly.","timer":300},{"title":"Steep and Strain","text":"Remove the saucepan from heat and allow the lavender to steep in the syrup for 10 minutes. Strain the syrup through a fine mesh sieve into a heat-safe container and allow it to cool completely to room temperature.","timer":600},{"title":"Juice the Lemons","text":"While the syrup cools, juice enough fresh lemons to yield 1.5 cups of juice. Strain the juice to remove seeds and excess pulp. Fresh lemon juice makes a significant difference in flavor.","timer":300},{"title":"Combine and Mix","text":"In a large pitcher, combine the cooled lavender syrup, fresh lemon juice, and cold water. Stir well to combine. Taste and adjust by adding more lemon juice for tartness or more water to dilute.","timer":60},{"title":"Serve","text":"Fill tall glasses with ice and pour the lavender lemonade over the ice. Garnish each glass with a fresh lavender sprig and a lemon slice. Serve immediately or refrigerate for up to 3 days.","timer":60}]','[{"original":"granulated sugar","swap":"honey for a more earthy sweetness"},{"original":"dried culinary lavender","swap":"lavender extract but use only 1 teaspoon"},{"original":"fresh lemon juice","swap":"bottled lemon juice in a pinch"}]','["Using non-culinary lavender which can contain pesticides or taste soapy","Steeping the lavender too long which makes the syrup taste overpowering and perfumed","Adding the syrup while it is still hot which dilutes the lemonade and reduces carbonation if used"]','["floral","summer","elegant","lemonade","lavender","nonalcoholic"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Watermelon Basil Cooler','watermelon-basil-cooler','A vibrant and juicy cooler combining sweet watermelon with the herbaceous punch of fresh basil. This drink is visually stunning and incredibly refreshing.','A bold and fruity watermelon drink with a surprising fresh basil twist.','American','Easy',10,0,10,4,70,1,17,0,1,'[{"amount":6,"unit":"cups","item":"seedless watermelon cubed","group":"Produce"},{"amount":15,"unit":"leaves","item":"fresh basil","group":"Produce"},{"amount":3,"unit":"tbsp","item":"fresh lime juice","group":"Produce"},{"amount":2,"unit":"tbsp","item":"honey","group":"Sweetener"},{"amount":2,"unit":"cups","item":"sparkling water","group":"Liquid"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"Seasoning"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Other"},{"amount":4,"unit":"small","item":"basil sprigs for garnish","group":"Garnish"}]','[{"title":"Blend the Watermelon","text":"Place the cubed watermelon into a blender and blend on high speed until completely smooth and liquified. Strain through a fine mesh sieve into a large pitcher to remove any fibrous pulp. You should have about 3 cups of juice.","timer":90},{"title":"Muddle the Basil","text":"Add the fresh basil leaves to the pitcher with the watermelon juice. Gently muddle the basil to release its aromatic oils. Do not tear the basil into tiny pieces as this can make the drink look murky.","timer":30},{"title":"Add Flavoring","text":"Add the fresh lime juice, honey, and sea salt to the pitcher. Whisk or stir vigorously until the honey fully dissolves into the juice. The salt enhances the natural sweetness of the watermelon.","timer":60},{"title":"Add Sparkling Water","text":"Pour the sparkling water gently into the pitcher and stir slowly to combine without losing the carbonation. Taste the drink and adjust the lime juice or honey to your preference.","timer":30},{"title":"Serve Immediately","text":"Fill chilled glasses with ice cubes and pour the watermelon basil cooler over the ice. Garnish each glass with a fresh basil sprig and serve right away for the best carbonation and color.","timer":60}]','[{"original":"honey","swap":"agave syrup for a vegan version"},{"original":"fresh basil","swap":"fresh mint for a more classic combination"},{"original":"sparkling water","swap":"coconut water for a tropical variation"}]','["Skipping the straining step which results in a pulpy and unpleasant texture","Using watermelon that is not fully ripe which makes the drink bland and watery","Letting the basil sit too long in the drink which turns it brown and bitter"]','["summer","watermelon","basil","fruity","sparkling","nonalcoholic"]','["gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Peach Ginger Iced Tea','peach-ginger-iced-tea','A warming and fruity iced tea combining ripe peaches with spicy fresh ginger and black tea. This drink is comforting yet completely refreshing over ice.','A bold peach and ginger iced tea that is sweet, spicy, and deeply satisfying.','American','Medium',15,15,30,6,80,0,20,0,1,'[{"amount":3,"unit":"large","item":"ripe peaches pitted and sliced","group":"Produce"},{"amount":2,"unit":"inch","item":"fresh ginger peeled and sliced","group":"Produce"},{"amount":4,"unit":"bags","item":"black tea bags","group":"Tea"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"Sweetener"},{"amount":5,"unit":"cups","item":"water divided","group":"Liquid"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"Produce"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Other"},{"amount":6,"unit":"slices","item":"fresh peach for garnish","group":"Garnish"}]','[{"title":"Make the Peach Ginger Syrup","text":"Combine 2 cups of water, sliced peaches, sliced ginger, and sugar in a saucepan over medium heat. Bring to a simmer and cook for 15 minutes until the peaches are very soft and the syrup is fragrant. Mash the peaches gently as they cook.","timer":900},{"title":"Strain the Syrup","text":"Remove the saucepan from heat and strain the peach ginger mixture through a fine mesh sieve into a bowl, pressing firmly to extract all the flavorful syrup. Discard the solids and allow the syrup to cool.","timer":300},{"title":"Brew the Tea","text":"Bring the remaining 3 cups of water to a boil. Remove from heat and add the 4 black tea bags. Steep for exactly 5 minutes. Do not steep longer or the tea will become bitter and astringent. Remove the bags without squeezing them.","timer":300},{"title":"Combine Tea and Syrup","text":"Allow the brewed tea to cool to room temperature. Combine the cooled tea with the peach ginger syrup and fresh lemon juice in a large pitcher. Stir well to combine and taste for sweetness.","timer":60},{"title":"Serve Over Ice","text":"Fill tall glasses with ice cubes and pour the peach ginger iced tea over the top. Garnish with a fresh peach slice on the rim of the glass. Refrigerate any leftovers for up to 3 days.","timer":60}]','[{"original":"black tea","swap":"green tea for a lighter more delicate flavor"},{"original":"fresh peaches","swap":"frozen peaches work equally well when blended"},{"original":"granulated sugar","swap":"maple syrup for a richer depth of flavor"}]','["Steeping the tea too long which creates a harsh and overly bitter base","Using underripe peaches which do not break down properly and lack sweetness","Combining hot tea directly with the syrup and ice which dilutes the drink immediately"]','["iced tea","peach","ginger","summer","fruity","nonalcoholic"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hibiscus Rose Agua Fresca','hibiscus-rose-agua-fresca','A jewel-toned and deeply floral agua fresca made with dried hibiscus flowers and rose water. This vibrant Mexican-inspired drink is tart, sweet, and absolutely beautiful.','A stunning deep red hibiscus and rose agua fresca that is tart, floral, and refreshing.','Mexican','Easy',10,10,20,6,60,0,15,0,0,'[{"amount":1,"unit":"cup","item":"dried hibiscus flowers","group":"Flavorings"},{"amount":6,"unit":"cups","item":"water","group":"Liquid"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"Sweetener"},{"amount":1,"unit":"tsp","item":"rose water","group":"Flavorings"},{"amount":3,"unit":"tbsp","item":"fresh lime juice","group":"Produce"},{"amount":1,"unit":"strip","item":"orange peel","group":"Produce"},{"amount":1,"unit":"cup","item":"ice cubes","group":"Other"},{"amount":6,"unit":"small","item":"dried hibiscus flowers for garnish","group":"Garnish"}]','[{"title":"Simmer the Hibiscus","text":"Combine 3 cups of water, dried hibiscus flowers, sugar, and orange peel strip in a medium saucepan over medium heat. Bring to a gentle simmer and stir until the sugar dissolves. Simmer for 10 minutes until deeply colored and fragrant.","timer":600},{"title":"Steep and Strain","text":"Remove the saucepan from heat and allow the hibiscus to steep for an additional 5 minutes. Strain the concentrated liquid through a fine mesh sieve into a large pitcher, pressing the flowers to extract maximum color and flavor. Discard the solids.","timer":300},{"title":"Dilute and Flavor","text":"Add the remaining 3 cups of cold water to the pitcher with the hibiscus concentrate. Stir in the fresh lime juice and rose water. Start with just 1 teaspoon of rose water as it is very potent. Do not add more without tasting first.","timer":60},{"title":"Chill the Drink","text":"Allow the agua fresca to cool to room temperature and then refrigerate for at least 30 minutes until well chilled. The color will deepen beautifully as it cools. Taste and adjust sweetness or lime juice as desired.","timer":1800},{"title":"Serve and Garnish","text":"Fill glasses with ice cubes and pour the hibiscus rose agua fresca over the top. Garnish with a single dried hibiscus flower floating on top and a lime wedge on the rim. Serve immediately and stir before each pour as settling may occur.","timer":60}]','[{"original":"dried hibiscus flowers","swap":"hibiscus tea bags using 8 bags per batch"},{"original":"rose water","swap":"a few drops of rose extract but use very sparingly"},{"original":"granulated sugar","swap":"agave syrup for a smoother sweetness"}]','["Adding too much rose water which makes the drink taste like perfume or soap","Boiling the hibiscus vigorously which can make the flavor turn sharp and unpleasant","Skipping the chilling step and serving warm which mutes the bright tart flavors"]','["agua fresca","hibiscus","floral","Mexican","tart","nonalcoholic","vibrant"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Matcha Kiwi Fizz','matcha-kiwi-fizz','A vibrant green drink that blends earthy matcha with sweet tart kiwi and sparkling water. This refreshing fizz is perfect for warm afternoons or a light energy boost.','A bright and bubbly matcha drink layered with fresh kiwi puree and sparkling water.','Japanese Fusion','Easy',10,0,10,2,85,2,18,1,3,'[{"amount":2,"unit":"tsp","item":"ceremonial grade matcha powder","group":"matcha base"},{"amount":4,"unit":"tbsp","item":"hot water at 80 degrees C","group":"matcha base"},{"amount":3,"unit":"whole","item":"ripe kiwi peeled and sliced","group":"fruit layer"},{"amount":2,"unit":"tbsp","item":"honey or agave syrup","group":"sweetener"},{"amount":1,"unit":"tbsp","item":"fresh lime juice","group":"fruit layer"},{"amount":2,"unit":"cups","item":"sparkling water chilled","group":"fizz"},{"amount":1,"unit":"cup","item":"ice cubes","group":"serving"},{"amount":4,"unit":"slices","item":"kiwi for garnish","group":"garnish"}]','[{"title":"Whisk the Matcha","text":"Sift the matcha powder into a small bowl. Add the hot water and whisk in a rapid W or M motion until the matcha is fully dissolved and slightly frothy with no clumps remaining.","timer":120},{"title":"Prepare the Kiwi Puree","text":"Add the peeled kiwi slices to a blender along with the honey and lime juice. Blend on high until completely smooth. Strain through a fine mesh sieve if you prefer a pulp free drink.","timer":60},{"title":"Chill the Matcha","text":"Allow the whisked matcha to cool to room temperature or place it in the refrigerator for 5 minutes. Do not add ice directly to hot matcha as it will dilute the flavor too quickly.","timer":300},{"title":"Layer the Drink","text":"Fill two tall glasses with ice cubes. Pour the kiwi puree evenly into the bottom of each glass. Slowly pour the chilled matcha over the back of a spoon to create a distinct green layer on top.","timer":60},{"title":"Add Fizz and Serve","text":"Gently pour chilled sparkling water into each glass and give a very light stir to combine slightly. Garnish with kiwi slices on the rim and serve immediately.","timer":30}]','[{"original":"ceremonial grade matcha","swap":"culinary grade matcha for a bolder and more bitter flavor"},{"original":"honey","swap":"maple syrup for a vegan friendly version"},{"original":"sparkling water","swap":"coconut water for a tropical twist"}]','["Using boiling water to dissolve matcha which destroys delicate flavor compounds and makes the drink bitter","Adding sparkling water too aggressively which collapses the fizz and ruins the layered effect","Using unripe kiwi which results in an overly tart and harsh puree that overpowers the matcha"]','["matcha","kiwi","fizzy","green drink","refreshing","antioxidant","summer drink"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Blue Spirulina Mermaid Refresher','blue-spirulina-mermaid-refresher','A stunning ocean blue drink made with blue spirulina, coconut milk, and tropical fruit for a magical visual effect. This stunning refresher is as nutritious as it is beautiful.','A vivid ocean blue coconut and tropical fruit refresher powered by blue spirulina.','Tropical Fusion','Easy',10,0,10,2,140,3,22,6,2,'[{"amount":1,"unit":"tsp","item":"blue spirulina powder","group":"color base"},{"amount":1,"unit":"cup","item":"coconut milk chilled","group":"base"},{"amount":1,"unit":"cup","item":"pineapple juice chilled","group":"fruit layer"},{"amount":0.5,"unit":"cup","item":"mango chunks frozen","group":"fruit layer"},{"amount":2,"unit":"tbsp","item":"agave syrup","group":"sweetener"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavor"},{"amount":1.5,"unit":"cups","item":"ice cubes","group":"serving"},{"amount":2,"unit":"tbsp","item":"shredded toasted coconut for garnish","group":"garnish"}]','[{"title":"Blend the Mango Base","text":"Combine the frozen mango chunks and pineapple juice in a blender. Blend until smooth and creamy. Pour evenly into the bottom of two large clear glasses and set aside.","timer":60},{"title":"Mix the Blue Spirulina","text":"In a small pitcher or bowl whisk the blue spirulina powder into the chilled coconut milk until fully dissolved and the color is evenly distributed throughout with no visible clumps.","timer":90},{"title":"Sweeten the Coconut Mixture","text":"Stir the agave syrup and vanilla extract into the blue coconut milk mixture. Taste and adjust sweetness as needed. The mixture should be mildly sweet to balance the tropical fruit base.","timer":30},{"title":"Add Ice and Layer","text":"Place ice cubes carefully on top of the mango layer in each glass. Pour the blue spirulina coconut mixture slowly over the ice using a spoon to preserve the layered effect.","timer":60},{"title":"Garnish and Serve","text":"Sprinkle toasted shredded coconut on top of each drink. Serve with a wide straw and encourage guests to stir before drinking to enjoy the swirling color effect.","timer":30}]','[{"original":"blue spirulina powder","swap":"butterfly pea flower tea for a similar vivid blue color"},{"original":"coconut milk","swap":"oat milk for a lighter lower fat version"},{"original":"frozen mango chunks","swap":"frozen peach slices for a different tropical flavor profile"}]','["Using too much blue spirulina which creates an overwhelmingly green or teal color instead of a bright ocean blue","Pouring the coconut mixture too fast which destroys the layered visual effect before serving","Skipping the chilling step which results in a watery drink that dilutes quickly once ice is added"]','["spirulina","blue drink","mermaid","tropical","coconut","instagram worthy","summer"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Turmeric Ginger Wellness Shot','turmeric-ginger-wellness-shot','A potent and invigorating one ounce shot packed with anti-inflammatory turmeric and spicy fresh ginger. This wellness shot is a powerful daily ritual for gut and immune health.','A bold anti-inflammatory wellness shot made with fresh turmeric ginger lemon and black pepper.','Wellness','Easy',10,0,10,4,25,1,5,0,1,'[{"amount":3,"unit":"inches","item":"fresh turmeric root peeled","group":"base"},{"amount":2,"unit":"inches","item":"fresh ginger root peeled","group":"base"},{"amount":3,"unit":"whole","item":"lemons juiced","group":"acid"},{"amount":1,"unit":"tbsp","item":"raw honey","group":"sweetener"},{"amount":0.25,"unit":"tsp","item":"black pepper freshly ground","group":"absorption booster"},{"amount":0.25,"unit":"tsp","item":"cayenne pepper","group":"heat"},{"amount":0.5,"unit":"cup","item":"filtered water","group":"base"},{"amount":1,"unit":"pinch","item":"sea salt","group":"mineral boost"}]','[{"title":"Juice the Roots","text":"Feed the peeled turmeric and ginger through a juicer. If you do not have a juicer add both roots to a high speed blender with the filtered water and blend until completely pulverized.","timer":120},{"title":"Strain the Mixture","text":"If using a blender pour the blended mixture through a fine mesh sieve or nut milk bag pressing firmly to extract all the liquid. Discard the remaining pulp or save it for smoothies.","timer":120},{"title":"Combine All Ingredients","text":"Add the fresh lemon juice honey black pepper cayenne and sea salt to the strained turmeric ginger liquid. Whisk or stir vigorously until the honey is fully dissolved and everything is combined.","timer":60},{"title":"Taste and Adjust","text":"Taste the shot and adjust flavor as needed. Add more honey if the shot is too spicy or more lemon if it needs brightness. Do not skip the black pepper as it increases turmeric absorption by up to 2000 percent.","timer":30},{"title":"Pour and Store","text":"Pour into small 1 ounce shot glasses and serve immediately. Store any remaining shots in a sealed glass jar in the refrigerator for up to 5 days. Shake well before each use.","timer":30}]','[{"original":"fresh turmeric root","swap":"1 tsp of ground turmeric powder per inch of fresh root"},{"original":"raw honey","swap":"maple syrup for a fully vegan version"},{"original":"fresh lemon juice","swap":"fresh orange juice for a sweeter and milder flavor"}]','["Skipping the black pepper which dramatically reduces the bioavailability of curcumin the active compound in turmeric","Using ground ginger instead of fresh ginger which produces a much weaker and less potent wellness benefit","Storing the shots in plastic containers which can stain and absorb the strong turmeric flavor permanently"]','["wellness shot","turmeric","ginger","anti-inflammatory","immune boost","detox","daily ritual"]','["vegan","gluten-free","dairy-free","paleo"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hibiscus Rose Iced Tea Lemonade','hibiscus-rose-iced-tea-lemonade','A deeply crimson and floral iced drink that combines tart hibiscus tea with fragrant rose water and bright lemon. This elegant refresher is naturally caffeine free and visually stunning.','A tart and floral crimson iced tea lemonade made with dried hibiscus flowers and rose water.','Middle Eastern Fusion','Easy',10,10,40,4,65,0,16,0,0,'[{"amount":0.5,"unit":"cup","item":"dried hibiscus flowers","group":"tea base"},{"amount":4,"unit":"cups","item":"boiling water","group":"tea base"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":0.5,"unit":"cup","item":"fresh lemon juice about 4 lemons","group":"citrus"},{"amount":1,"unit":"tsp","item":"rose water food grade","group":"floral"},{"amount":2,"unit":"cups","item":"cold water","group":"dilution"},{"amount":2,"unit":"cups","item":"ice cubes","group":"serving"},{"amount":4,"unit":"slices","item":"lemon for garnish","group":"garnish"}]','[{"title":"Steep the Hibiscus Tea","text":"Add the dried hibiscus flowers to a heatproof pitcher. Pour the boiling water over the flowers and allow them to steep for 10 minutes. The liquid will turn a deep jewel red color.","timer":600},{"title":"Make the Simple Syrup","text":"While the tea steeps combine the sugar with 0.25 cup of hot water in a small saucepan over medium heat. Stir until the sugar is completely dissolved then remove from heat and cool.","timer":180},{"title":"Strain and Cool","text":"Strain the hibiscus tea through a fine mesh sieve discarding the spent flowers. Allow the tea to cool to room temperature for about 20 minutes or refrigerate for faster cooling.","timer":1200},{"title":"Combine and Flavor","text":"Add the simple syrup fresh lemon juice rose water and cold water to the cooled hibiscus tea. Stir well to combine. Taste and adjust sweetness or lemon as preferred. Do not add too much rose water as it can become soapy.","timer":60},{"title":"Serve Over Ice","text":"Fill tall glasses with ice cubes and pour the hibiscus lemonade over the ice. Garnish each glass with a lemon slice and an optional fresh or dried edible rose petal. Serve immediately.","timer":30}]','[{"original":"dried hibiscus flowers","swap":"4 hibiscus herbal tea bags for a quicker preparation"},{"original":"granulated sugar","swap":"honey dissolved in warm water for a more complex sweetness"},{"original":"rose water","swap":"a small sprig of fresh mint for a different but equally refreshing floral note"}]','["Steeping the hibiscus for too long which makes the tea excessively tart and overpowers all other flavors","Adding too much rose water which quickly turns the drink into an overwhelmingly perfumed and soapy tasting beverage","Using bottled lemon juice instead of fresh which results in a flat and artificial tasting drink"]','["hibiscus","iced tea","lemonade","floral","caffeine-free","summer","elegant"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Charcoal Lemonade Detox Drink','charcoal-lemonade-detox-drink','A dramatically black lemonade made with activated charcoal and fresh citrus that is as striking as it is refreshing. This detox drink pairs bold visual impact with a bright clean lemon flavor.','A jet black and tangy lemonade powered by activated charcoal and fresh squeezed lemon juice.','Modern Wellness','Easy',10,5,15,2,70,0,18,0,1,'[{"amount":1,"unit":"tsp","item":"food grade activated charcoal powder","group":"color base"},{"amount":0.5,"unit":"cup","item":"fresh lemon juice about 5 lemons","group":"citrus"},{"amount":0.33,"unit":"cup","item":"simple syrup","group":"sweetener"},{"amount":2,"unit":"cups","item":"filtered water chilled","group":"base"},{"amount":1,"unit":"tbsp","item":"fresh ginger juice","group":"wellness boost"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"mineral"},{"amount":1.5,"unit":"cups","item":"ice cubes","group":"serving"},{"amount":2,"unit":"slices","item":"lemon and mint sprigs for garnish","group":"garnish"}]','[{"title":"Make the Simple Syrup","text":"Combine 0.33 cup sugar with 0.33 cup water in a small saucepan over medium heat. Stir until the sugar is fully dissolved. Remove from heat and allow to cool completely before using.","timer":300},{"title":"Dissolve the Charcoal","text":"In a small bowl whisk the activated charcoal powder with 2 tablespoons of the chilled water until it forms a smooth black paste with no dry clumps. This ensures even color throughout the drink.","timer":60},{"title":"Combine All Liquids","text":"In a large pitcher combine the fresh lemon juice ginger juice simple syrup sea salt and remaining chilled water. Stir well. Add the dissolved charcoal paste and whisk until the color is uniform and deeply black.","timer":60},{"title":"Taste and Adjust","text":"Taste the lemonade and adjust sweetness or tartness as needed. Do not consume charcoal lemonade within 2 hours of taking any medications as activated charcoal can interfere with absorption.","timer":30},{"title":"Serve Over Ice","text":"Fill two tall glasses with ice cubes. Pour the black lemonade over the ice and garnish with a lemon slice and mint sprig. Stir before serving as the charcoal may settle slightly over time.","timer":30}]','[{"original":"activated charcoal powder","swap":"black sesame powder for a nutty black color alternative"},{"original":"simple syrup","swap":"agave nectar for a lower glycemic sweetener option"},{"original":"fresh ginger juice","swap":"a pinch of cayenne pepper for a different warming kick"}]','["Using too much activated charcoal which creates a gritty unpleasant texture and an overly harsh flavor","Consuming the drink alongside medications or supplements which can reduce their effectiveness significantly","Failing to dissolve the charcoal into a paste first which results in visible clumps floating throughout the finished drink"]','["activated charcoal","black lemonade","detox","dramatic","citrus","wellness","striking"]','["vegan","gluten-free","dairy-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dirty Cherry Sprite','dirty-cherry-sprite','A sweet and fizzy drink combining Sprite with rich coconut cream and bold cherry flavor. This popular Utah-style dirty soda is refreshing and indulgent.','A creamy cherry coconut Sprite drink that is sweet, fizzy, and totally addictive.','American','Easy',5,0,5,1,320,1,68,6,0,'[{"amount":12,"unit":"oz","item":"Sprite soda","group":"Base"},{"amount":2,"unit":"tbsp","item":"coconut cream","group":"Cream"},{"amount":3,"unit":"tbsp","item":"cherry syrup","group":"Flavoring"},{"amount":1,"unit":"tbsp","item":"maraschino cherry juice","group":"Flavoring"},{"amount":2,"unit":"cups","item":"crushed ice","group":"Base"},{"amount":2,"unit":"whole","item":"maraschino cherries","group":"Garnish"},{"amount":1,"unit":"tsp","item":"fresh lime juice","group":"Flavoring"},{"amount":1,"unit":"tbsp","item":"sweetened condensed milk","group":"Cream"}]','[{"title":"Prepare Your Glass","text":"Fill a large cup or mason jar completely with crushed ice. Use plenty of ice to keep the drink cold and slow dilution.","timer":0},{"title":"Add the Cherry Flavor","text":"Pour the cherry syrup and maraschino cherry juice over the ice. Add the fresh lime juice to balance the sweetness.","timer":0},{"title":"Pour the Sprite","text":"Slowly pour the cold Sprite over the ice and syrups. Pour gently along the side of the glass to preserve carbonation.","timer":0},{"title":"Add the Cream","text":"Drizzle the coconut cream and sweetened condensed milk over the top of the drink. Do not stir so the cream floats on top for a layered effect.","timer":0},{"title":"Garnish and Serve","text":"Top with maraschino cherries and serve immediately with a wide straw so each sip pulls through all the layers.","timer":0}]','[{"original":"coconut cream","swap":"heavy whipping cream"},{"original":"cherry syrup","swap":"grenadine syrup"},{"original":"Sprite","swap":"Sierra Mist or 7UP"}]','["Stirring the drink too vigorously and losing all the carbonation","Using warm soda which makes the drink flat and less refreshing","Adding too much coconut cream which overpowers the cherry flavor"]','["dirty soda","cherry","sprite","coconut","cold drink","summer","Utah soda"]','["vegetarian","gluten-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dirty Dr Pepper','dirty-dr-pepper','A creamy and indulgent take on Dr Pepper loaded with coconut cream and vanilla for a dessert-like sip. This dirty soda trend turns a classic cola into something extraordinary.','Creamy coconut and vanilla elevate Dr Pepper into a rich and satisfying dirty soda.','American','Easy',5,0,5,1,340,2,62,9,0,'[{"amount":12,"unit":"oz","item":"Dr Pepper soda","group":"Base"},{"amount":3,"unit":"tbsp","item":"coconut cream","group":"Cream"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"Flavoring"},{"amount":2,"unit":"tbsp","item":"amaretto syrup","group":"Flavoring"},{"amount":2,"unit":"cups","item":"crushed ice","group":"Base"},{"amount":1,"unit":"tbsp","item":"sweetened condensed milk","group":"Cream"},{"amount":2,"unit":"whole","item":"maraschino cherries","group":"Garnish"},{"amount":1,"unit":"pinch","item":"sea salt","group":"Flavoring"}]','[{"title":"Prepare Your Glass","text":"Fill a large cup or mason jar to the top with crushed ice. A cold glass will help keep the soda carbonated longer.","timer":0},{"title":"Add Syrups and Flavor","text":"Pour the amaretto syrup and vanilla extract over the ice. Add a small pinch of sea salt to enhance the sweetness and depth of flavor.","timer":0},{"title":"Pour the Dr Pepper","text":"Slowly pour cold Dr Pepper down the side of the glass. This preserves the bubbles and mixes the syrup gently from the bottom up.","timer":0},{"title":"Add the Cream Layer","text":"Spoon the coconut cream and sweetened condensed milk over the top. Do not mix so the cream slowly sinks through the drink as you sip.","timer":0},{"title":"Finish and Serve","text":"Garnish with maraschino cherries on top and serve right away with a wide straw for the best layered drinking experience.","timer":0}]','[{"original":"coconut cream","swap":"half and half cream"},{"original":"amaretto syrup","swap":"almond extract mixed with simple syrup"},{"original":"Dr Pepper","swap":"Mr Pibb or Cherry Dr Pepper"}]','["Using diet Dr Pepper which reacts poorly with dairy and coconut cream","Skipping the sea salt which is key to rounding out the sweetness","Pouring the soda too fast and causing it to overflow from the carbonation reaction"]','["dirty soda","dr pepper","coconut","vanilla","cold drink","indulgent","Utah soda"]','["vegetarian","gluten-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Raspberry Vanilla Dirty Soda','raspberry-vanilla-dirty-soda','A fruity and creamy dirty soda featuring bright raspberry syrup and smooth vanilla over bubbly lemon-lime soda. This vibrant drink is as beautiful as it is delicious.','Raspberry and vanilla come together over fizzy soda for a dreamy and colorful dirty soda treat.','American','Easy',5,0,5,1,310,1,64,7,1,'[{"amount":12,"unit":"oz","item":"lemon-lime soda","group":"Base"},{"amount":3,"unit":"tbsp","item":"raspberry syrup","group":"Flavoring"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"Flavoring"},{"amount":3,"unit":"tbsp","item":"coconut cream","group":"Cream"},{"amount":2,"unit":"cups","item":"crushed ice","group":"Base"},{"amount":1,"unit":"tbsp","item":"sweetened condensed milk","group":"Cream"},{"amount":5,"unit":"whole","item":"fresh raspberries","group":"Garnish"},{"amount":1,"unit":"tsp","item":"fresh lemon juice","group":"Flavoring"}]','[{"title":"Prepare the Glass","text":"Fill a tall glass or mason jar fully with crushed ice. Pre-chill the glass in the freezer for 5 minutes if you want an extra cold drink.","timer":300},{"title":"Layer the Flavor","text":"Pour the raspberry syrup, vanilla extract, and fresh lemon juice over the ice. The lemon adds brightness and balances the sweet raspberry.","timer":0},{"title":"Add the Soda","text":"Gently pour the lemon-lime soda along the inside edge of the glass. Do not dump it straight down or the carbonation will be lost instantly.","timer":0},{"title":"Create the Cream Top","text":"Mix the coconut cream and sweetened condensed milk together briefly then spoon it slowly over the top of the drink. The cream will create a beautiful white layer.","timer":0},{"title":"Garnish and Enjoy","text":"Place fresh raspberries on top of the cream layer and serve immediately with a wide straw. Drink right away before the ice dilutes the flavors.","timer":0}]','[{"original":"raspberry syrup","swap":"strawberry syrup or mixed berry syrup"},{"original":"coconut cream","swap":"whipped heavy cream"},{"original":"lemon-lime soda","swap":"club soda for a less sweet version"}]','["Using raspberry jam instead of syrup which does not dissolve and creates a gritty texture","Adding the cream before the soda which prevents proper layering","Not using enough ice which causes the drink to become warm and flat quickly"]','["dirty soda","raspberry","vanilla","creamy","fruity","summer drink","cold beverage"]','["vegetarian","gluten-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Coconut Lime Dirty Soda','classic-coconut-lime-dirty-soda','A tropical dirty soda combining zesty lime with rich coconut cream over crisp sparkling water or club soda. Light yet creamy and perfect for warm weather.','Bright lime and rich coconut cream make this refreshing dirty soda a tropical escape in a glass.','American','Easy',5,0,5,1,280,1,52,8,0,'[{"amount":12,"unit":"oz","item":"club soda or sparkling water","group":"Base"},{"amount":3,"unit":"tbsp","item":"coconut cream","group":"Cream"},{"amount":3,"unit":"tbsp","item":"lime simple syrup","group":"Flavoring"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"Flavoring"},{"amount":2,"unit":"cups","item":"crushed ice","group":"Base"},{"amount":1,"unit":"tbsp","item":"sweetened condensed milk","group":"Cream"},{"amount":3,"unit":"slices","item":"fresh lime","group":"Garnish"},{"amount":1,"unit":"pinch","item":"flaky sea salt","group":"Flavoring"}]','[{"title":"Set Up the Glass","text":"Rim a tall glass with a lime wedge and a pinch of flaky sea salt if desired. Fill the glass completely with crushed ice.","timer":0},{"title":"Add Lime Flavor","text":"Pour the lime simple syrup and fresh lime juice over the ice. The combination of syrup and fresh juice gives both sweetness and tartness.","timer":0},{"title":"Pour the Soda","text":"Slowly pour the cold club soda or sparkling water down the side of the glass to keep the bubbles intact. Fill to about an inch from the top.","timer":0},{"title":"Add Coconut Cream","text":"Stir the coconut cream and sweetened condensed milk together until smooth then slowly pour over the back of a spoon onto the surface of the drink.","timer":0},{"title":"Garnish and Serve","text":"Add the fresh lime slices to the rim of the glass and serve immediately. Do not stir the drink so the cream layer stays visible on top.","timer":0}]','[{"original":"lime simple syrup","swap":"plain simple syrup with extra lime juice"},{"original":"club soda","swap":"lemon-lime soda for added sweetness"},{"original":"coconut cream","swap":"canned full-fat coconut milk shaken well"}]','["Using bottled lime juice instead of fresh which results in a flat and artificial flavor","Pouring the coconut cream in too fast so it sinks rather than floats","Forgetting to chill the club soda beforehand which flattens it quickly over the ice"]','["dirty soda","coconut","lime","tropical","refreshing","summer","light drink"]','["vegetarian","vegan","gluten-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Peach Cream Dirty Soda','peach-cream-dirty-soda','A sweet and summery dirty soda bursting with peach flavor and topped with a silky coconut cream layer. Every sip is like biting into a ripe peach dipped in cream.','Juicy peach syrup and velvety coconut cream make this dirty soda taste like summer in a cup.','American','Easy',5,0,5,1,330,1,66,8,0,'[{"amount":12,"unit":"oz","item":"ginger ale or lemon-lime soda","group":"Base"},{"amount":4,"unit":"tbsp","item":"peach syrup","group":"Flavoring"},{"amount":3,"unit":"tbsp","item":"coconut cream","group":"Cream"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"Flavoring"},{"amount":2,"unit":"cups","item":"crushed ice","group":"Base"},{"amount":1,"unit":"tbsp","item":"sweetened condensed milk","group":"Cream"},{"amount":3,"unit":"slices","item":"fresh or canned peach","group":"Garnish"},{"amount":1,"unit":"tsp","item":"fresh lemon juice","group":"Flavoring"}]','[{"title":"Fill and Chill the Glass","text":"Fill a large glass or mason jar to the brim with crushed ice. Use a glass that has been stored in the freezer for best results.","timer":0},{"title":"Add Peach and Vanilla","text":"Pour the peach syrup, vanilla extract, and fresh lemon juice over the ice. Stir gently just at the bottom to combine the flavors.","timer":0},{"title":"Pour the Soda","text":"Tilt the glass slightly and pour the cold ginger ale or lemon-lime soda slowly along the inner wall. This keeps the bubbles alive and prevents overflow.","timer":0},{"title":"Layer the Cream","text":"Whisk together the coconut cream and sweetened condensed milk until well combined. Spoon the mixture over the top of the soda in a slow and steady pour.","timer":0},{"title":"Top and Serve","text":"Arrange sliced peaches on top of the cream and serve immediately with a wide straw. Do not stir before serving to preserve the beautiful layers.","timer":0}]','[{"original":"peach syrup","swap":"apricot syrup or mango syrup"},{"original":"ginger ale","swap":"Sprite or plain sparkling water"},{"original":"coconut cream","swap":"vanilla ice cream blended until pourable"}]','["Using peach nectar instead of syrup which is too thin and does not provide enough flavor","Over-pouring the cream which makes the drink too heavy and overly sweet","Letting the drink sit too long before drinking which causes the layers to fully combine and go flat"]','["dirty soda","peach","cream","vanilla","summer","fruity","sweet drink"]','["vegetarian","gluten-free"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Brazilian Mint Lemonade','brazilian-mint-lemonade','A creamy and refreshing Brazilian drink made with whole limes, sweetened condensed milk, and fresh mint. This blended lemonade is rich, frothy, and unlike any lemonade you have tried before.','Creamy blended Brazilian lemonade with sweetened condensed milk and fresh mint.','Brazilian','Easy',10,0,10,4,180,3,28,6,1,'[{"amount":4,"unit":"whole","item":"limes","group":"main"},{"amount":3,"unit":"cups","item":"cold water","group":"main"},{"amount":0.33,"unit":"cup","item":"sweetened condensed milk","group":"main"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"main"},{"amount":10,"unit":"leaves","item":"fresh mint","group":"main"},{"amount":2,"unit":"cups","item":"ice cubes","group":"main"},{"amount":0.25,"unit":"teaspoon","item":"fine sea salt","group":"seasoning"},{"amount":1,"unit":"tablespoon","item":"cream cheese","group":"main"}]','[{"title":"Prep the Limes","text":"Wash the limes thoroughly. Cut off both ends of each lime and cut each lime into quarters. Do not peel the limes as the rind adds flavor, but remove any visible seeds to prevent bitterness.","timer":0},{"title":"Blend the Base","text":"Add the lime quarters, cold water, sweetened condensed milk, cream cheese, sugar, and salt into a blender. Blend on high speed for exactly 5 seconds. Do not over-blend or the drink will become very bitter from the lime rind.","timer":5},{"title":"Strain the Mixture","text":"Pour the blended mixture through a fine mesh strainer into a large pitcher, pressing gently with a spoon to extract all the liquid. Discard the solids left in the strainer.","timer":0},{"title":"Add Mint and Ice","text":"Add the fresh mint leaves to the pitcher and stir gently. Fill serving glasses with ice cubes and pour the lemonade over the ice.","timer":0},{"title":"Serve Immediately","text":"Garnish each glass with a sprig of fresh mint and a lime wheel. Serve right away as the drink loses its frothy texture and may become bitter if it sits too long.","timer":0}]','[{"original":"sweetened condensed milk","swap":"coconut condensed milk for a dairy-free version"},{"original":"cream cheese","swap":"full-fat coconut cream for a vegan option"},{"original":"granulated sugar","swap":"simple syrup or honey to taste"}]','["Blending for too long which releases bitter compounds from the lime rind","Using warm water which prevents the drink from being refreshing and frothy","Skipping the straining step which leaves pulp and makes the texture unpleasant"]','["refreshing","creamy","blended","summer","citrus","Brazilian"]','["vegetarian","gluten-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hibiscus Agua Fresca','hibiscus-agua-fresca','A vibrant deep-red Mexican agua fresca made from dried hibiscus flowers, lime juice, and a touch of sweetness. This refreshing drink is tart, floral, and incredibly easy to make.','Tart and floral hibiscus agua fresca sweetened with sugar and brightened with fresh lime.','Mexican','Easy',5,15,20,6,70,0,18,0,0,'[{"amount":1,"unit":"cup","item":"dried hibiscus flowers","group":"main"},{"amount":8,"unit":"cups","item":"water","group":"main"},{"amount":0.75,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":3,"unit":"tablespoons","item":"fresh lime juice","group":"main"},{"amount":1,"unit":"teaspoon","item":"lime zest","group":"main"},{"amount":0.25,"unit":"teaspoon","item":"ground cinnamon","group":"seasoning"},{"amount":1,"unit":"inch","item":"fresh ginger peeled and sliced","group":"seasoning"},{"amount":3,"unit":"cups","item":"ice cubes","group":"serving"}]','[{"title":"Steep the Hibiscus","text":"Combine the dried hibiscus flowers, ginger slices, cinnamon, and 4 cups of water in a medium saucepan. Bring to a boil over medium-high heat, then reduce heat and simmer for 10 minutes until the liquid turns deep red and fragrant.","timer":600},{"title":"Sweeten the Concentrate","text":"Remove the pan from heat and stir in the granulated sugar until fully dissolved. The residual heat will dissolve the sugar without additional cooking. Do not add sugar while still boiling as it can make the flavor harsh.","timer":0},{"title":"Strain and Cool","text":"Pour the hibiscus concentrate through a fine mesh strainer into a large pitcher, pressing the flowers gently to extract all liquid. Discard the spent flowers and ginger. Allow the concentrate to cool for 15 minutes.","timer":900},{"title":"Dilute and Add Citrus","text":"Add the remaining 4 cups of cold water to the pitcher along with the fresh lime juice and lime zest. Stir well to combine. Taste and adjust sweetness or tartness as needed.","timer":0},{"title":"Serve Over Ice","text":"Fill tall glasses with ice and pour the hibiscus agua fresca over the top. Garnish with a lime wheel and a few fresh hibiscus flowers if available. Serve immediately or refrigerate for up to 3 days.","timer":0}]','[{"original":"granulated sugar","swap":"agave nectar for a lower glycemic option"},{"original":"fresh ginger","swap":"0.25 teaspoon ground ginger in a pinch"},{"original":"lime juice","swap":"lemon juice for a slightly different citrus note"}]','["Boiling the hibiscus for too long which can make the drink overly bitter and astringent","Not straining thoroughly which leaves plant material that affects texture","Adding too little water to the concentrate resulting in an overpoweringly tart drink"]','["floral","tart","refreshing","summer","Mexican","agua fresca","hibiscus"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Non-Alcoholic Horchata','non-alcoholic-horchata','A traditional Mexican rice-based drink infused with cinnamon and vanilla for a creamy, naturally sweet flavor. This classic agua fresca is smooth, lightly spiced, and perfect for any occasion.','Creamy cinnamon rice drink that is sweet, smooth, and completely alcohol-free.','Mexican','Medium',15,0,495,6,160,2,32,3,0,'[{"amount":1,"unit":"cup","item":"long grain white rice uncooked","group":"main"},{"amount":4,"unit":"cups","item":"water for soaking","group":"main"},{"amount":4,"unit":"cups","item":"cold water for blending","group":"main"},{"amount":2,"unit":"sticks","item":"cinnamon","group":"spice"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":1,"unit":"teaspoon","item":"pure vanilla extract","group":"flavoring"},{"amount":0.5,"unit":"cup","item":"whole milk","group":"main"},{"amount":0.25,"unit":"teaspoon","item":"ground cinnamon for garnish","group":"garnish"}]','[{"title":"Soak Rice and Cinnamon","text":"Rinse the white rice under cold water until the water runs clear. Place the rinsed rice and cinnamon sticks in a large bowl and cover with 4 cups of water. Let the mixture soak at room temperature for a minimum of 8 hours or overnight for best results.","timer":28800},{"title":"Blend the Soaked Rice","text":"Transfer the soaked rice, cinnamon sticks, and all the soaking liquid into a blender. Blend on high speed for 2 full minutes until the mixture is as smooth as possible and the rice is completely broken down.","timer":120},{"title":"Strain Thoroughly","text":"Line a fine mesh strainer with a double layer of cheesecloth and set it over a large pitcher. Pour the blended rice mixture through the cheesecloth in batches, squeezing firmly to extract as much liquid as possible. Discard the rice solids.","timer":0},{"title":"Season the Horchata","text":"Add the remaining 4 cups of cold water, granulated sugar, vanilla extract, and whole milk to the strained liquid. Stir vigorously until the sugar is fully dissolved. Taste and adjust sweetness if needed.","timer":0},{"title":"Chill and Serve","text":"Refrigerate the horchata for at least 30 minutes before serving. Stir well before pouring over ice-filled glasses as the drink separates naturally. Dust each glass with a pinch of ground cinnamon before serving.","timer":1800}]','[{"original":"whole milk","swap":"almond milk or oat milk for a dairy-free version"},{"original":"white rice","swap":"blanched almonds for a nuttier traditional style"},{"original":"granulated sugar","swap":"maple syrup or agave for a different sweetness profile"}]','["Not soaking the rice long enough which results in a gritty texture that is difficult to strain","Skipping the cheesecloth and using only a strainer which leaves too much starch and grit in the final drink","Not stirring before serving which causes the starch to settle and makes the drink uneven in flavor"]','["creamy","cinnamon","rice drink","Mexican","traditional","refreshing","horchata"]','["vegetarian","gluten-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sparkling Watermelon Agua Fresca','sparkling-watermelon-agua-fresca','A bright and juicy watermelon agua fresca lifted with fresh lime juice and topped with sparkling water for a festive fizz. This effortless summer drink comes together in minutes and needs no cooking.','Fresh watermelon blended with lime and topped with sparkling water for a light fizzy drink.','Mexican','Easy',10,0,10,6,65,1,16,0,1,'[{"amount":8,"unit":"cups","item":"seedless watermelon cubed","group":"main"},{"amount":3,"unit":"tablespoons","item":"fresh lime juice","group":"main"},{"amount":1,"unit":"teaspoon","item":"lime zest","group":"main"},{"amount":2,"unit":"tablespoons","item":"granulated sugar","group":"sweetener"},{"amount":0.25,"unit":"teaspoon","item":"fine sea salt","group":"seasoning"},{"amount":2,"unit":"cups","item":"sparkling water","group":"main"},{"amount":0.25,"unit":"cup","item":"fresh mint leaves","group":"garnish"},{"amount":3,"unit":"cups","item":"ice cubes","group":"serving"}]','[{"title":"Blend the Watermelon","text":"Add the cubed watermelon to a blender in batches and blend until completely smooth. Do not add any water as fresh watermelon contains enough liquid on its own.","timer":0},{"title":"Strain for Smoothness","text":"Pour the blended watermelon through a fine mesh strainer into a large pitcher, pressing with a spoon to extract all juice. Discard the fibrous pulp left behind.","timer":0},{"title":"Season and Sweeten","text":"Stir in the fresh lime juice, lime zest, granulated sugar, and sea salt. Stir until the sugar is fully dissolved. Taste the mixture and adjust sweetness or tartness according to your preference.","timer":0},{"title":"Chill the Base","text":"Refrigerate the watermelon base for at least 20 minutes until very cold. Do not add the sparkling water yet as it will lose carbonation if added too early.","timer":1200},{"title":"Top and Serve","text":"Fill glasses with ice and pour the chilled watermelon base about three-quarters full. Top each glass with sparkling water and gently stir once. Garnish with fresh mint leaves and a lime wedge.","timer":0}]','[{"original":"sparkling water","swap":"plain cold water if you prefer a still version"},{"original":"granulated sugar","swap":"honey or agave syrup for natural sweetness"},{"original":"fresh mint","swap":"fresh basil for a more unexpected herbal note"}]','["Adding sparkling water too early and losing all the carbonation before serving","Not straining the blended watermelon which leaves a pulpy unpleasant texture","Using warm or room temperature watermelon which makes the drink taste flat and less refreshing"]','["watermelon","sparkling","refreshing","summer","Mexican","agua fresca","easy"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cucumber Lime Agua Fresca','cucumber-lime-agua-fresca','A cool and ultra-hydrating agua fresca made with fresh cucumber, bright lime juice, and a hint of jalapeño for a mild kick. This clean and elegant drink is perfect for hot days and pairs well with any meal.','Refreshing cucumber and lime agua fresca with a subtle spicy kick from fresh jalapeño.','Mexican','Easy',10,0,40,4,45,1,11,0,1,'[{"amount":2,"unit":"large","item":"English cucumbers peeled and chopped","group":"main"},{"amount":4,"unit":"cups","item":"cold water","group":"main"},{"amount":0.33,"unit":"cup","item":"fresh lime juice","group":"main"},{"amount":1,"unit":"teaspoon","item":"lime zest","group":"main"},{"amount":3,"unit":"tablespoons","item":"granulated sugar","group":"sweetener"},{"amount":0.5,"unit":"whole","item":"jalapeño seeded and sliced","group":"seasoning"},{"amount":0.25,"unit":"teaspoon","item":"fine sea salt","group":"seasoning"},{"amount":0.25,"unit":"cup","item":"fresh cilantro leaves","group":"garnish"}]','[{"title":"Blend Cucumber and Water","text":"Add the chopped cucumber, jalapeño slices, and 2 cups of the cold water to a blender. Blend on high for about 60 seconds until completely smooth and no large chunks remain.","timer":60},{"title":"Strain the Mixture","text":"Pour the blended cucumber mixture through a fine mesh strainer into a large pitcher. Press firmly with a spoon to extract as much liquid as possible. Discard the solids.","timer":0},{"title":"Build the Drink","text":"Add the remaining 2 cups of cold water, fresh lime juice, lime zest, granulated sugar, and sea salt to the pitcher. Stir well until the sugar is completely dissolved.","timer":0},{"title":"Chill Before Serving","text":"Refrigerate the agua fresca for at least 30 minutes to allow the flavors to meld and the drink to become thoroughly cold. Do not skip this step as the flavor improves significantly with resting time.","timer":1800},{"title":"Garnish and Serve","text":"Stir the pitcher well before serving. Pour over ice-filled glasses and garnish each with a thin cucumber ribbon, a lime wheel, and a few fresh cilantro leaves.","timer":0}]','[{"original":"jalapeño","swap":"a pinch of cayenne pepper for consistent heat without seeds"},{"original":"cilantro","swap":"fresh mint for a cooler herbal finish"},{"original":"granulated sugar","swap":"agave nectar stirred in to taste"}]','["Not straining the cucumber pulp which makes the drink cloudy and grainy in texture","Adding too much jalapeño which overwhelms the delicate cucumber flavor","Serving immediately without chilling which prevents the flavors from blending properly"]','["cucumber","lime","spicy","refreshing","summer","Mexican","agua fresca","hydrating"]','["vegan","gluten-free","dairy-free"]','Beverages','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pistachio Cream Cold Foam Latte','pistachio-cream-cold-foam-latte','A rich espresso latte topped with velvety pistachio cream cold foam that melts into the coffee below. This cafe-style drink is easy to make at home with just a few ingredients.','Creamy pistachio cold foam floats over smooth iced espresso for a nutty indulgent latte.','American','Easy',10,5,15,1,280,6,28,16,1,'[{"amount":2,"unit":"shots","item":"espresso","group":"base"},{"amount":1,"unit":"cup","item":"oat milk","group":"base"},{"amount":2,"unit":"tbsp","item":"pistachio paste or pistachio butter","group":"foam"},{"amount":3,"unit":"tbsp","item":"heavy cream","group":"foam"},{"amount":2,"unit":"tbsp","item":"whole milk","group":"foam"},{"amount":1,"unit":"tbsp","item":"powdered sugar","group":"foam"},{"amount":1,"unit":"cup","item":"ice","group":"base"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"foam"},{"amount":1,"unit":"pinch","item":"sea salt","group":"foam"}]','[{"title":"Brew the Espresso","text":"Brew 2 shots of espresso using your espresso machine or moka pot. Let the espresso cool for 2 minutes at room temperature so it does not melt all the ice immediately.","timer":120},{"title":"Prepare the Pistachio Cold Foam","text":"In a small bowl or jar combine the heavy cream, whole milk, pistachio paste, powdered sugar, vanilla extract, and a pinch of sea salt. Use a handheld milk frother and froth for 30 to 45 seconds until thick and foamy but still pourable.","timer":45},{"title":"Build the Latte Base","text":"Fill a tall glass with ice. Pour the oat milk over the ice first, then slowly pour the cooled espresso shots over the back of a spoon to create a layered effect.","timer":30},{"title":"Add the Cold Foam","text":"Spoon or pour the pistachio cold foam generously over the top of the latte. The foam should sit on top of the milk and espresso layer and slowly drift down as you drink.","timer":15},{"title":"Garnish and Serve","text":"Finish with a light dusting of crushed pistachios or a pinch of sea salt on top of the foam. Serve immediately with a wide straw so you can enjoy the foam and latte together.","timer":0}]','[{"original":"heavy cream","swap":"coconut cream for a dairy free version"},{"original":"oat milk","swap":"almond milk or whole milk"},{"original":"pistachio paste","swap":"pistachio flavored syrup combined with 1 tsp of nut butter"}]','["Using hot espresso directly on the ice which melts everything and dilutes the drink","Over-frothing the cold foam so it becomes too stiff and does not pour smoothly over the latte","Adding too much pistachio paste which can make the foam too heavy and cause it to sink"]','["cold brew","espresso","pistachio","cold foam","iced latte","summer drink","cafe style"]','["vegetarian"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Hojicha Soft Serve','hojicha-soft-serve','This hojicha soft serve delivers a toasty roasted tea flavor wrapped in a smooth creamy frozen base. It captures the cozy warmth of Japanese hojicha in a cool refreshing dessert.','Silky roasted hojicha ice cream churned into a soft swirl with deep caramel tea notes.','Japanese','Medium',20,15,35,4,310,5,30,19,0,'[{"amount":2,"unit":"cups","item":"heavy cream","group":"base"},{"amount":1,"unit":"cup","item":"whole milk","group":"base"},{"amount":3,"unit":"tbsp","item":"hojicha powder","group":"flavoring"},{"amount":0.5,"unit":"cup","item":"granulated sugar","group":"base"},{"amount":4,"unit":"large","item":"egg yolks","group":"base"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"flavoring"},{"amount":1,"unit":"pinch","item":"sea salt","group":"flavoring"},{"amount":2,"unit":"tbsp","item":"sweetened condensed milk","group":"base"}]','[{"title":"Make the Hojicha Custard Base","text":"In a medium saucepan warm the heavy cream and whole milk over medium heat until just steaming. Whisk in the hojicha powder until fully dissolved with no lumps. Remove from heat.","timer":300},{"title":"Temper the Egg Yolks","text":"In a bowl whisk egg yolks and sugar together until pale and thick. Slowly pour a ladleful of the warm hojicha cream into the yolks while whisking constantly to temper them. Pour the tempered yolk mixture back into the saucepan.","timer":120},{"title":"Cook the Custard","text":"Return the saucepan to medium-low heat and stir constantly with a wooden spoon until the custard thickens enough to coat the back of the spoon, about 8 minutes. Do not let it boil. Stir in vanilla, salt, and condensed milk. Strain through a fine mesh sieve.","timer":480},{"title":"Chill and Churn","text":"Let the custard cool to room temperature then refrigerate for at least 4 hours or overnight. Churn in an ice cream maker according to manufacturer instructions until it reaches a soft serve consistency, about 20 to 25 minutes.","timer":1500},{"title":"Serve Immediately","text":"Transfer the soft serve to a piping bag fitted with a large star tip and pipe into cones or cups in a swirling motion. Dust with a little extra hojicha powder and serve right away for best texture.","timer":0}]','[{"original":"hojicha powder","swap":"matcha powder for a classic green tea soft serve"},{"original":"heavy cream","swap":"full fat coconut cream for a dairy free option"},{"original":"egg yolks","swap":"2 tbsp of cornstarch dissolved in milk for an egg free custard"}]','["Boiling the custard which causes the eggs to scramble and creates a grainy texture","Skipping the chilling step which leads to ice crystals and a coarse texture when churned","Using brewed hojicha tea instead of powder which results in a watery base that does not freeze properly"]','["hojicha","soft serve","Japanese dessert","ice cream","tea dessert","summer","frozen treat"]','["vegetarian","gluten-free"]','Desserts','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Blueberry Matcha Latte','blueberry-matcha-latte','This vibrant blueberry matcha latte layers earthy green tea with a sweet jammy blueberry compote for a stunning two-tone drink. It is as beautiful to look at as it is refreshing to drink.','Earthy ceremonial matcha meets a vivid blueberry syrup in a creamy layered iced latte.','Japanese-American','Easy',10,10,20,1,210,4,32,7,2,'[{"amount":1.5,"unit":"tsp","item":"ceremonial grade matcha powder","group":"matcha"},{"amount":3,"unit":"tbsp","item":"hot water at 175 degrees F","group":"matcha"},{"amount":1,"unit":"cup","item":"oat milk","group":"base"},{"amount":0.5,"unit":"cup","item":"fresh or frozen blueberries","group":"syrup"},{"amount":2,"unit":"tbsp","item":"granulated sugar","group":"syrup"},{"amount":2,"unit":"tbsp","item":"water","group":"syrup"},{"amount":1,"unit":"tsp","item":"lemon juice","group":"syrup"},{"amount":1,"unit":"cup","item":"ice","group":"base"}]','[{"title":"Make the Blueberry Syrup","text":"In a small saucepan combine blueberries, sugar, water, and lemon juice. Cook over medium heat for 8 to 10 minutes stirring occasionally until the blueberries burst and the syrup thickens. Strain through a sieve and let it cool completely.","timer":600},{"title":"Whisk the Matcha","text":"Sift the matcha powder into a small bowl or mug. Add 3 tablespoons of hot water at 175 degrees F and whisk in a rapid W or M motion for 30 seconds until the matcha is fully dissolved and lightly frothy with no clumps.","timer":30},{"title":"Build the Layered Drink","text":"Spoon 2 to 3 tablespoons of the cooled blueberry syrup into the bottom of a tall glass. Fill the glass with ice, then slowly pour the oat milk over the ice so it sits on top of the blueberry layer.","timer":20},{"title":"Add the Matcha Layer","text":"Very slowly pour the whisked matcha over the back of a spoon so it floats gently on top of the oat milk layer. This creates a beautiful three-tone gradient of purple, white, and green.","timer":20},{"title":"Serve and Stir","text":"Garnish with a few fresh blueberries on top and serve immediately. Stir the drink together before sipping to blend all the flavors or enjoy each sip as the layers naturally combine.","timer":0}]','[{"original":"oat milk","swap":"coconut milk for a richer tropical flavor"},{"original":"fresh blueberries","swap":"blueberry jam thinned with a little water"},{"original":"ceremonial matcha","swap":"culinary matcha which has a stronger flavor and lower cost"}]','["Using boiling water to whisk matcha which burns the powder and creates a bitter bitter flavor","Pouring the matcha too fast which breaks the layers and turns the drink murky green","Skipping the straining step for the blueberry syrup which leaves seeds and pulp in the drink"]','["matcha","blueberry","iced latte","layered drink","summer","cafe style","antioxidants"]','["vegan","dairy-free","gluten-free","vegetarian"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Iced Brown Sugar Oat Milk Shaken Espresso','iced-brown-sugar-oat-milk-shaken-espresso','This copycat cafe classic combines bold espresso shaken with cinnamon brown sugar syrup and topped with creamy oat milk. Shaking the espresso aerates it into a light frothy base that is deeply satisfying.','Shaken espresso with warm brown sugar and cinnamon topped with cold oat milk over ice.','American','Easy',8,5,13,1,190,3,29,5,1,'[{"amount":3,"unit":"shots","item":"espresso","group":"base"},{"amount":3,"unit":"tbsp","item":"brown sugar","group":"syrup"},{"amount":3,"unit":"tbsp","item":"water","group":"syrup"},{"amount":0.5,"unit":"tsp","item":"ground cinnamon","group":"syrup"},{"amount":1,"unit":"cup","item":"oat milk","group":"base"},{"amount":1.5,"unit":"cups","item":"ice","group":"base"},{"amount":1,"unit":"pinch","item":"flaky sea salt","group":"garnish"},{"amount":0.25,"unit":"tsp","item":"vanilla extract","group":"syrup"}]','[{"title":"Make the Brown Sugar Cinnamon Syrup","text":"Combine brown sugar, water, ground cinnamon, and vanilla extract in a small saucepan over medium heat. Stir until the sugar fully dissolves, about 3 to 4 minutes. Remove from heat and let cool for 5 minutes.","timer":240},{"title":"Brew the Espresso","text":"Brew 3 shots of espresso. Pour the hot espresso directly into a cocktail shaker or mason jar with a lid while it is still hot so it absorbs the flavors of the syrup when combined.","timer":120},{"title":"Shake the Espresso","text":"Add the brown sugar cinnamon syrup and a generous handful of ice to the shaker with the espresso. Seal tightly and shake vigorously for 15 to 20 seconds until the outside of the shaker feels very cold and the mixture is frothy.","timer":20},{"title":"Build the Drink","text":"Fill a tall glass with fresh ice. Strain the shaken espresso mixture over the ice in the glass. The espresso should look frothy and slightly aerated from the shaking process.","timer":15},{"title":"Top and Garnish","text":"Pour the cold oat milk gently over the shaken espresso to fill the glass. Finish with a pinch of flaky sea salt and a dusting of ground cinnamon on top. Serve immediately without stirring for the best visual effect.","timer":0}]','[{"original":"oat milk","swap":"almond milk for a nuttier lighter finish"},{"original":"brown sugar","swap":"coconut sugar for a deeper caramel flavor"},{"original":"espresso shots","swap":"2 cups of strong cold brew concentrate"}]','["Not shaking long enough which results in a flat drink without the signature frothy top","Adding oat milk before straining the espresso which breaks the layered visual effect","Using too little ice in the shaker so the espresso does not chill and dilute to the right strength"]','["espresso","brown sugar","oat milk","shaken espresso","iced coffee","cinnamon","cafe copycat"]','["vegan","dairy-free","vegetarian"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Strawberry Basil Agua Fresca','strawberry-basil-agua-fresca','This refreshing strawberry basil agua fresca blends sweet ripe strawberries with fragrant fresh basil and a squeeze of lime. It is a light naturally sweetened drink perfect for warm weather gatherings.','Bright fresh strawberry water infused with basil and lime for an effortless summer drink.','Mexican','Easy',15,0,15,4,85,1,20,0,2,'[{"amount":4,"unit":"cups","item":"fresh strawberries, hulled and halved","group":"base"},{"amount":4,"unit":"cups","item":"cold water","group":"base"},{"amount":3,"unit":"tbsp","item":"granulated sugar or to taste","group":"sweetener"},{"amount":2,"unit":"tbsp","item":"fresh lime juice","group":"flavoring"},{"amount":10,"unit":"large","item":"fresh basil leaves","group":"flavoring"},{"amount":1,"unit":"tsp","item":"lime zest","group":"flavoring"},{"amount":2,"unit":"cups","item":"ice","group":"serving"},{"amount":1,"unit":"pinch","item":"sea salt","group":"flavoring"}]','[{"title":"Blend the Strawberries","text":"Place the hulled strawberries, sugar, lime juice, lime zest, sea salt, and 2 cups of the cold water into a blender. Blend on high speed for 45 seconds until completely smooth and the mixture looks vibrant and silky.","timer":45},{"title":"Infuse with Basil","text":"Add the fresh basil leaves to the blender and pulse 3 to 4 times briefly. Do not over-blend the basil or the drink will taste bitter and turn an unpleasant dark color. You want just a gentle green floral infusion.","timer":10},{"title":"Strain the Mixture","text":"Pour the blended mixture through a fine mesh sieve or cheesecloth into a large pitcher, pressing gently with a spoon to extract all the juice. Discard the seeds and pulp left in the sieve.","timer":120},{"title":"Dilute and Taste","text":"Stir in the remaining 2 cups of cold water into the strained juice. Taste and adjust sweetness by adding more sugar if needed or a little more lime juice for brightness. Stir until any added sugar dissolves.","timer":30},{"title":"Serve Over Ice","text":"Fill glasses generously with ice and pour the agua fresca over the top. Garnish each glass with a small fresh basil leaf and a thin slice of lime on the rim. Serve immediately or refrigerate for up to 2 days.","timer":0}]','[{"original":"fresh strawberries","swap":"frozen strawberries thawed at room temperature for 30 minutes"},{"original":"granulated sugar","swap":"honey or agave nectar for a natural sweetener"},{"original":"fresh basil","swap":"fresh mint for a cooler more classic agua fresca flavor"}]','["Over-blending the basil leaves which makes the drink taste bitter and look muddy green","Skipping the straining step which leaves seeds in the drink and creates an unpleasant texture","Not tasting before serving which can result in a drink that is too tart or not sweet enough"]','["strawberry","basil","agua fresca","summer drink","non-alcoholic","Mexican","refreshing","fruit drink"]','["vegan","dairy-free","gluten-free","vegetarian"]','Drinks','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dubai Chocolate Lava Cake','dubai-chocolate-lava-cake','A rich molten chocolate cake infused with tahini and topped with crushed kataifi pastry for a luxurious Dubai-inspired twist. The gooey center melts into a silky chocolate river with every bite.','Decadent molten chocolate lava cakes with a tahini core and crispy kataifi topping inspired by the viral Dubai chocolate trend.','Middle Eastern Fusion','Medium',20,12,32,4,520,8,48,34,3,'[{"amount":150,"unit":"g","item":"dark chocolate 70 percent","group":"batter"},{"amount":100,"unit":"g","item":"unsalted butter","group":"batter"},{"amount":2,"unit":"whole","item":"large eggs","group":"batter"},{"amount":2,"unit":"whole","item":"egg yolks","group":"batter"},{"amount":80,"unit":"g","item":"powdered sugar","group":"batter"},{"amount":40,"unit":"g","item":"all-purpose flour","group":"batter"},{"amount":60,"unit":"g","item":"tahini","group":"filling"},{"amount":80,"unit":"g","item":"kataifi pastry shredded","group":"topping"},{"amount":30,"unit":"g","item":"unsalted butter melted","group":"topping"},{"amount":2,"unit":"tbsp","item":"pistachio cream","group":"topping"}]','[{"title":"Prepare the Kataifi Topping","text":"Preheat oven to 200C. Toss shredded kataifi pastry with melted butter in a pan over medium heat. Stir constantly for 4 to 5 minutes until golden and crispy. Remove from heat and stir in pistachio cream. Set aside to cool.","timer":300},{"title":"Melt Chocolate and Butter","text":"Combine dark chocolate and unsalted butter in a heatproof bowl. Microwave in 30-second intervals stirring between each until fully melted and smooth. Allow to cool for 5 minutes before proceeding.","timer":120},{"title":"Make the Batter","text":"Whisk eggs, egg yolks, and powdered sugar together vigorously until pale and slightly thickened. Pour in the cooled chocolate mixture and fold gently. Sift in flour and fold until just combined. Do not overmix the batter.","timer":180},{"title":"Fill and Layer the Ramekins","text":"Grease 4 ramekins with butter and dust with cocoa powder. Fill each halfway with batter. Add a small spoonful of tahini in the center of each. Cover with remaining batter filling to about three quarters full.","timer":120},{"title":"Bake and Serve","text":"Bake at 200C for 10 to 12 minutes until the edges are set but the center still has a slight jiggle. Run a knife around the edges and invert onto plates immediately. Top with the crispy kataifi mixture and serve at once.","timer":720}]','[{"original":"tahini","swap":"smooth almond butter for a nuttier mild flavor"},{"original":"kataifi pastry","swap":"crushed shredded wheat biscuits toasted in butter"},{"original":"dark chocolate 70 percent","swap":"semi-sweet chocolate chips for a sweeter result"}]','["Overbaking the cakes which causes the center to set completely and eliminates the lava effect","Skipping the ramekin greasing and cocoa dusting which causes the cakes to stick and break when inverted","Adding tahini that is too cold which sinks unevenly and does not create a clean molten center"]','["chocolate","lava cake","Dubai","molten","dessert","Middle Eastern","pistachio","kataifi"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Pistachio Kunafa Croissant','pistachio-kunafa-croissant','A flaky buttery croissant stuffed with creamy pistachio filling and crispy kunafa pastry soaked in rose water syrup. This viral fusion pastry brings together French and Levantine baking traditions.','Buttery croissants filled with pistachio cream and crunchy kunafa pastry drizzled with fragrant rose water syrup.','Middle Eastern Fusion','Medium',25,20,45,4,610,11,58,39,4,'[{"amount":4,"unit":"whole","item":"large butter croissants store-bought or homemade","group":"base"},{"amount":120,"unit":"g","item":"kataifi shredded pastry","group":"kunafa layer"},{"amount":50,"unit":"g","item":"unsalted butter melted","group":"kunafa layer"},{"amount":200,"unit":"g","item":"pistachio cream","group":"filling"},{"amount":100,"unit":"g","item":"cream cheese softened","group":"filling"},{"amount":3,"unit":"tbsp","item":"powdered sugar","group":"filling"},{"amount":60,"unit":"ml","item":"water","group":"syrup"},{"amount":60,"unit":"g","item":"granulated sugar","group":"syrup"},{"amount":1,"unit":"tsp","item":"rose water","group":"syrup"},{"amount":2,"unit":"tbsp","item":"crushed pistachios","group":"garnish"}]','[{"title":"Prepare the Rose Water Syrup","text":"Combine water and granulated sugar in a small saucepan over medium heat. Stir until sugar dissolves completely then bring to a gentle simmer for 3 minutes. Remove from heat and stir in rose water. Allow to cool completely before using.","timer":300},{"title":"Toast the Kataifi Pastry","text":"Toss kataifi shredded pastry with melted butter in a non-stick pan over medium heat. Cook stirring frequently for 5 to 6 minutes until evenly golden and crispy. Transfer to a plate and let it cool fully before mixing into the filling.","timer":360},{"title":"Make the Pistachio Filling","text":"Beat cream cheese and powdered sugar together until smooth and fluffy. Add pistachio cream and mix until fully incorporated. Fold in two thirds of the cooled toasted kataifi pastry reserving the rest for topping. Chill for 10 minutes.","timer":180},{"title":"Fill the Croissants","text":"Using a serrated knife slice each croissant horizontally without cutting all the way through. Pipe or spoon a generous amount of the pistachio kataifi filling into each croissant. Press gently to close and do not overfill to prevent spilling during baking.","timer":300},{"title":"Bake and Finish","text":"Place filled croissants on a lined baking sheet and bake at 180C for 8 to 10 minutes until warmed through and slightly crisped on the outside. Drizzle with rose water syrup immediately after baking. Top with remaining kataifi and crushed pistachios before serving.","timer":600}]','[{"original":"pistachio cream","swap":"store-bought Lotus Biscoff spread mixed with ground pistachios"},{"original":"rose water","swap":"orange blossom water for a citrus floral note"},{"original":"cream cheese","swap":"mascarpone for a richer creamier texture"}]','["Using warm kataifi pastry in the filling which makes it soggy instead of staying crispy","Overfilling the croissants causing the filling to leak out and burn on the baking sheet","Adding rose water syrup before baking instead of after which softens the croissant exterior too much"]','["croissant","pistachio","kunafa","Dubai","fusion","pastry","rose water","viral"]','["vegetarian"]','Pastry','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dubai Chocolate Cheesecake Bars','dubai-chocolate-cheesecake-bars','Creamy no-bake cheesecake bars layered with crunchy kataifi pastry and rich pistachio cream encased in a Dubai-style chocolate shell. Each bar delivers a satisfying contrast of textures and bold flavors.','No-bake cheesecake bars with a pistachio kataifi center coated in glossy Dubai chocolate inspired by the iconic viral candy bar.','Middle Eastern Fusion','Easy',30,0,30,8,480,7,42,32,3,'[{"amount":200,"unit":"g","item":"digestive biscuits crushed","group":"crust"},{"amount":80,"unit":"g","item":"unsalted butter melted","group":"crust"},{"amount":300,"unit":"g","item":"cream cheese softened","group":"cheesecake layer"},{"amount":60,"unit":"g","item":"powdered sugar","group":"cheesecake layer"},{"amount":100,"unit":"g","item":"pistachio cream","group":"cheesecake layer"},{"amount":100,"unit":"g","item":"kataifi pastry toasted","group":"crunch layer"},{"amount":250,"unit":"g","item":"dark chocolate 70 percent chopped","group":"coating"},{"amount":30,"unit":"g","item":"coconut oil","group":"coating"},{"amount":3,"unit":"tbsp","item":"crushed pistachios","group":"garnish"},{"amount":1,"unit":"tsp","item":"flaky sea salt","group":"garnish"}]','[{"title":"Make the Biscuit Crust","text":"Combine crushed digestive biscuits with melted butter and mix until the texture resembles wet sand. Press firmly and evenly into the base of a parchment-lined 8x8 inch pan. Refrigerate for 20 minutes to firm up while you prepare the other layers.","timer":1200},{"title":"Toast the Kataifi","text":"Cook kataifi pastry with a small amount of butter in a pan over medium heat stirring constantly for 5 minutes until golden and crispy. Remove from heat and let it cool completely on a plate. Do not allow it to cool in the pan as residual heat will over-toast it.","timer":300},{"title":"Prepare the Cheesecake Layer","text":"Beat cream cheese and powdered sugar together until smooth with no lumps. Add pistachio cream and mix until well combined and creamy. Fold in the cooled toasted kataifi pastry gently to preserve its crunch. Spread evenly over the chilled biscuit crust.","timer":240},{"title":"Chill Until Set","text":"Freeze the pan for at least 2 hours or refrigerate overnight until the cheesecake layer is fully set and firm enough to slice cleanly. Once set lift out using the parchment paper and cut into 8 equal bars using a hot sharp knife.","timer":7200},{"title":"Coat in Chocolate and Serve","text":"Melt dark chocolate with coconut oil in a heatproof bowl until smooth and glossy. Dip each bar halfway into the chocolate or drizzle over the top. Place on a wire rack and immediately sprinkle with crushed pistachios and flaky sea salt. Refrigerate for 15 minutes to set the coating.","timer":900}]','[{"original":"digestive biscuits","swap":"graham crackers or Oreo cookies with filling removed"},{"original":"dark chocolate 70 percent","swap":"milk chocolate for a sweeter less bitter coating"},{"original":"coconut oil","swap":"vegetable shortening to achieve the same glossy chocolate finish"}]','["Not chilling the cheesecake layer long enough before slicing which causes the bars to crumble and lose shape","Adding warm toasted kataifi directly into the cheesecake mixture which introduces steam and makes it soggy","Skipping the coconut oil in the chocolate coating which results in a thick dull coating that cracks when bitten"]','["cheesecake","Dubai chocolate","pistachio","kataifi","bars","no-bake","dessert","viral"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dubai Chocolate Tart','dubai-chocolate-tart','A silky smooth chocolate ganache tart with a buttery shortcrust base layered with toasted kataifi and pistachio cream filling. This elegant tart is a stunning centerpiece for any dessert table.','A luxurious chocolate ganache tart filled with crispy kataifi and pistachio cream inspired by the beloved Dubai chocolate bar.','Middle Eastern Fusion','Medium',35,25,60,8,540,8,46,36,4,'[{"amount":200,"unit":"g","item":"all-purpose flour","group":"crust"},{"amount":80,"unit":"g","item":"cold unsalted butter cubed","group":"crust"},{"amount":40,"unit":"g","item":"powdered sugar","group":"crust"},{"amount":1,"unit":"whole","item":"egg yolk","group":"crust"},{"amount":2,"unit":"tbsp","item":"cold water","group":"crust"},{"amount":120,"unit":"g","item":"kataifi pastry toasted","group":"filling"},{"amount":150,"unit":"g","item":"pistachio cream","group":"filling"},{"amount":250,"unit":"ml","item":"heavy cream","group":"ganache"},{"amount":200,"unit":"g","item":"dark chocolate 70 percent finely chopped","group":"ganache"},{"amount":3,"unit":"tbsp","item":"crushed pistachios","group":"garnish"}]','[{"title":"Make the Shortcrust Pastry","text":"Combine flour powdered sugar and cold butter in a bowl. Rub together with fingertips until the mixture resembles breadcrumbs. Add egg yolk and cold water one tablespoon at a time mixing until dough just comes together. Wrap in cling film and refrigerate for 30 minutes.","timer":1800},{"title":"Blind Bake the Tart Shell","text":"Roll out chilled dough and press into a 9-inch tart pan with a removable base. Trim excess and prick the base with a fork. Line with parchment and fill with baking weights. Bake at 180C for 15 minutes then remove weights and bake for another 5 minutes until golden.","timer":1200},{"title":"Layer the Kataifi Filling","text":"Toast kataifi pastry with a knob of butter in a pan until golden and crispy. Allow to cool completely then mix with pistachio cream until evenly coated. Spread this mixture in an even layer across the cooled tart shell pressing gently to compact slightly.","timer":360},{"title":"Make the Chocolate Ganache","text":"Heat heavy cream in a saucepan over medium heat until it just begins to simmer. Do not let it boil. Pour hot cream over finely chopped dark chocolate in a bowl and let sit for 2 minutes. Stir from the center outward in slow circles until completely smooth and glossy.","timer":300},{"title":"Assemble and Set","text":"Pour the warm ganache slowly over the kataifi pistachio layer allowing it to fill the tart shell completely and create a smooth top. Tap the pan gently on the counter to remove air bubbles. Scatter crushed pistachios over the surface and refrigerate for at least 2 hours until fully set before slicing.","timer":7200}]','[{"original":"all-purpose flour crust","swap":"crushed digestive biscuit and butter base for a no-bake shortcut"},{"original":"heavy cream","swap":"full-fat coconut cream for a dairy-free ganache option"},{"original":"pistachio cream","swap":"hazelnut spread for a different but equally indulgent flavor profile"}]','["Not chilling the pastry dough before rolling which causes it to shrink and crack during blind baking","Boiling the cream for the ganache instead of just simmering which can cause the ganache to split and turn grainy","Pouring ganache over a warm tart shell which melts the kataifi layer and ruins the distinct texture contrast"]','["tart","chocolate","ganache","pistachio","kataifi","Dubai","elegant","dessert"]','["vegetarian"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Dubai Chocolate Stuffed French Toast','dubai-chocolate-stuffed-french-toast','Thick brioche slices stuffed with pistachio cream and toasted kataifi then dipped in a rich custard and pan-fried to golden perfection. A breakfast indulgence inspired by the iconic Dubai chocolate bar.','Golden brioche French toast stuffed with pistachio kataifi filling and served with a chocolate drizzle for the ultimate Dubai-inspired brunch.','Middle Eastern Fusion','Easy',15,15,30,4,590,14,62,33,3,'[{"amount":8,"unit":"slices","item":"thick-cut brioche bread","group":"base"},{"amount":120,"unit":"g","item":"pistachio cream","group":"filling"},{"amount":80,"unit":"g","item":"kataifi pastry toasted and cooled","group":"filling"},{"amount":3,"unit":"whole","item":"large eggs","group":"custard"},{"amount":120,"unit":"ml","item":"whole milk","group":"custard"},{"amount":1,"unit":"tsp","item":"vanilla extract","group":"custard"},{"amount":1,"unit":"tsp","item":"ground cinnamon","group":"custard"},{"amount":30,"unit":"g","item":"unsalted butter","group":"cooking"},{"amount":80,"unit":"g","item":"dark chocolate melted","group":"drizzle"},{"amount":2,"unit":"tbsp","item":"crushed pistachios","group":"garnish"}]','[{"title":"Prepare the Kataifi Filling","text":"Toast kataifi pastry in a dry pan over medium heat stirring constantly for 4 to 5 minutes until golden and fragrant. Remove from heat and cool completely. Mix cooled kataifi with pistachio cream until well combined to form a thick spreadable filling.","timer":300},{"title":"Assemble the Stuffed Toast","text":"Spread a generous layer of the pistachio kataifi filling onto 4 brioche slices. Press the remaining 4 slices on top to create sandwiches. Press gently around the edges to help seal the filling inside. Do not overfill or the filling will spill out during cooking.","timer":180},{"title":"Make the Custard Dip","text":"Whisk together eggs whole milk vanilla extract and ground cinnamon in a wide shallow bowl until smooth and fully combined. The bowl should be wide enough to fit the assembled sandwiches flat for even coating.","timer":60},{"title":"Cook the French Toast","text":"Melt butter in a large non-stick skillet over medium heat. Dip each stuffed sandwich into the custard mixture letting it soak for 30 seconds per side. Place in the pan and cook for 3 to 4 minutes per side until deep golden brown and the custard is fully cooked through.","timer":480},{"title":"Drizzle and Serve","text":"Transfer cooked French toast to serving plates. Drizzle generously with melted dark chocolate. Scatter crushed pistachios over the top and serve immediately while hot. Pair with a dusting of powdered sugar or a dollop of whipped cream if desired.","timer":120}]','[{"original":"brioche bread","swap":"thick-cut challah bread for a similarly rich eggy texture"},{"original":"whole milk","swap":"oat milk for a dairy-free custard that still coats well"},{"original":"dark chocolate drizzle","swap":"store-bought Dubai chocolate bar melted down for an authentic flavor"}]','["Soaking the bread in custard for too long which makes it fall apart in the pan and cook unevenly","Using bread slices that are too thin which causes the filling to burst out during cooking","Cooking on too high a heat which burns the outside of the French toast before the custard center is fully set"]','["French toast","Dubai chocolate","pistachio","kataifi","brunch","breakfast","stuffed","brioche"]','["vegetarian"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Tikka Masala Burrito','tikka-masala-burrito','A fusion wrap that combines creamy Indian tikka masala chicken with fluffy basmati rice inside a warm flour tortilla. Bold spices meet burrito comfort in every bite.','Spiced tikka masala chicken and basmati rice wrapped in a toasted flour tortilla.','Indian-Mexican Fusion','Medium',20,30,50,4,620,38,68,18,5,'[{"amount":600,"unit":"g","item":"boneless chicken thighs cut into chunks","group":"Protein"},{"amount":1,"unit":"cup","item":"basmati rice","group":"Base"},{"amount":4,"unit":"piece","item":"large flour tortillas","group":"Base"},{"amount":1,"unit":"cup","item":"tomato puree","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"heavy cream","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"tikka masala spice blend","group":"Spices"},{"amount":1,"unit":"cup","item":"plain yogurt","group":"Marinade"},{"amount":0.5,"unit":"cup","item":"chopped fresh cilantro","group":"Garnish"},{"amount":1,"unit":"piece","item":"medium onion diced","group":"Aromatics"},{"amount":3,"unit":"clove","item":"garlic minced","group":"Aromatics"}]','[{"title":"Marinate the Chicken","text":"Mix yogurt with half the tikka masala spice blend and coat the chicken chunks thoroughly. Let the chicken marinate for at least 15 minutes at room temperature.","timer":900},{"title":"Cook the Basmati Rice","text":"Rinse basmati rice until water runs clear then cook in 2 cups of salted water over medium heat with the lid on. Fluff with a fork once all water is absorbed.","timer":1080},{"title":"Build the Tikka Masala Sauce","text":"Saute onion and garlic in oil over medium heat until golden. Add remaining spice blend and toast for 1 minute then pour in tomato puree. Simmer for 10 minutes then stir in heavy cream.","timer":720},{"title":"Cook the Chicken","text":"Add marinated chicken to the sauce and simmer over medium heat until the chicken is fully cooked through and the sauce thickens. Stir occasionally to prevent sticking.","timer":900},{"title":"Assemble and Toast the Burritos","text":"Layer rice and tikka masala chicken on each tortilla and top with fresh cilantro. Fold tightly into a burrito and toast seam side down in a dry skillet for 2 minutes per side.","timer":240}]','[{"original":"heavy cream","swap":"coconut cream for a dairy free version"},{"original":"chicken thighs","swap":"paneer cubes for a vegetarian option"},{"original":"flour tortillas","swap":"whole wheat tortillas for added fiber"}]','["Skipping the marinade time which results in bland and dry chicken","Adding too much sauce which makes the burrito soggy and difficult to wrap","Not toasting the burrito which causes it to fall apart when eaten"]','["fusion","burrito","tikka masala","chicken","indian","mexican","spicy"]','["Gluten-Contains","Dairy-Contains"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Kimchi Grilled Cheese','kimchi-grilled-cheese','A boldly tangy grilled cheese that layers fermented kimchi with melted cheddar and gooey mozzarella between buttered sourdough slices. The kimchi adds heat and depth to a classic comfort sandwich.','Crispy buttered sourdough filled with melted cheese and spicy fermented kimchi.','Korean-American Fusion','Easy',5,10,15,2,490,22,38,28,3,'[{"amount":4,"unit":"slice","item":"sourdough bread","group":"Base"},{"amount":0.75,"unit":"cup","item":"well fermented kimchi drained and chopped","group":"Filling"},{"amount":1,"unit":"cup","item":"shredded sharp cheddar cheese","group":"Cheese"},{"amount":0.5,"unit":"cup","item":"shredded mozzarella cheese","group":"Cheese"},{"amount":2,"unit":"tbsp","item":"unsalted butter softened","group":"Fat"},{"amount":1,"unit":"tsp","item":"sesame oil","group":"Fat"},{"amount":1,"unit":"tbsp","item":"gochujang paste","group":"Spice"},{"amount":1,"unit":"tsp","item":"toasted sesame seeds","group":"Garnish"}]','[{"title":"Prepare the Kimchi","text":"Drain excess liquid from the kimchi and chop it into smaller pieces. Pat the kimchi dry with paper towels to prevent the bread from becoming soggy.","timer":120},{"title":"Mix the Cheese and Spread","text":"Combine cheddar and mozzarella in a bowl. Mix gochujang with sesame oil in a small dish and spread a thin layer on the inner sides of all four bread slices.","timer":60},{"title":"Build the Sandwich","text":"Layer a generous amount of mixed cheese on the gochujang side of two bread slices. Spread kimchi evenly over the cheese then top with remaining cheese before placing the second bread slice on top.","timer":60},{"title":"Butter the Exterior","text":"Spread softened butter generously and evenly on both outer sides of each assembled sandwich. Make sure to reach the edges to ensure even browning.","timer":30},{"title":"Grill Until Golden","text":"Place sandwiches in a cold skillet then turn heat to medium low. Cook for 4 to 5 minutes per side pressing gently with a spatula until deeply golden and cheese is fully melted. Sprinkle sesame seeds on top before serving.","timer":600}]','[{"original":"sourdough bread","swap":"thick cut white bread for a softer crust"},{"original":"sharp cheddar","swap":"gruyere for a nuttier flavor profile"},{"original":"gochujang paste","swap":"sriracha mixed with a pinch of sugar"}]','["Using wet kimchi which makes the bread soggy before it can toast","Cooking on high heat which burns the outside before the cheese melts inside","Overfilling the sandwich which prevents it from closing and melting evenly"]','["grilled cheese","kimchi","korean","fusion","sandwich","comfort food"]','["Vegetarian","Dairy-Contains"]','Sandwich','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shawarma Nachos','shawarma-nachos','Crispy tortilla chips topped with spiced shawarma chicken, creamy garlic sauce, and pickled vegetables for a Middle Eastern twist on classic nachos. Every chip is loaded with bold flavor and satisfying texture.','Tortilla chips loaded with shawarma spiced chicken, garlic sauce, and tangy pickled toppings.','Middle Eastern-Mexican Fusion','Medium',20,25,45,4,710,40,62,30,6,'[{"amount":500,"unit":"g","item":"boneless chicken breast thinly sliced","group":"Protein"},{"amount":2,"unit":"tbsp","item":"shawarma spice blend","group":"Spices"},{"amount":300,"unit":"g","item":"tortilla chips","group":"Base"},{"amount":1.5,"unit":"cup","item":"shredded mozzarella cheese","group":"Cheese"},{"amount":0.5,"unit":"cup","item":"garlic sauce toum","group":"Sauce"},{"amount":0.5,"unit":"cup","item":"diced tomatoes drained","group":"Topping"},{"amount":0.5,"unit":"cup","item":"pickled turnips or pickled cucumbers sliced","group":"Topping"},{"amount":0.25,"unit":"cup","item":"fresh parsley chopped","group":"Garnish"},{"amount":2,"unit":"tbsp","item":"olive oil","group":"Fat"},{"amount":1,"unit":"piece","item":"lemon juiced","group":"Acid"}]','[{"title":"Season and Cook the Chicken","text":"Toss sliced chicken with shawarma spice blend olive oil and lemon juice. Cook in a hot skillet over high heat for 5 to 6 minutes until charred on the edges and cooked through. Slice into smaller strips.","timer":420},{"title":"Preheat the Oven","text":"Preheat your oven to 200 degrees Celsius or 390 degrees Fahrenheit. Line a large baking sheet with parchment paper for easy cleanup.","timer":300},{"title":"Layer the Nachos","text":"Spread tortilla chips in a single even layer on the baking sheet. Scatter half the mozzarella over the chips then distribute the cooked shawarma chicken evenly. Top with the remaining cheese.","timer":120},{"title":"Bake Until Melted","text":"Bake the loaded nacho tray in the preheated oven for 8 to 10 minutes until the cheese is fully melted and bubbling and the edges of the chips are lightly golden.","timer":600},{"title":"Add Toppings and Serve","text":"Remove from oven and immediately drizzle garlic sauce over the nachos. Top with diced tomatoes pickled turnips and fresh parsley. Serve straight from the tray while hot.","timer":60}]','[{"original":"garlic sauce toum","swap":"tahini mixed with lemon juice and water"},{"original":"pickled turnips","swap":"quick pickled red onions for a similar tang"},{"original":"chicken breast","swap":"lamb mince cooked with shawarma spices"}]','["Piling chips too thick which results in soggy chips on the bottom layer","Adding garlic sauce before baking which causes it to break down and become oily","Using wet tomatoes which releases liquid and makes the nachos soggy quickly"]','["nachos","shawarma","middle eastern","fusion","chicken","party food","snack"]','["Dairy-Contains"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Miso Carbonara','miso-carbonara','A Japanese Italian fusion pasta that replaces traditional pancetta with miso glazed mushrooms and uses white miso to deepen the classic egg and cheese sauce. Silky umami rich noodles ready in under 30 minutes.','Creamy egg and miso sauce coats spaghetti with savory umami glazed mushrooms.','Japanese-Italian Fusion','Medium',10,20,30,2,580,24,72,20,4,'[{"amount":200,"unit":"g","item":"spaghetti","group":"Base"},{"amount":250,"unit":"g","item":"shiitake or cremini mushrooms sliced","group":"Protein"},{"amount":2,"unit":"tbsp","item":"white miso paste","group":"Sauce"},{"amount":3,"unit":"piece","item":"large eggs","group":"Sauce"},{"amount":0.75,"unit":"cup","item":"finely grated pecorino romano","group":"Cheese"},{"amount":2,"unit":"clove","item":"garlic minced","group":"Aromatics"},{"amount":2,"unit":"tbsp","item":"unsalted butter","group":"Fat"},{"amount":1,"unit":"tsp","item":"cracked black pepper","group":"Spice"},{"amount":2,"unit":"tsp","item":"soy sauce","group":"Sauce"}]','[{"title":"Cook the Pasta","text":"Bring a large pot of well salted water to a boil and cook spaghetti until al dente according to package instructions. Reserve 1 cup of starchy pasta cooking water before draining.","timer":720},{"title":"Prepare the Miso Egg Sauce","text":"Whisk together eggs pecorino miso paste and black pepper in a bowl until fully smooth. This sauce should be creamy and well combined with no lumps of miso remaining.","timer":180},{"title":"Cook the Mushrooms","text":"Melt butter in a large skillet over medium high heat and add mushrooms without stirring for 3 minutes to develop a sear. Add garlic and soy sauce and toss for 1 more minute until fragrant.","timer":240},{"title":"Combine Pasta and Mushrooms","text":"Add drained spaghetti directly to the mushroom skillet and toss well off the heat. Remove the pan completely from heat source before adding the egg sauce to avoid scrambling.","timer":60},{"title":"Add Sauce and Emulsify","text":"Pour the miso egg mixture over the pasta while tossing constantly. Add pasta water a splash at a time until the sauce becomes glossy silky and coats every strand evenly. Serve immediately.","timer":120}]','[{"original":"pecorino romano","swap":"parmesan which gives a milder less salty flavor"},{"original":"shiitake mushrooms","swap":"smoked bacon or pancetta for a non vegetarian version"},{"original":"white miso paste","swap":"yellow miso for a slightly stronger umami flavor"}]','["Adding the egg sauce while the pan is still on heat which scrambles the eggs","Skipping the pasta water which is essential for creating the silky emulsified sauce","Using cold eggs straight from the fridge which do not emulsify smoothly into the sauce"]','["pasta","carbonara","miso","japanese","italian","fusion","vegetarian","umami"]','["Vegetarian","Dairy-Contains"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Harissa Honey Fried Chicken Sandwich','harissa-honey-fried-chicken-sandwich','A crispy buttermilk fried chicken thigh glazed with spicy North African harissa and sweet honey served on a brioche bun with cool slaw. The heat and sweetness create an addictive contrast in every bite.','Crunchy fried chicken thigh with a spicy harissa honey glaze on a toasted brioche bun.','North African-American Fusion','Hard',30,20,50,4,760,42,74,32,4,'[{"amount":4,"unit":"piece","item":"boneless skin on chicken thighs","group":"Protein"},{"amount":1,"unit":"cup","item":"buttermilk","group":"Marinade"},{"amount":1.5,"unit":"cup","item":"all purpose flour","group":"Coating"},{"amount":3,"unit":"tbsp","item":"harissa paste","group":"Sauce"},{"amount":2,"unit":"tbsp","item":"honey","group":"Sauce"},{"amount":4,"unit":"piece","item":"brioche buns","group":"Base"},{"amount":1.5,"unit":"cup","item":"shredded cabbage and carrot coleslaw mix","group":"Topping"},{"amount":3,"unit":"tbsp","item":"mayonnaise","group":"Sauce"},{"amount":1,"unit":"tsp","item":"smoked paprika","group":"Spice"},{"amount":500,"unit":"ml","item":"neutral oil for frying","group":"Fat"}]','[{"title":"Marinate the Chicken","text":"Submerge chicken thighs fully in buttermilk seasoned with salt and smoked paprika. Marinate for at least 20 minutes at room temperature or up to 4 hours in the refrigerator for deeper flavor.","timer":1200},{"title":"Dredge and Coat","text":"Season flour generously with salt pepper and smoked paprika in a shallow dish. Lift each chicken thigh from buttermilk letting excess drip off then press firmly into the flour coating on all sides. Let rest on a rack for 5 minutes.","timer":300},{"title":"Fry the Chicken","text":"Heat oil in a deep heavy skillet to 175 degrees Celsius or 350 degrees Fahrenheit. Carefully lower chicken thighs into oil and fry for 8 to 10 minutes turning once until the coating is deep golden and the internal temperature reaches 74 degrees Celsius.","timer":600},{"title":"Make the Harissa Honey Glaze","text":"While chicken rests whisk harissa paste and honey together in a small bowl until fully combined. Brush the glaze generously over the hot fried chicken immediately after it comes out of the oil.","timer":60},{"title":"Assemble the Sandwich","text":"Mix coleslaw with mayonnaise and a pinch of salt. Toast brioche buns cut side down in a dry skillet until golden. Layer coleslaw on the bottom bun place glazed chicken on top and close with the top bun.","timer":180}]','[{"original":"harissa paste","swap":"gochujang mixed with olive oil for a Korean heat"},{"original":"buttermilk","swap":"plain yogurt thinned with a splash of milk"},{"original":"brioche buns","swap":"potato rolls which are equally soft and slightly sweet"}]','["Frying in oil that is not hot enough which results in greasy and soggy coating","Skipping the rest time after dredging which causes the flour coating to fall off","Adding the harissa honey glaze too early in the cooking process which causes it to burn in the oil"]','["fried chicken","sandwich","harissa","honey","spicy","north african","fusion","crispy"]','["Dairy-Contains"]','Sandwich','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cottage Cheese Cookie Dough','cottage-cheese-cookie-dough','A high protein no bake treat that tastes just like raw cookie dough without the risk. Blended cottage cheese creates a creamy base loaded with chocolate chips.','Creamy high protein cookie dough made with blended cottage cheese and chocolate chips.','American','Easy',10,0,10,4,280,18,28,10,1,'[{"amount":2,"unit":"cups","item":"full fat cottage cheese","group":"base"},{"amount":3,"unit":"tablespoons","item":"maple syrup","group":"sweetener"},{"amount":2,"unit":"teaspoons","item":"vanilla extract","group":"flavoring"},{"amount":0.25,"unit":"teaspoon","item":"salt","group":"seasoning"},{"amount":3,"unit":"tablespoons","item":"almond flour","group":"base"},{"amount":2,"unit":"tablespoons","item":"peanut butter","group":"flavoring"},{"amount":0.5,"unit":"cup","item":"mini chocolate chips","group":"mix-ins"},{"amount":1,"unit":"teaspoon","item":"coconut flour","group":"base"}]','[{"title":"Blend the Base","text":"Add cottage cheese, maple syrup, vanilla extract, and salt to a high speed blender or food processor. Blend on high for 60 to 90 seconds until completely smooth with no visible curds.","timer":90},{"title":"Add the Flours","text":"Add the almond flour and coconut flour to the blended mixture. Pulse a few times until fully incorporated. The mixture should be thick and scoopable.","timer":20},{"title":"Mix in Peanut Butter","text":"Add the peanut butter and blend again for 15 seconds until smooth and fully combined. Taste and adjust sweetness with more maple syrup if desired.","timer":15},{"title":"Fold in Chocolate Chips","text":"Transfer the mixture to a bowl and fold in the mini chocolate chips using a spatula. Do not blend the chips in as they will break apart.","timer":60},{"title":"Chill and Serve","text":"Refrigerate for at least 30 minutes to firm up the texture. Serve chilled in a bowl or scoop into balls. Store in an airtight container for up to 4 days.","timer":1800}]','[{"original":"maple syrup","swap":"honey or agave nectar"},{"original":"peanut butter","swap":"almond butter or sunflower seed butter"},{"original":"almond flour","swap":"oat flour or cashew flour"}]','["Not blending long enough leaving a grainy texture from cottage cheese curds","Skipping the chilling step which results in a runny consistency","Using low fat cottage cheese which produces a watery and less creamy result"]','["high protein","no bake","healthy dessert","meal prep","snack"]','["vegetarian","gluten-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Rice Paper Dumplings','rice-paper-dumplings','Crispy pan fried dumplings made with rice paper wrappers instead of traditional dough. The double wrap technique creates a golden chewy shell around a savory veggie filling.','Pan fried rice paper dumplings with a crispy golden exterior and savory vegetable filling.','Asian Fusion','Medium',20,15,35,4,220,9,32,7,3,'[{"amount":12,"unit":"sheets","item":"rice paper wrappers","group":"wrapper"},{"amount":2,"unit":"cups","item":"shredded cabbage","group":"filling"},{"amount":1,"unit":"cup","item":"shredded carrots","group":"filling"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"filling"},{"amount":2,"unit":"tablespoons","item":"soy sauce","group":"seasoning"},{"amount":1,"unit":"tablespoon","item":"sesame oil","group":"seasoning"},{"amount":1,"unit":"teaspoon","item":"fresh ginger grated","group":"seasoning"},{"amount":2,"unit":"tablespoons","item":"neutral oil for frying","group":"cooking"},{"amount":2,"unit":"stalks","item":"green onions thinly sliced","group":"filling"}]','[{"title":"Cook the Filling","text":"Heat sesame oil in a pan over medium high heat. Add garlic and ginger and cook for 30 seconds. Add cabbage and carrots and stir fry for 4 minutes until softened. Add soy sauce and green onions and cook 1 more minute. Set aside to cool completely.","timer":360},{"title":"Prepare the Rice Paper","text":"Fill a wide shallow bowl with warm water. Dip one rice paper sheet for 5 to 8 seconds until just pliable but not fully soft. Lay flat on a damp cutting board. Dip a second sheet and place directly on top of the first.","timer":30},{"title":"Fill and Fold","text":"Place 2 tablespoons of cooled filling in the lower center of the double layered rice paper. Fold the bottom edge up over the filling, fold in the sides, then roll forward tightly to seal. Press gently to secure. Repeat with remaining wrappers and filling.","timer":600},{"title":"Pan Fry the Dumplings","text":"Heat neutral oil in a nonstick pan over medium heat. Place dumplings seam side down and cook for 3 to 4 minutes without moving until the bottom is golden and crispy. Flip and cook the other side for 2 to 3 minutes.","timer":420},{"title":"Serve","text":"Remove from pan and let rest for 2 minutes. Serve immediately with soy sauce, chili oil, or your favorite dipping sauce. Do not stack the dumplings as they will stick together.","timer":120}]','[{"original":"cabbage and carrots","swap":"ground pork or shrimp for a meat filling"},{"original":"soy sauce","swap":"tamari for a gluten free option"},{"original":"sesame oil","swap":"chili sesame oil for extra heat"}]','["Soaking the rice paper too long making it tear and impossible to fold","Using hot filling which makes the rice paper fall apart before folding","Skipping the double wrap which causes the dumpling to burst open during frying"]','["dumplings","rice paper","pan fried","asian","appetizer"]','["vegan","gluten-free","dairy-free"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sheet Pan Quesadillas','sheet-pan-quesadillas','A hands off method for making crispy evenly melted quesadillas for a crowd using just one sheet pan. The oven does all the work producing perfect results every single time.','Oven baked sheet pan quesadillas that are crispy cheesy and ready in under 30 minutes.','Mexican','Easy',10,18,28,6,420,22,38,20,4,'[{"amount":6,"unit":"large","item":"flour tortillas","group":"base"},{"amount":2,"unit":"cups","item":"shredded Mexican blend cheese","group":"filling"},{"amount":1,"unit":"can","item":"black beans drained and rinsed","group":"filling"},{"amount":1,"unit":"cup","item":"cooked chicken breast shredded","group":"filling"},{"amount":0.5,"unit":"cup","item":"diced bell peppers","group":"filling"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"cooking"},{"amount":1,"unit":"teaspoon","item":"cumin","group":"seasoning"},{"amount":1,"unit":"teaspoon","item":"chili powder","group":"seasoning"},{"amount":0.5,"unit":"teaspoon","item":"garlic powder","group":"seasoning"}]','[{"title":"Preheat and Prep Pan","text":"Preheat oven to 425 degrees Fahrenheit. Brush a large rimmed sheet pan generously with olive oil. This is the key step for achieving a crispy bottom on the quesadillas.","timer":600},{"title":"Mix the Filling","text":"In a bowl combine shredded chicken, black beans, bell peppers, cumin, chili powder, and garlic powder. Toss together until the filling is evenly seasoned.","timer":120},{"title":"Assemble on the Pan","text":"Lay 3 tortillas flat on the prepared sheet pan. Sprinkle half the cheese evenly over the tortillas. Distribute the filling mixture over the cheese layer. Top with remaining cheese and place the remaining 3 tortillas on top pressing down gently.","timer":180},{"title":"Weight and Bake","text":"Brush the top tortillas lightly with olive oil. Place a second sheet pan directly on top to weigh down the quesadillas. Bake for 10 minutes then remove the top pan and bake for another 8 minutes until golden and crispy.","timer":1080},{"title":"Slice and Serve","text":"Remove from oven and let cool for 3 minutes. Slice into wedges using a pizza cutter or sharp knife. Serve with sour cream, salsa, and guacamole on the side.","timer":180}]','[{"original":"cooked chicken breast","swap":"canned tuna or sauteed mushrooms for a vegetarian option"},{"original":"flour tortillas","swap":"whole wheat or gluten free tortillas"},{"original":"Mexican blend cheese","swap":"sharp cheddar or pepper jack cheese"}]','["Overfilling the quesadillas which prevents them from sealing and causes spillage","Skipping the second pan on top which results in uneven cooking and lifting tortillas","Not letting them rest before slicing which causes all the cheese to slide out"]','["quesadillas","sheet pan","meal prep","easy dinner","crowd pleaser"]','["nut-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Mango Avocado Salsa','spicy-mango-avocado-salsa','A vibrant fresh salsa combining sweet mango with creamy avocado and a fiery jalapeno kick. Ready in minutes with no cooking required and perfect for chips or grilled fish.','Fresh sweet and spicy mango avocado salsa ready in 15 minutes with zero cooking.','Mexican','Easy',15,0,15,6,140,2,18,8,5,'[{"amount":2,"unit":"large","item":"ripe mangoes diced","group":"produce"},{"amount":2,"unit":"medium","item":"ripe avocados diced","group":"produce"},{"amount":1,"unit":"medium","item":"jalapeno finely diced seeds removed","group":"produce"},{"amount":0.5,"unit":"cup","item":"red onion finely diced","group":"produce"},{"amount":0.33,"unit":"cup","item":"fresh cilantro chopped","group":"herb"},{"amount":3,"unit":"tablespoons","item":"fresh lime juice","group":"acid"},{"amount":0.5,"unit":"teaspoon","item":"salt","group":"seasoning"},{"amount":0.25,"unit":"teaspoon","item":"cayenne pepper","group":"seasoning"}]','[{"title":"Prep the Produce","text":"Dice the mangoes and avocados into uniform half inch cubes for the best texture. Finely dice the red onion and jalapeno. Place diced avocado in a bowl and immediately toss with lime juice to prevent browning.","timer":300},{"title":"Combine Ingredients","text":"Add the diced mango, red onion, and jalapeno to the bowl with the avocado. Gently fold everything together being careful not to mash the avocado pieces.","timer":60},{"title":"Season the Salsa","text":"Add the chopped cilantro, salt, and cayenne pepper. Gently toss to combine. Taste and adjust seasoning adding more lime juice for brightness or more cayenne for heat.","timer":60},{"title":"Rest the Flavors","text":"Let the salsa rest at room temperature for 5 to 10 minutes before serving. This allows the salt to draw out the juices and the flavors to meld together beautifully.","timer":600},{"title":"Serve","text":"Serve immediately with tortilla chips or as a topping for grilled chicken or fish. Do not make this more than 2 hours ahead as the avocado will oxidize and turn brown.","timer":30}]','[{"original":"fresh mango","swap":"frozen thawed mango or pineapple"},{"original":"jalapeno","swap":"serrano pepper for more heat or bell pepper for no heat"},{"original":"cilantro","swap":"fresh mint or flat leaf parsley"}]','["Using underripe mango which is too fibrous and lacks sweetness","Overmixing the salsa which turns the avocado into mush","Making it too far in advance causing the avocado to brown and the salsa to become watery"]','["salsa","no cook","fresh","summer","appetizer","topping"]','["vegan","gluten-free","dairy-free","paleo"]','Appetizer','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('One Pot Creamy Tuscan White Bean Soup','one-pot-creamy-tuscan-white-bean-soup','A hearty Italian inspired soup loaded with white beans, sun dried tomatoes, and fresh spinach in a rich parmesan broth. Everything comes together in one pot in under 40 minutes.','Creamy one pot Tuscan white bean soup with spinach and sun dried tomatoes ready in 40 minutes.','Italian','Easy',10,30,40,6,320,16,42,10,11,'[{"amount":2,"unit":"cans","item":"white cannellini beans drained and rinsed","group":"base"},{"amount":4,"unit":"cups","item":"low sodium vegetable broth","group":"liquid"},{"amount":3,"unit":"cups","item":"fresh baby spinach","group":"produce"},{"amount":0.5,"unit":"cup","item":"sun dried tomatoes in oil chopped","group":"produce"},{"amount":4,"unit":"cloves","item":"garlic minced","group":"aromatics"},{"amount":1,"unit":"medium","item":"yellow onion diced","group":"aromatics"},{"amount":0.5,"unit":"cup","item":"grated parmesan cheese","group":"dairy"},{"amount":1,"unit":"teaspoon","item":"Italian seasoning","group":"seasoning"},{"amount":2,"unit":"tablespoons","item":"olive oil","group":"cooking"}]','[{"title":"Saute the Aromatics","text":"Heat olive oil in a large Dutch oven over medium heat. Add diced onion and cook for 5 minutes until softened and translucent. Add minced garlic and cook for 1 more minute until fragrant.","timer":360},{"title":"Add Tomatoes and Seasoning","text":"Add the chopped sun dried tomatoes and Italian seasoning to the pot. Stir and cook for 2 minutes to allow the tomatoes to release their oils and deepen the flavor base.","timer":120},{"title":"Add Beans and Broth","text":"Add the drained white beans and pour in the vegetable broth. Bring to a boil then reduce heat to low and simmer for 15 minutes. Use the back of a spoon to mash about one quarter of the beans against the pot wall to thicken the broth naturally.","timer":900},{"title":"Finish with Spinach and Parmesan","text":"Add the baby spinach to the pot and stir until wilted which takes about 2 minutes. Remove from heat and stir in the grated parmesan cheese until fully melted into the broth.","timer":120},{"title":"Season and Serve","text":"Taste the soup and adjust salt and pepper as needed. Ladle into bowls and top with extra parmesan and a drizzle of olive oil. Serve with crusty bread for dipping.","timer":60}]','[{"original":"cannellini beans","swap":"great northern beans or chickpeas"},{"original":"fresh spinach","swap":"kale or Swiss chard add 5 extra minutes cooking time"},{"original":"parmesan cheese","swap":"nutritional yeast for a vegan version"}]','["Not mashing any beans which leaves the broth thin and watery instead of creamy","Adding parmesan while the soup is still boiling which causes it to clump and become stringy","Using regular broth with full sodium which makes the final soup far too salty"]','["soup","one pot","italian","beans","comfort food","meal prep"]','["vegetarian","gluten-free","nut-free"]','Soup','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Gochujang Tofu','crispy-gochujang-tofu','Golden crispy tofu cubes tossed in a spicy and sweet gochujang glaze. This bold Korean-inspired dish delivers serious heat with a satisfying crunch.','Crispy baked tofu coated in a fiery Korean gochujang sauce ready in 45 minutes.','Korean','Easy',15,30,45,4,280,14,22,16,3,'[{"amount":400,"unit":"g","item":"extra firm tofu pressed and cubed","group":"main"},{"amount":2,"unit":"tbsp","item":"cornstarch","group":"main"},{"amount":2,"unit":"tbsp","item":"gochujang paste","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"maple syrup","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"neutral oil","group":"main"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"sauce"},{"amount":2,"unit":"stalks","item":"green onions sliced","group":"garnish"}]','[{"title":"Press and prep the tofu","text":"Press tofu for at least 15 minutes to remove excess moisture. Cut into 1 inch cubes and toss thoroughly with cornstarch until each piece is lightly coated.","timer":900},{"title":"Bake the tofu","text":"Preheat oven to 200C. Toss tofu cubes with neutral oil and spread in a single layer on a lined baking sheet. Bake for 25 to 30 minutes flipping halfway until deeply golden and crispy.","timer":1800},{"title":"Make the gochujang sauce","text":"While tofu bakes whisk together gochujang, soy sauce, maple syrup, sesame oil, rice vinegar, and minced garlic in a small bowl until smooth and combined.","timer":120},{"title":"Glaze the tofu","text":"Heat a large skillet over medium heat. Add the baked tofu and pour the sauce over it. Toss quickly for 2 to 3 minutes until every piece is coated and the sauce thickens slightly.","timer":180},{"title":"Serve","text":"Transfer glazed tofu to a serving plate and top with sliced green onions. Serve immediately over steamed rice or noodles for best texture.","timer":0}]','[{"original":"gochujang paste","swap":"sriracha mixed with a small amount of miso paste"},{"original":"maple syrup","swap":"honey or agave nectar"},{"original":"rice vinegar","swap":"apple cider vinegar"}]','["Not pressing the tofu long enough which results in soggy rather than crispy pieces","Overcrowding the baking sheet which steams the tofu instead of crisping it","Adding the sauce too early before the tofu is fully crispy which causes it to become soft"]','["tofu","gochujang","spicy","Korean","vegan","baked"]','["vegan","vegetarian","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Sticky Sesame Tofu','sticky-sesame-tofu','Tender pan-fried tofu glazed in a rich sticky sesame sauce with a nutty aroma. This easy weeknight dish comes together in under 30 minutes.','Pan-fried tofu in a glossy sesame soy glaze that is sweet savory and irresistibly sticky.','Asian-Inspired','Easy',10,20,30,4,265,13,20,15,2,'[{"amount":400,"unit":"g","item":"extra firm tofu pressed and cubed","group":"main"},{"amount":2,"unit":"tbsp","item":"cornstarch","group":"main"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"honey or maple syrup","group":"sauce"},{"amount":1,"unit":"tbsp","item":"toasted sesame oil","group":"sauce"},{"amount":2,"unit":"tbsp","item":"tahini","group":"sauce"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"sauce"},{"amount":2,"unit":"tbsp","item":"sesame seeds toasted","group":"garnish"},{"amount":2,"unit":"tbsp","item":"neutral cooking oil","group":"main"}]','[{"title":"Prepare the tofu","text":"Press tofu for at least 15 minutes. Cut into bite sized cubes and toss with cornstarch until all sides are evenly coated. This step is critical for achieving a crispy exterior.","timer":900},{"title":"Pan-fry the tofu","text":"Heat neutral oil in a large non-stick skillet over medium-high heat. Add tofu in a single layer and fry undisturbed for 3 to 4 minutes per side until all faces are golden brown and crispy.","timer":480},{"title":"Mix the sesame sauce","text":"In a small bowl whisk together soy sauce, honey, sesame oil, tahini, minced garlic, and grated ginger until smooth. Add 2 tablespoons of water to loosen if the sauce seems too thick.","timer":60},{"title":"Combine and glaze","text":"Reduce heat to medium-low. Pour the sesame sauce over the crispy tofu in the skillet. Toss gently and cook for 2 to 3 minutes until the sauce thickens and clings to every piece.","timer":180},{"title":"Garnish and serve","text":"Remove from heat and sprinkle generously with toasted sesame seeds. Serve hot over steamed jasmine rice with steamed broccoli or bok choy on the side.","timer":0}]','[{"original":"tahini","swap":"smooth peanut butter for a nuttier flavor"},{"original":"honey","swap":"maple syrup or agave for a fully vegan version"},{"original":"fresh ginger","swap":"half a teaspoon of ground ginger"}]','["Skipping the cornstarch coating which prevents the tofu from getting crispy in the pan","Moving the tofu too frequently while frying which stops it from forming a golden crust","Using low-fat or silken tofu which will fall apart during cooking"]','["tofu","sesame","sticky","Asian","vegan","quick"]','["vegan","vegetarian","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('General Tso Tofu','general-tso-tofu','A plant-based take on the classic Chinese-American takeout dish with crispy tofu in a tangy sweet and spicy sauce. Better than takeout and ready in 40 minutes.','Crispy tofu smothered in General Tso sauce that is tangy sweet spicy and deeply satisfying.','Chinese-American','Medium',15,25,40,4,310,15,30,14,2,'[{"amount":400,"unit":"g","item":"extra firm tofu pressed and cubed","group":"main"},{"amount":3,"unit":"tbsp","item":"cornstarch divided","group":"main"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"hoisin sauce","group":"sauce"},{"amount":2,"unit":"tbsp","item":"rice vinegar","group":"sauce"},{"amount":1,"unit":"tbsp","item":"brown sugar","group":"sauce"},{"amount":1,"unit":"tsp","item":"chili flakes","group":"sauce"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"sauce"},{"amount":3,"unit":"tbsp","item":"neutral oil","group":"main"}]','[{"title":"Press and coat the tofu","text":"Press tofu firmly for at least 15 minutes to remove excess water. Cut into 1 inch cubes and toss with 2 tablespoons of cornstarch until fully and evenly coated on all sides.","timer":900},{"title":"Fry the tofu until crispy","text":"Heat oil in a large wok or skillet over high heat. Add tofu in batches to avoid overcrowding and fry for 3 to 4 minutes per side until deeply golden and crispy. Remove and set aside.","timer":480},{"title":"Make the General Tso sauce","text":"Whisk together soy sauce, hoisin sauce, rice vinegar, brown sugar, chili flakes, and the remaining 1 tablespoon of cornstarch with 60ml of water until smooth and lump free.","timer":90},{"title":"Build the dish","text":"In the same skillet over medium heat add a drizzle of oil and saute garlic and ginger for 30 seconds until fragrant. Pour in the sauce and stir constantly until it thickens about 2 minutes.","timer":150},{"title":"Toss and finish","text":"Add the crispy tofu back to the skillet and toss immediately to coat every piece in the glossy sauce. Serve at once over rice garnished with sesame seeds and sliced green onions.","timer":0}]','[{"original":"hoisin sauce","swap":"plum sauce or extra soy sauce with a pinch of five spice"},{"original":"brown sugar","swap":"coconut sugar or maple syrup"},{"original":"chili flakes","swap":"one tablespoon of sambal oelek for a fresher heat"}]','["Not pressing the tofu which creates steam during frying and prevents a crispy exterior","Adding too much tofu to the pan at once which lowers the oil temperature and leads to soft tofu","Letting the sauce over-reduce which makes it too thick and causes it to burn and turn bitter"]','["tofu","general tso","Chinese-American","takeout","crispy","spicy"]','["vegan","vegetarian","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Crispy Tofu Rice Bowl','crispy-tofu-rice-bowl','A nourishing bowl loaded with golden crispy tofu, fluffy rice, fresh vegetables, and a savory ginger soy dressing. Simple wholesome and endlessly customizable.','A balanced and colorful tofu rice bowl with crispy tofu and a punchy ginger soy dressing.','Japanese-Inspired','Easy',15,25,40,4,390,16,48,14,5,'[{"amount":400,"unit":"g","item":"extra firm tofu pressed and cubed","group":"main"},{"amount":2,"unit":"cups","item":"jasmine rice cooked","group":"base"},{"amount":2,"unit":"tbsp","item":"cornstarch","group":"main"},{"amount":3,"unit":"tbsp","item":"soy sauce","group":"dressing"},{"amount":1,"unit":"tbsp","item":"sesame oil","group":"dressing"},{"amount":1,"unit":"tbsp","item":"rice vinegar","group":"dressing"},{"amount":1,"unit":"tsp","item":"fresh ginger grated","group":"dressing"},{"amount":2,"unit":"cups","item":"edamame shelled and cooked","group":"toppings"},{"amount":1,"unit":"large","item":"cucumber thinly sliced","group":"toppings"},{"amount":2,"unit":"tbsp","item":"neutral cooking oil","group":"main"}]','[{"title":"Press and coat the tofu","text":"Press tofu for at least 15 minutes until very dry. Cut into bite sized cubes and toss thoroughly with cornstarch until all surfaces are lightly and evenly coated.","timer":900},{"title":"Pan-fry the tofu","text":"Heat neutral oil in a non-stick skillet over medium-high heat. Add tofu in a single layer and cook undisturbed for 3 to 4 minutes per side until all sides are golden brown and crispy.","timer":480},{"title":"Prepare the dressing","text":"Whisk together soy sauce, sesame oil, rice vinegar, and grated ginger in a small bowl. Taste and adjust seasoning. Set aside until bowls are assembled.","timer":60},{"title":"Prep the toppings","text":"While tofu cooks prepare the bowl toppings. Thinly slice the cucumber. Warm the edamame if using frozen. Fluff the cooked rice with a fork and divide between four bowls.","timer":300},{"title":"Assemble the bowls","text":"Layer rice in each bowl followed by crispy tofu, edamame, and cucumber slices. Drizzle generously with the ginger soy dressing and serve immediately while tofu is still crispy.","timer":0}]','[{"original":"jasmine rice","swap":"brown rice, quinoa, or cauliflower rice"},{"original":"edamame","swap":"frozen peas or shelled broad beans"},{"original":"cucumber","swap":"thinly sliced radishes or shredded carrots"}]','["Using warm or wet tofu which prevents it from crisping up properly in the skillet","Dressing the bowl too early which softens the crispy tofu before eating","Using silken tofu which is too delicate and will crumble during pan-frying"]','["tofu","rice bowl","Japanese","healthy","meal prep","vegan"]','["vegan","vegetarian","dairy-free","gluten-free adaptable"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Spicy Peanut Tofu Stir-Fry','spicy-peanut-tofu-stir-fry','A vibrant stir-fry featuring crispy tofu and colorful vegetables tossed in a creamy spicy peanut sauce. Rich nutty and packed with plant-based protein.','A fast and flavorful tofu stir-fry coated in a bold spicy peanut sauce with crisp vegetables.','Southeast Asian-Inspired','Easy',15,20,35,4,340,17,24,20,4,'[{"amount":400,"unit":"g","item":"extra firm tofu pressed and cubed","group":"main"},{"amount":2,"unit":"tbsp","item":"cornstarch","group":"main"},{"amount":3,"unit":"tbsp","item":"smooth peanut butter","group":"sauce"},{"amount":2,"unit":"tbsp","item":"soy sauce","group":"sauce"},{"amount":1,"unit":"tbsp","item":"sriracha","group":"sauce"},{"amount":1,"unit":"tbsp","item":"lime juice","group":"sauce"},{"amount":2,"unit":"cups","item":"broccoli florets","group":"vegetables"},{"amount":1,"unit":"large","item":"red bell pepper sliced","group":"vegetables"},{"amount":3,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"tbsp","item":"neutral cooking oil","group":"main"}]','[{"title":"Prepare and coat the tofu","text":"Press tofu for a minimum of 15 minutes. Cube into 1 inch pieces and toss with cornstarch to coat evenly. This ensures a crispy exterior that will hold up in the stir-fry.","timer":900},{"title":"Fry the tofu","text":"Heat 1 tablespoon of oil in a wok or large skillet over high heat. Add tofu and cook for 3 to 4 minutes per side until all sides are golden and crispy. Remove from the pan and set aside.","timer":480},{"title":"Make the peanut sauce","text":"Whisk together peanut butter, soy sauce, sriracha, lime juice, and minced garlic with 3 tablespoons of warm water until completely smooth and creamy. The sauce should be pourable.","timer":90},{"title":"Stir-fry the vegetables","text":"Add remaining oil to the hot wok. Add broccoli florets and red bell pepper and stir-fry on high heat for 4 to 5 minutes until tender-crisp with some char on the edges.","timer":300},{"title":"Combine everything","text":"Return the crispy tofu to the wok with the vegetables. Pour the peanut sauce over everything and toss vigorously for 1 to 2 minutes until evenly coated and heated through. Serve immediately.","timer":120}]','[{"original":"peanut butter","swap":"almond butter or sunflower seed butter for a nut-free version"},{"original":"sriracha","swap":"chili garlic sauce or sambal oelek"},{"original":"broccoli","swap":"snap peas, bok choy, or zucchini"}]','["Making the peanut sauce too thick by not adding enough water which causes it to clump and not coat evenly","Cooking the vegetables until soft instead of tender-crisp which makes the dish lose its texture contrast","Not frying the tofu separately before adding it to the stir-fry which results in soft tofu pieces"]','["tofu","peanut","stir-fry","spicy","vegan","quick"]','["vegan","vegetarian","dairy-free"]','Main Course','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Silken Tofu Chocolate Mousse','silken-tofu-chocolate-mousse','A creamy and decadent chocolate mousse made entirely from silken tofu and melted dark chocolate. It is rich, smooth, and completely dairy free.','A velvety dairy free chocolate mousse that comes together in minutes using silken tofu.','American','Easy',10,5,75,4,280,8,28,16,3,'[{"amount":350,"unit":"g","item":"silken tofu drained","group":"base"},{"amount":200,"unit":"g","item":"dark chocolate chips 70 percent","group":"chocolate"},{"amount":3,"unit":"tbsp","item":"maple syrup","group":"sweetener"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"flavoring"},{"amount":2,"unit":"tbsp","item":"cocoa powder unsweetened","group":"chocolate"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"seasoning"},{"amount":1,"unit":"tbsp","item":"coconut oil","group":"chocolate"},{"amount":2,"unit":"tbsp","item":"plant based milk","group":"base"}]','[{"title":"Melt the Chocolate","text":"Combine the dark chocolate chips and coconut oil in a heatproof bowl. Melt over a double boiler on low heat, stirring constantly until completely smooth. Remove from heat and let cool for 5 minutes.","timer":300},{"title":"Blend the Tofu","text":"Add the drained silken tofu and plant based milk to a blender or food processor. Blend on high speed for about 60 seconds until the tofu is completely smooth with no lumps remaining.","timer":60},{"title":"Combine Ingredients","text":"Add the melted chocolate, maple syrup, cocoa powder, vanilla extract, and sea salt into the blender with the tofu. Blend everything together on high for 90 seconds until the mixture is completely uniform and silky.","timer":90},{"title":"Portion and Chill","text":"Pour the mousse evenly into 4 serving glasses or ramekins. Cover each glass with plastic wrap and refrigerate for at least 1 hour until the mousse is set and firm to the touch.","timer":3600},{"title":"Serve","text":"Remove the mousse from the refrigerator and let it sit at room temperature for 5 minutes before serving. Top with fresh berries or shaved chocolate if desired and serve immediately.","timer":300}]','[{"original":"maple syrup","swap":"agave nectar or coconut sugar dissolved in 1 tbsp warm water"},{"original":"dark chocolate chips","swap":"carob chips for a caffeine free version"},{"original":"coconut oil","swap":"vegan butter melted at room temperature"}]','["Not draining the tofu properly which leads to a watery mousse that does not set","Adding hot melted chocolate directly to the tofu without cooling it first which can cause separation","Not blending long enough which leaves small tofu lumps in the final texture"]','["chocolate","mousse","tofu","dairy free","no bake","dessert","vegan"]','["vegan","gluten-free","dairy-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Banana Bread','vegan-banana-bread','A moist and tender banana bread made without eggs or dairy that is packed with sweet ripe banana flavor. It bakes up golden on the outside and soft on the inside.','A perfectly moist vegan banana bread using flax eggs and ripe bananas for incredible flavor.','American','Easy',15,60,75,10,210,4,34,7,2,'[{"amount":3,"unit":"large","item":"very ripe bananas mashed","group":"base"},{"amount":2,"unit":"tbsp","item":"ground flaxseed","group":"egg replacer"},{"amount":6,"unit":"tbsp","item":"water","group":"egg replacer"},{"amount":1.5,"unit":"cups","item":"all purpose flour","group":"dry"},{"amount":0.5,"unit":"cup","item":"coconut sugar","group":"sweetener"},{"amount":0.33,"unit":"cup","item":"melted coconut oil","group":"fat"},{"amount":1,"unit":"tsp","item":"baking soda","group":"leavening"},{"amount":1,"unit":"tsp","item":"cinnamon","group":"spice"},{"amount":0.5,"unit":"tsp","item":"sea salt","group":"seasoning"}]','[{"title":"Prepare Flax Eggs and Preheat","text":"Preheat your oven to 350 degrees Fahrenheit and grease a 9x5 inch loaf pan. Mix the ground flaxseed with the water in a small bowl and set aside for 10 minutes until it becomes thick and gel like.","timer":600},{"title":"Mash Bananas and Mix Wet Ingredients","text":"In a large bowl mash the ripe bananas thoroughly with a fork until almost no large chunks remain. Add the melted coconut oil, coconut sugar, and thickened flax egg to the bowl and stir everything together well.","timer":180},{"title":"Mix Dry Ingredients","text":"In a separate bowl whisk together the all purpose flour, baking soda, cinnamon, and sea salt until evenly combined. This ensures the leavening is distributed evenly throughout the batter.","timer":60},{"title":"Combine and Pour","text":"Fold the dry ingredients into the wet banana mixture using a spatula until just combined. Do not overmix the batter as this will make the bread tough. Pour the batter into the prepared loaf pan and smooth the top.","timer":120},{"title":"Bake and Cool","text":"Bake in the preheated oven for 55 to 65 minutes until a toothpick inserted in the center comes out clean. Allow the bread to cool in the pan for 10 minutes then transfer to a wire rack to cool completely before slicing.","timer":3900}]','[{"original":"ground flaxseed","swap":"chia seeds mixed with water in the same ratio"},{"original":"coconut oil","swap":"vegan butter or neutral vegetable oil"},{"original":"all purpose flour","swap":"whole wheat flour for a denser more nutritious loaf"}]','["Using under ripe bananas which do not provide enough sweetness or moisture to the bread","Overmixing the batter after adding flour which develops too much gluten and makes the bread dense and tough","Cutting into the bread while it is still hot which causes it to fall apart and appear underbaked"]','["banana bread","vegan","baking","breakfast","snack","dairy free","egg free"]','["vegan","dairy-free","egg-free"]','Bread','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Fudgy Vegan Brownies','fudgy-vegan-brownies','Intensely chocolatey and fudgy brownies that are completely plant based and utterly irresistible. They have a crinkly top, dense center, and rich dark chocolate flavor.','Ultra fudgy vegan brownies with a crinkly top and deep chocolate flavor in every bite.','American','Easy',15,25,55,12,230,3,32,11,2,'[{"amount":0.75,"unit":"cup","item":"all purpose flour","group":"dry"},{"amount":0.5,"unit":"cup","item":"cocoa powder unsweetened","group":"dry"},{"amount":1,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":0.5,"unit":"cup","item":"melted coconut oil","group":"fat"},{"amount":0.5,"unit":"cup","item":"aquafaba liquid from canned chickpeas","group":"egg replacer"},{"amount":1,"unit":"tsp","item":"pure vanilla extract","group":"flavoring"},{"amount":0.5,"unit":"tsp","item":"baking powder","group":"leavening"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"seasoning"},{"amount":0.5,"unit":"cup","item":"vegan chocolate chips","group":"mix-in"}]','[{"title":"Preheat Oven and Prepare Pan","text":"Preheat your oven to 350 degrees Fahrenheit. Line an 8x8 inch baking pan with parchment paper leaving overhang on two sides to act as handles for easy removal. Lightly grease the parchment paper.","timer":600},{"title":"Whip the Aquafaba","text":"Pour the aquafaba into a medium bowl and beat with a hand mixer on high speed for 3 to 4 minutes until it becomes frothy and slightly thickened. This step adds lift and helps create that classic crinkly brownie top.","timer":240},{"title":"Mix Wet Ingredients","text":"Add the melted coconut oil, granulated sugar, and vanilla extract to the whipped aquafaba. Stir together gently until the sugar is mostly dissolved and the mixture looks glossy and smooth.","timer":90},{"title":"Fold In Dry Ingredients","text":"Sift the flour, cocoa powder, baking powder, and salt over the wet mixture. Fold together with a spatula until just combined, then fold in the vegan chocolate chips. Do not overmix the batter.","timer":120},{"title":"Bake and Cool","text":"Pour the batter into the prepared pan and spread it evenly. Bake for 22 to 26 minutes until the edges look set but the center still has a slight jiggle. Allow the brownies to cool completely in the pan before lifting out and slicing into 12 pieces.","timer":1800}]','[{"original":"aquafaba","swap":"3 tablespoons of unsweetened applesauce mixed with 1 tsp baking powder"},{"original":"coconut oil","swap":"vegan butter for a richer buttery flavor"},{"original":"granulated sugar","swap":"coconut sugar for a deeper caramel like sweetness"}]','["Overbaking the brownies which causes them to dry out and lose their signature fudgy texture","Skipping the aquafaba whipping step which results in flat brownies without the characteristic crinkly top","Cutting into the brownies while they are still warm which causes them to crumble and fall apart"]','["brownies","chocolate","vegan","fudgy","baking","dessert","dairy free","egg free"]','["vegan","dairy-free","egg-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Classic Vegan Chocolate Chip Cookies','classic-vegan-chocolate-chip-cookies','Golden edged and chewy centered chocolate chip cookies that happen to be completely vegan and utterly delicious. They use flax eggs and vegan butter for a perfect bakery style result.','Chewy golden vegan chocolate chip cookies that taste just as good as the classic version.','American','Easy',15,12,42,18,175,2,23,9,1,'[{"amount":2,"unit":"cups","item":"all purpose flour","group":"dry"},{"amount":0.75,"unit":"cup","item":"vegan butter softened","group":"fat"},{"amount":0.75,"unit":"cup","item":"brown sugar packed","group":"sweetener"},{"amount":0.25,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":1,"unit":"tbsp","item":"ground flaxseed","group":"egg replacer"},{"amount":3,"unit":"tbsp","item":"water","group":"egg replacer"},{"amount":1,"unit":"tsp","item":"baking soda","group":"leavening"},{"amount":0.5,"unit":"tsp","item":"sea salt","group":"seasoning"},{"amount":1,"unit":"cup","item":"vegan chocolate chips","group":"mix-in"}]','[{"title":"Make Flax Egg and Preheat","text":"Preheat your oven to 375 degrees Fahrenheit and line two baking sheets with parchment paper. Combine the ground flaxseed and water in a small bowl and let it sit for 10 minutes until it becomes thick and gel like.","timer":600},{"title":"Cream Butter and Sugars","text":"In a large bowl beat the softened vegan butter with the brown sugar and granulated sugar using a hand mixer or stand mixer on medium speed for 2 to 3 minutes until the mixture is light fluffy and pale in color.","timer":180},{"title":"Add Wet Ingredients","text":"Add the thickened flax egg and vanilla extract to the butter sugar mixture. Beat on medium speed for another minute until everything is well incorporated and the mixture looks smooth and creamy.","timer":60},{"title":"Add Dry Ingredients and Chips","text":"Add the flour, baking soda, and salt to the bowl. Mix on low speed until just combined then fold in the vegan chocolate chips with a spatula. Do not overmix the dough once the flour is added.","timer":90},{"title":"Scoop Bake and Cool","text":"Scoop rounded tablespoons of dough onto the prepared baking sheets spacing them 2 inches apart. Bake for 10 to 12 minutes until the edges are golden but the centers look slightly underdone. Cool on the pan for 5 minutes before transferring to a wire rack.","timer":720}]','[{"original":"vegan butter","swap":"refined coconut oil at room temperature for a slightly crispier cookie"},{"original":"ground flaxseed","swap":"1 tablespoon chia seeds mixed with 3 tablespoons water"},{"original":"all purpose flour","swap":"a 1 to 1 gluten free baking flour blend for gluten free cookies"}]','["Using melted vegan butter instead of softened which causes the cookies to spread too thin and become greasy","Overbaking the cookies past golden edges since they continue to cook on the hot pan after removal from the oven","Not chilling the flax egg long enough which means it does not bind the dough properly and the cookies fall apart"]','["cookies","chocolate chip","vegan","baking","dessert","dairy free","egg free"]','["vegan","dairy-free","egg-free"]','Dessert','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Vegan Lemon Poppyseed Muffins','vegan-lemon-poppyseed-muffins','Bright zingy lemon muffins studded with poppy seeds and topped with a sweet lemon glaze. They are tender moist and completely dairy and egg free.','Fluffy vegan lemon poppyseed muffins bursting with citrus flavor and finished with a tangy glaze.','American','Easy',15,22,37,12,195,3,31,7,1,'[{"amount":2,"unit":"cups","item":"all purpose flour","group":"dry"},{"amount":0.75,"unit":"cup","item":"granulated sugar","group":"sweetener"},{"amount":1,"unit":"cup","item":"unsweetened almond milk","group":"wet"},{"amount":0.33,"unit":"cup","item":"neutral vegetable oil","group":"fat"},{"amount":2,"unit":"tbsp","item":"fresh lemon juice","group":"flavoring"},{"amount":1,"unit":"tbsp","item":"lemon zest","group":"flavoring"},{"amount":2,"unit":"tbsp","item":"poppy seeds","group":"mix-in"},{"amount":2,"unit":"tsp","item":"baking powder","group":"leavening"},{"amount":0.25,"unit":"tsp","item":"sea salt","group":"seasoning"}]','[{"title":"Preheat and Prepare","text":"Preheat your oven to 375 degrees Fahrenheit. Line a standard 12 cup muffin tin with paper liners or grease each cup thoroughly with cooking spray. Zest and juice your lemons and set them aside.","timer":600},{"title":"Make Vegan Buttermilk","text":"Combine the almond milk and 1 tablespoon of the fresh lemon juice in a small bowl. Stir briefly and let it sit for 5 minutes until the milk curdles slightly. This creates a vegan buttermilk that makes the muffins extra tender.","timer":300},{"title":"Mix Dry and Wet Separately","text":"In a large bowl whisk together the flour, sugar, baking powder, poppy seeds, and salt. In a separate bowl whisk together the vegan buttermilk, vegetable oil, remaining lemon juice, and lemon zest until combined.","timer":120},{"title":"Combine and Fill","text":"Pour the wet ingredients into the dry ingredients and fold together with a spatula until just combined. A few small lumps in the batter are perfectly fine. Divide the batter evenly among the 12 muffin cups filling each about three quarters full.","timer":90},{"title":"Bake and Glaze","text":"Bake for 20 to 24 minutes until a toothpick inserted in the center of a muffin comes out clean and the tops are lightly golden. While the muffins cool mix 0.5 cup powdered sugar with 1 tablespoon lemon juice and drizzle over the cooled muffins.","timer":1440}]','[{"original":"almond milk","swap":"oat milk or soy milk for a creamier vegan buttermilk base"},{"original":"vegetable oil","swap":"melted coconut oil for a subtle tropical note"},{"original":"poppy seeds","swap":"chia seeds for a similar texture and appearance"}]','["Overmixing the batter after adding the flour which develops gluten and results in dense tough muffins","Skipping the vegan buttermilk step which is essential for achieving a light and tender crumb","Opening the oven door too early in the baking process which causes the muffins to sink in the center"]','["muffins","lemon","poppyseed","vegan","breakfast","snack","dairy free","egg free"]','["vegan","dairy-free","egg-free"]','Breakfast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Shibuya Honey Toast','shibuya-honey-toast','A decadent Japanese cafe dessert featuring a thick bread cube hollowed out and filled with cream, ice cream, and honey. This indulgent treat is inspired by the famous Shibuya district cafes of Tokyo.','A towering Japanese dessert bread filled with whipped cream and ice cream drizzled with golden honey.','Japanese','Medium',20,15,35,2,680,10,82,34,2,'[{"amount":1,"unit":"loaf","item":"thick Japanese milk bread","group":"base"},{"amount":3,"unit":"tablespoons","item":"unsalted butter melted","group":"base"},{"amount":2,"unit":"tablespoons","item":"honey","group":"base"},{"amount":1,"unit":"cup","item":"heavy whipping cream","group":"filling"},{"amount":2,"unit":"tablespoons","item":"powdered sugar","group":"filling"},{"amount":2,"unit":"scoops","item":"vanilla ice cream","group":"filling"},{"amount":1,"unit":"tablespoon","item":"extra honey for drizzling","group":"topping"},{"amount":1,"unit":"cup","item":"fresh strawberries sliced","group":"topping"}]','[{"title":"Prepare the Bread","text":"Preheat oven to 375F. Cut the top off the milk bread loaf and carefully hollow out the inside leaving a 1 inch thick border on all sides and the bottom. Cut the removed bread into large cubes and set aside along with the bread shell.","timer":0},{"title":"Butter and Toast","text":"Brush the inside of the bread shell and the bread cubes generously with melted butter mixed with honey. Place the shell and cubes on a baking sheet and bake until golden and crisp.","timer":900},{"title":"Whip the Cream","text":"While the bread toasts, beat the heavy whipping cream and powdered sugar together in a chilled bowl until stiff peaks form. Transfer to a piping bag or keep in the bowl for spooning.","timer":300},{"title":"Assemble the Toast","text":"Remove the toasted bread shell from the oven and place the toasted bread cubes back inside the hollow. Place scoops of vanilla ice cream on top of the bread cubes and then pile whipped cream generously over everything.","timer":0},{"title":"Finish and Serve","text":"Arrange sliced strawberries around and on top of the whipped cream. Drizzle extra honey over the entire dessert and serve immediately before the ice cream melts.","timer":0}]','[{"original":"Japanese milk bread","swap":"brioche loaf"},{"original":"vanilla ice cream","swap":"matcha ice cream"},{"original":"strawberries","swap":"banana slices and blueberries"}]','["Do not hollow the bread too thin or the shell will collapse when filled","Do not skip chilling the bowl before whipping cream as it will not hold peaks","Do not assemble too early or the bread will become soggy from the ice cream"]','["honey toast","Japanese dessert","cafe style","bread dessert","ice cream"]','["vegetarian"]','Dessert Toast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Turkish Egg Toast','turkish-egg-toast','A bold and savory toast inspired by Turkish cilbir featuring garlicky yogurt, poached eggs, and a sizzling chili butter. This dish transforms simple ingredients into a deeply satisfying breakfast or brunch.','Crusty toast topped with garlic yogurt and poached eggs finished with spiced chili butter.','Turkish','Medium',10,15,25,2,420,18,34,24,2,'[{"amount":2,"unit":"slices","item":"thick sourdough bread","group":"base"},{"amount":1,"unit":"cup","item":"full fat Greek yogurt","group":"sauce"},{"amount":2,"unit":"cloves","item":"garlic minced","group":"sauce"},{"amount":2,"unit":"whole","item":"large eggs","group":"protein"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"chili butter"},{"amount":1,"unit":"teaspoon","item":"Aleppo pepper or red pepper flakes","group":"chili butter"},{"amount":1,"unit":"teaspoon","item":"smoked paprika","group":"chili butter"},{"amount":2,"unit":"tablespoons","item":"fresh dill or parsley chopped","group":"garnish"}]','[{"title":"Make the Garlic Yogurt","text":"In a small bowl combine the Greek yogurt with minced garlic and a pinch of salt. Stir well and let it sit at room temperature while you prepare the rest of the dish so the flavors can meld together.","timer":600},{"title":"Toast the Bread","text":"Toast the sourdough slices in a toaster or under the broiler until deeply golden and crisp. The bread needs to be sturdy enough to support the yogurt and eggs without becoming immediately soggy.","timer":240},{"title":"Poach the Eggs","text":"Bring a wide saucepan of water to a gentle simmer and add a splash of white vinegar. Create a gentle swirl and carefully slide in the eggs one at a time. Poach until the whites are set but the yolks remain runny.","timer":240},{"title":"Make the Chili Butter","text":"In a small pan melt the butter over medium heat until it just starts to foam. Add the Aleppo pepper and smoked paprika and swirl constantly for about 30 seconds until fragrant and the butter turns a deep red orange color.","timer":60},{"title":"Assemble and Serve","text":"Spread a generous layer of garlic yogurt onto each toast. Place a poached egg on top of the yogurt and immediately spoon the hot chili butter over the egg. Finish with fresh dill or parsley and a pinch of flaky salt.","timer":0}]','[{"original":"Aleppo pepper","swap":"regular red pepper flakes"},{"original":"sourdough bread","swap":"pita bread or ciabatta"},{"original":"Greek yogurt","swap":"labneh or strained plain yogurt"}]','["Do not use cold yogurt straight from the fridge as it will make the dish taste flat","Do not let the butter burn when making chili butter or it will taste bitter","Do not overcook the poached eggs as a runny yolk is essential to the dish"]','["Turkish","eggs","yogurt","brunch","cilbir inspired","savory toast"]','["vegetarian"]','Savory Toast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Ricotta Hot Honey Peach Toast','ricotta-hot-honey-peach-toast','A stunning summer toast featuring creamy whipped ricotta topped with fresh juicy peaches and a drizzle of spicy hot honey. The combination of sweet fruit and heat creates an irresistible balance on every bite.','Whipped ricotta toast piled with fresh peaches and finished with a fiery hot honey drizzle.','American','Easy',10,5,15,2,380,14,44,16,3,'[{"amount":2,"unit":"slices","item":"thick sourdough or country bread","group":"base"},{"amount":1,"unit":"cup","item":"whole milk ricotta cheese","group":"spread"},{"amount":1,"unit":"tablespoon","item":"honey","group":"spread"},{"amount":1,"unit":"teaspoon","item":"lemon zest","group":"spread"},{"amount":2,"unit":"whole","item":"ripe peaches sliced","group":"topping"},{"amount":2,"unit":"tablespoons","item":"hot honey","group":"topping"},{"amount":2,"unit":"tablespoons","item":"fresh basil leaves torn","group":"garnish"},{"amount":1,"unit":"pinch","item":"flaky sea salt","group":"garnish"}]','[{"title":"Whip the Ricotta","text":"Place the ricotta in a food processor or use a hand mixer and whip it with the honey and lemon zest for about 2 minutes until it becomes light fluffy and spreadable. Season with a small pinch of salt and set aside.","timer":120},{"title":"Toast the Bread","text":"Toast the bread slices in a toaster or on a hot grill pan until golden brown and crisp. If using a grill pan you can brush the bread lightly with olive oil for extra flavor and beautiful char marks.","timer":300},{"title":"Prepare the Peaches","text":"Slice the ripe peaches into thin wedges removing the pit. If the peaches are very firm you can briefly warm them in a pan with a little butter for 2 minutes to help release their juices and soften them slightly.","timer":120},{"title":"Spread and Top","text":"Spread a thick generous layer of the whipped ricotta onto each piece of toast going all the way to the edges. Arrange the peach slices on top of the ricotta overlapping them slightly for a beautiful presentation.","timer":0},{"title":"Finish and Serve","text":"Drizzle the hot honey generously over the peaches and ricotta. Scatter torn fresh basil leaves over the top and finish with a pinch of flaky sea salt. Serve immediately while the toast is still crisp.","timer":0}]','[{"original":"fresh peaches","swap":"nectarines or canned peaches drained well"},{"original":"hot honey","swap":"regular honey mixed with a pinch of red pepper flakes"},{"original":"ricotta cheese","swap":"mascarpone or cream cheese"}]','["Do not use watery low quality ricotta without draining it first or the toast will become soggy","Do not skip the flaky salt as it balances the sweetness of the honey and peaches","Do not assemble the toast too far in advance as the bread will lose its crunch"]','["ricotta toast","peach","hot honey","summer","brunch","sweet toast"]','["vegetarian"]','Sweet Toast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Smashed Avocado Everything Bagel Toast','smashed-avocado-everything-bagel-toast','A crowd pleasing avocado toast elevated with everything bagel seasoning and a perfectly jammy soft boiled egg on top. This recipe delivers big bold flavor with minimal effort and maximum satisfaction.','Creamy smashed avocado toast loaded with everything bagel spice and topped with a jammy soft boiled egg.','American','Easy',10,7,17,2,340,13,28,21,7,'[{"amount":2,"unit":"slices","item":"whole grain or sourdough bread","group":"base"},{"amount":2,"unit":"whole","item":"ripe avocados","group":"spread"},{"amount":1,"unit":"tablespoon","item":"fresh lemon juice","group":"spread"},{"amount":1,"unit":"teaspoon","item":"everything bagel seasoning","group":"seasoning"},{"amount":2,"unit":"whole","item":"large eggs","group":"protein"},{"amount":1,"unit":"teaspoon","item":"red pepper flakes","group":"garnish"},{"amount":1,"unit":"tablespoon","item":"extra virgin olive oil","group":"garnish"},{"amount":2,"unit":"tablespoons","item":"microgreens or arugula","group":"garnish"}]','[{"title":"Soft Boil the Eggs","text":"Bring a small pot of water to a full boil. Gently lower the eggs into the water using a spoon and cook for exactly 7 minutes. Transfer immediately to an ice bath for 2 minutes then peel and slice in half lengthwise.","timer":420},{"title":"Toast the Bread","text":"Toast the bread slices until they are golden and firm enough to hold the avocado without bending. A sturdy toast base is important so the toppings do not slide off when you pick up the slice.","timer":240},{"title":"Smash the Avocado","text":"Halve and pit the avocados and scoop the flesh into a bowl. Add the lemon juice and a generous pinch of salt. Smash with a fork until you reach a chunky creamy texture. Do not over mix into a smooth paste.","timer":0},{"title":"Build the Toast","text":"Spread the smashed avocado thickly onto each slice of toast. Sprinkle everything bagel seasoning evenly over the avocado pressing it in gently so it adheres to the surface.","timer":0},{"title":"Top and Serve","text":"Place the halved soft boiled eggs on top of the avocado cut side up so the jammy yolk is visible. Add microgreens or arugula around the eggs and finish with a drizzle of olive oil and a pinch of red pepper flakes.","timer":0}]','[{"original":"everything bagel seasoning","swap":"za atar spice blend"},{"original":"soft boiled egg","swap":"fried egg or poached egg"},{"original":"lemon juice","swap":"lime juice or white wine vinegar"}]','["Do not use unripe avocado as it will be bitter and difficult to smash properly","Do not over cook the eggs past 7 minutes or the yolk will not be jammy","Do not skip the acid in the avocado mixture as it prevents browning and brightens flavor"]','["avocado toast","everything bagel","brunch","healthy","eggs","savory"]','["vegetarian","dairy-free"]','Savory Toast','ai');
INSERT INTO recipes (title,slug,description,quick_summary,cuisine,difficulty,prep_time,cook_time,total_time,servings,calories,protein,carbs,fat,fiber,ingredients,steps,substitutions,common_mistakes,tags,dietary,category,source) VALUES ('Cinnamon Brown Butter Apple Toast','cinnamon-brown-butter-apple-toast','A cozy autumnal toast featuring warm caramelized apples cooked in nutty brown butter and cinnamon over a layer of cream cheese. This recipe tastes like apple pie on a slice of bread and comes together in under 20 minutes.','Thick toast spread with cream cheese and topped with warm cinnamon brown butter caramelized apples.','American','Easy',8,10,18,2,410,7,52,20,4,'[{"amount":2,"unit":"slices","item":"brioche or thick white bread","group":"base"},{"amount":3,"unit":"tablespoons","item":"unsalted butter","group":"sauce"},{"amount":2,"unit":"whole","item":"apples peeled cored and thinly sliced","group":"topping"},{"amount":2,"unit":"tablespoons","item":"brown sugar","group":"sauce"},{"amount":1,"unit":"teaspoon","item":"ground cinnamon","group":"sauce"},{"amount":3,"unit":"tablespoons","item":"cream cheese softened","group":"spread"},{"amount":1,"unit":"tablespoon","item":"maple syrup","group":"spread"},{"amount":2,"unit":"tablespoons","item":"chopped toasted walnuts","group":"garnish"}]','[{"title":"Make the Brown Butter Apples","text":"Melt the butter in a skillet over medium heat and continue cooking while swirling the pan until the butter turns golden brown and smells nutty. Add the apple slices brown sugar and cinnamon and stir to coat everything evenly.","timer":180},{"title":"Caramelize the Apples","text":"Cook the apples in the brown butter mixture over medium heat stirring occasionally until they are tender and golden and the sauce has thickened into a sticky glaze. Do not rush this step by using high heat.","timer":420},{"title":"Toast the Bread","text":"While the apples cook toast the brioche slices until golden and just crisp on the outside but still slightly soft inside. Brioche toasts quickly so watch it carefully to avoid burning.","timer":180},{"title":"Prepare the Cream Cheese Spread","text":"In a small bowl stir together the softened cream cheese and maple syrup until smooth and well combined. The mixture should be easily spreadable and lightly sweet with a hint of maple flavor.","timer":0},{"title":"Assemble and Serve","text":"Spread the maple cream cheese generously onto each toast slice. Spoon the warm cinnamon brown butter apples over the cream cheese and drizzle any remaining sauce from the pan over the top. Finish with chopped toasted walnuts.","timer":0}]','[{"original":"brioche bread","swap":"thick cut challah or Texas toast"},{"original":"cream cheese","swap":"mascarpone or ricotta cheese"},{"original":"walnuts","swap":"pecans or granola clusters"}]','["Do not walk away from the brown butter as it can go from golden to burnt very quickly","Do not use a watery apple variety such as Red Delicious as it will not hold its shape when cooked","Do not use cold cream cheese straight from the fridge as it will tear the bread when you try to spread it"]','["apple toast","brown butter","cinnamon","autumn","cozy","sweet toast","brunch"]','["vegetarian"]','Sweet Toast','ai');